window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["nicet-fire-alarm"] = window.COURSE_LANG["nicet-fire-alarm"] || {};
window.COURSE_LANG["nicet-fire-alarm"]["es"] = [
  {id:1, q:"El tetraedro del fuego añade un cuarto elemento al clásico triángulo del fuego. ¿Cuál es ese cuarto elemento?", opts:["Energía lumínica (radiante)","Producción de humo","Una reacción química en cadena autosostenida","Gas monóxido de carbono"], re:"El tetraedro del fuego está formado por combustible, calor, oxígeno, más la reacción química en cadena autosostenida. Fuente: fundamentos de la ciencia del fuego (Tetraedro del Fuego de la WFCA; antecedentes de detección de NFPA 72)."},
  {id:2, q:"¿Qué tres elementos componen el triángulo básico del fuego?", opts:["Humo, calor y llama","Ignición, ventilación y combustible","Carbono, hidrógeno y oxígeno","Combustible, oxígeno y calor"], re:"El triángulo del fuego es combustible, oxígeno (oxidante) y calor; eliminar cualquiera de ellos extingue el fuego. Fuente: fundamentos de la ciencia del fuego (Firesafe.org.uk; WFCA)."},
  {id:3, q:"En la etapa temprana de un incendio típico, ¿qué producto detectable suele aparecer PRIMERO?", opts:["Llama abierta","Calor elevado","Partículas de combustión invisibles / humo","Colapso estructural"], re:"En la etapa incipiente, los aerosoles invisibles y las partículas de combustión aparecen antes que el humo visible, la llama o el calor significativo, por lo que la detección temprana de humo responde primero. Fuente: principios de detección de NFPA 72; fundamentos de las etapas del fuego."},
  {id:4, q:"Un incendio de desarrollo lento que produce partículas de humo grandes pero poca llama se describe mejor como un:", opts:["Incendio con combustión súbita generalizada (flashover)","Incendio con llama","Backdraft","Incendio latente (smoldering)"], re:"Un incendio latente arde lentamente sin llama y genera partículas de humo más grandes; la detección fotoeléctrica responde mejor a él. Fuente: guía de alarmas de humo de la NFPA; fundamentos de la combustión."},
  {id:5, q:"En comparación con los incendios latentes, los incendios con llama rápida normalmente producen partículas de humo que son:", opts:["Siempre invisibles para todos los detectores","De mayor tamaño","De menor tamaño","De tamaño idéntico"], re:"Los incendios con llama generan partículas de humo/combustión más pequeñas, a las que la detección por ionización responde mejor; los incendios latentes producen partículas más grandes. Fuente: guía de tecnología de alarmas de humo de la NFPA."},
  {id:6, q:"Las cuatro etapas generales del desarrollo de un incendio suelen enumerarse como:", opts:["Combustión súbita (flashover), latente, con llama, decaimiento","Decaimiento, incipiente, crecimiento, combustión súbita (flashover)","Incipiente, crecimiento, totalmente desarrollado, decaimiento","Ignición, combustión súbita (flashover), supresión, remate"], re:"El incendio se desarrolla a través de las etapas incipiente, de crecimiento, totalmente desarrollada y de decaimiento. Fuente: fundamentos del comportamiento del fuego (referencia de Phoenix Fire; antecedentes de detección de NFPA)."},
  {id:7, q:"El calor de un incendio se transfiere por tres modos. ¿Qué lista nombra correctamente los tres?", opts:["Combustión, oxidación, pirólisis","Ionización, fotoeléctrico, haz","Conducción, convección, radiación","Ignición, propagación, extinción"], re:"La transferencia de calor ocurre por conducción, convección y radiación; la convección (gases calientes ascendentes) lleva el humo a los detectores del techo. Fuente: fundamentos de la ciencia del fuego."},
  {id:8, q:"¿Por qué la mayoría de los detectores puntuales de humo y calor se montan en el techo o cerca de él?", opts:["Para mantenerlos fuera del alcance de los ocupantes","Solo para reducir la longitud del cableado","Porque el código prohíbe totalmente el montaje en pared","Porque el humo y los gases calientes ascienden por convección y se acumulan en el techo"], re:"El humo caliente y flotante asciende y forma una capa en el techo, por lo que la colocación en el área del techo da la respuesta más temprana. Fuente: fundamento de colocación de detectores puntuales de NFPA 72."},
  {id:9, q:"El proceso por el cual un combustible sólido se descompone químicamente por el calor, liberando vapores inflamables, se llama:", opts:["Convección","Oxidación","Sublimación","Pirólisis"], re:"La pirólisis es la descomposición térmica de un combustible que libera gases combustibles que luego se inflaman. Fuente: fundamentos de la ciencia del fuego."},
  {id:10, q:"El monóxido de carbono (CO) es producido por un incendio principalmente como resultado de:", opts:["Solo arco eléctrico","Combustión completa con exceso de oxígeno","Combustión incompleta de combustibles a base de carbono","Reacción del agua con el combustible"], re:"El CO es un producto de la combustión incompleta cuando el oxígeno es limitado; es un gas tóxico incoloro e inodoro. Fuente: fundamentos de la química del fuego; antecedentes de detección de CO (NFPA 720/72)."},
  {id:11, q:"La ignición rápida y casi simultánea de la mayoría de las superficies combustibles expuestas en un compartimento se conoce como:", opts:["Backdraft","Pirólisis","Rollover","Combustión súbita generalizada (flashover)"], re:"La combustión súbita generalizada (flashover) es la transición en la que el calor radiante inflama casi todos los combustibles de una habitación casi a la vez. Fuente: fundamentos del comportamiento del fuego."},
  {id:12, q:"Las tecnologías de detección generalmente perciben una de tres firmas del fuego. ¿Qué conjunto enumera esas firmas?", opts:["Voltaje, corriente, resistencia","Velocidad, presión, masa","Humo (aerosoles), calor y energía radiante (llama)","Color, olor y sabor"], re:"Los detectores automáticos de incendios responden al humo/aerosoles, al calor o a la energía radiante (llama): las tres firmas principales del fuego. Fuente: clasificaciones de detectores de NFPA 72."},
  {id:13, q:"¿En qué orden suelen estar disponibles más comúnmente las firmas detectables del fuego en un incendio típico que primero es latente y luego con llama?", opts:["Calor, luego llama, luego humo","Llama, luego calor, luego humo","Calor, luego humo, luego llama","Humo, luego llama, luego calor elevado"], re:"Los aerosoles de humo suelen aparecer primero, seguidos de la llama y luego el calor significativo a medida que el incendio crece; esto determina la elección del detector para la alerta temprana. Fuente: principios de detección de NFPA 72."},
  {id:14, q:"¿Qué afirmación sobre el oxígeno y la combustión es correcta?", opts:["El oxígeno no desempeña ningún papel en el fuego","La combustión requiere oxígeno puro al 100 %","El aire normal (aproximadamente 21 % de oxígeno) sostiene fácilmente la combustión con llama","Reducir el oxígeno siempre acelera un incendio"], re:"El aire ordinario (~21 % de O2) sostiene la combustión; reducir la concentración del oxidante tiende a suprimir el fuego. Fuente: fundamentos de la ciencia del fuego."},
  {id:15, q:"La temperatura más baja a la que un combustible desprende suficiente vapor para formar una mezcla inflamable en el aire es su:", opts:["Temperatura de autoignición","Punto de ebullición","Punto de inflamación","Punto de Curie"], re:"El punto de inflamación es la temperatura mínima a la que un líquido produce suficiente vapor para inflamarse momentáneamente cuando hay una fuente de ignición presente. Fuente: fundamentos de la química del fuego."},
  {id:16, q:"¿A qué firma del fuego NO respondería directamente un detector de HUMO?", opts:["Partículas de humo visibles","Aerosoles de combustión invisibles","Calor radiante de una llama de combustión limpia que produce poco humo","Productos de combustión latente"], re:"Los detectores de humo responden a las partículas de combustión en el aire; una llama limpia y rápida que produce poco humo se detecta mejor con un detector de llama (energía radiante). Fuente: selección de detectores de NFPA 72."},
  {id:17, q:"La selección del tipo de detector adecuado para un riesgo depende principalmente de:", opts:["La firma del fuego esperada y el entorno del espacio protegido","El color de la pared","Solo la marca del panel de control","El día de la semana en que se instala"], re:"La selección del detector se basa en la firma del fuego prevista (humo, calor, llama) y las condiciones ambientales del espacio. Fuente: guía de selección de detectores del Capítulo 17 de NFPA 72."},
  {id:18, q:"Un detector de humo de ionización generalmente responde MÁS RÁPIDO a qué tipo de incendio?", opts:["Incendios con llama rápida","Incendios latentes lentos","Fugas de CO sin combustión","Cableado sobrecalentado sin humo"], re:"Los detectores de ionización responden mejor a los incendios con llama rápida que producen partículas de humo pequeñas. Fuente: guía de tecnología de alarmas de humo de la NFPA."},
  {id:19, q:"Un detector de humo fotoeléctrico generalmente responde MÁS RÁPIDO a qué tipo de incendio?", opts:["Incendios con llama rápida","Solo llama radiante","Calor puro sin humo","Incendios latentes lentos"], re:"Los detectores fotoeléctricos (de dispersión de luz) responden mejor a los incendios latentes lentos que producen partículas de humo más grandes. Fuente: guía de tecnología de alarmas de humo de la NFPA."},
  {id:20, q:"La fuente radiactiva utilizada en un detector de humo de ionización típico es:", opts:["Cobalto-60","Radio-226","Americio-241","Cesio-137"], re:"Los detectores de humo de ionización usan una pequeña fuente alfa de americio-241 (aproximadamente 1 microcurio en unidades residenciales) para ionizar el aire de la cámara. Fuente: ORAU/Asociación Mundial de Energía Nuclear; referencias de detectores de ionización."},
  {id:21, q:"¿Cómo activa una alarma el humo que entra en una cámara de ionización?", opts:["Aumenta bruscamente la corriente de la cámara","Calienta la cámara hasta un punto de ajuste","Genera un campo magnético","Se adhiere a los iones y reduce la corriente de la cámara"], re:"Las partículas de humo se adhieren a las moléculas de aire ionizadas, reduciendo la pequeña corriente constante; el detector percibe esa caída y activa la alarma. Fuente: principio de funcionamiento del detector de ionización (ORAU)."},
  {id:22, q:"Un detector de humo fotoeléctrico (de dispersión de luz) activa la alarma cuando:", opts:["Las partículas de humo dispersan la luz de la fuente hacia el fotosensor","El humo enfría el calefactor interno","Una fuente radiactiva decae más rápido","El voltaje de la cámara cae a cero"], re:"En un detector fotoeléctrico de dispersión de luz, el humo que entra en la cámara dispersa la luz del LED hacia un fotosensor que normalmente está protegido del haz, activando la alarma. Fuente: principio de funcionamiento del detector fotoeléctrico."},
  {id:23, q:"Para la mejor protección global de la seguridad de la vida, la guía de la NFPA recomienda:", opts:["Solo alarmas de ionización","Retirar las alarmas de humo de los dormitorios","Solo detectores de calor","Ambas tecnologías, fotoeléctrica e ionización (o una unidad combinada)"], re:"La NFPA recomienda usar ambas tecnologías, ionización y fotoeléctrica, o alarmas combinadas, porque cada una responde mejor a diferentes tipos de incendio. Fuente: guía de alarmas de humo de la NFPA."},
  {id:24, q:"Una fuente común de alarmas molestas para los detectores de IONIZACIÓN colocados demasiado cerca de una cocina es:", opts:["Aerosoles de cocción y vapor","Solo calor radiante","Baja humedad","Monóxido de carbono solo"], re:"Las unidades de ionización son propensas a alarmas molestas por vapores/vapor de cocción, por lo que deben mantenerse alejadas de los aparatos de cocción. Fuente: guía de colocación de NFPA 72; referencias de alarmas de humo."},
  {id:25, q:"Según NFPA 72, el espaciamiento nominal (comúnmente aceptado) utilizado como guía para los detectores puntuales de humo en techos lisos es de aproximadamente:", opts:["10 ft","20 ft","30 ft","75 ft"], re:"Los detectores de humo no están homologados para un espaciamiento específico, pero comúnmente se aplican con un espaciamiento nominal de 30 ft en techos lisos como guía inicial. Fuente: NFPA 72; artículo de ECMag sobre espaciamiento de detectores."},
  {id:26, q:"Un detector de humo montado en una pared lateral (no en el techo) generalmente debe tener su parte superior ubicada:", opts:["Dentro de 12 in. del techo","Al menos 36 in. por debajo del techo","En el piso","Exactamente a media altura de la pared solamente"], re:"Los detectores puntuales de humo montados en pared se colocan con la parte superior dentro de 12 in. del techo para que alcancen la capa de humo ascendente. Fuente: montaje de detectores puntuales de NFPA 72 (UpCodes 907 / 17.7)."},
  {id:27, q:"Un detector puntual de humo montado en el techo debe mantenerse a una distancia mínima de una pared lateral de al menos:", opts:["1 in.","2 in.","4 in.","18 in."], re:"NFPA 72 requiere que los detectores puntuales montados en el techo estén al menos a 4 in. de una pared lateral. Fuente: montaje de detectores puntuales de NFPA 72 (getsafeandsound; UpCodes)."},
  {id:28, q:"¿Qué tipo de detector es MÁS adecuado donde se necesita una alerta muy temprana de incendios latentes y lentos de equipos electrónicos en un centro de datos?", opts:["Detección de humo fotoeléctrica o por aspiración de aire","Solo detector de calor de temperatura fija","Estación manual de alarma de acción simple","Solo detector de calor de tasa de aumento"], re:"Los incendios latentes y de baja energía producen partículas más grandes y poco calor al principio, por lo que se prefiere la detección de humo fotoeléctrica o por aspiración de aire de alta sensibilidad frente a los detectores de calor. Fuente: selección de detectores de NFPA 72; guía de aplicación de VESDA."},
  {id:29, q:"Un detector de humo 'combinado' comúnmente se refiere a una unidad que:", opts:["Usa detección tanto por ionización como fotoeléctrica","Combina una estación manual de alarma y una bocina","Detecta solo dióxido de carbono","Tiene dos cables de alimentación"], re:"Una alarma de humo combinada incorpora detección tanto por ionización como fotoeléctrica para responder bien tanto a incendios con llama como latentes. Fuente: guía de alarmas de humo de la NFPA."},
  {id:30, q:"¿Qué afirmación sobre los detectores de ionización es VERDADERA según las homologaciones actuales?", opts:["Están prohibidos por NFPA 72 en todos los edificios","Nunca requieren mantenimiento","Detectan solo calor, no humo","Están homologados según UL 268 y aceptados por NFPA 72 para uso comercial"], re:"Los detectores de humo de ionización cumplen con UL 268 y son aceptados por NFPA 72; como todos los detectores de humo, requieren pruebas funcionales y de sensibilidad periódicas. Fuente: NFPA 72; UL 268."},
  {id:31, q:"Montar un detector puntual de humo directamente en el flujo de aire de alta velocidad de un difusor de suministro de HVAC es un problema porque:", opts:["Se ve poco atractivo","Lo convierte en un detector de calor","Aumenta la intensidad de la fuente radiactiva","El aire en movimiento puede diluir o desviar el humo del detector, retrasando la respuesta"], re:"El fuerte flujo de aire cerca de los difusores puede impedir que el humo llegue a la cámara de detección, por lo que los detectores deben mantenerse alejados del flujo de aire de suministro directo. Fuente: guía de ubicación de NFPA 72."},
  {id:32, q:"Los detectores de humo utilizados en un SISTEMA de alarma contra incendios (frente a las alarmas autónomas) suelen estar:", opts:["Alimentados solo por una batería de 9V sin supervisión","Prohibidos de iniciar la notificación","Obligados a no contener componentes electrónicos","Conectados y supervisados por una unidad de control de alarma contra incendios"], re:"Los detectores del sistema se conectan a una unidad de control de alarma contra incendios que los supervisa e inicia la notificación; las alarmas autónomas son autónomas. Fuente: fundamentos del sistema de NFPA 72."},
  {id:33, q:"El propósito PRINCIPAL de un detector de humo de ducto en un sistema HVAC es:", opts:["Reemplazar todos los detectores de humo de área del edificio","Proporcionar cobertura general de área para los ocupantes","Medir la temperatura del ducto para el confort","Detectar humo en el manejador de aire y apagar/controlar el HVAC para limitar la propagación del humo"], re:"Los detectores de humo de ducto muestrean el aire en los ductos de HVAC para detectar humo y apagar o controlar el sistema, evitando la distribución del humo; no sustituyen la detección de área. Fuente: requisitos de detectores de ducto de NFPA 72 / NFPA 90A."},
  {id:34, q:"La deriva de sensibilidad causada por la acumulación de polvo en la cámara de un detector de humo se aborda mediante:", opts:["Pruebas de sensibilidad periódicas y limpieza según NFPA 72","Pintar sobre el detector","Desconectar el detector permanentemente","Ignorarlo hasta que la unidad falle"], re:"NFPA 72 requiere pruebas funcionales periódicas y pruebas de sensibilidad/limpieza para que los detectores se mantengan dentro de su rango de sensibilidad homologado. Fuente: inspección, pruebas y mantenimiento de NFPA 72."},
  {id:35, q:"Un detector de calor de temperatura fija opera cuando:", opts:["La temperatura aumenta más rápido que una tasa establecida","El monóxido de carbono alcanza 70 ppm","El humo oscurece un haz de luz","El elemento sensor alcanza una temperatura predeterminada"], re:"Un detector de calor de temperatura fija se activa cuando su elemento operativo alcanza una temperatura preestablecida (por ejemplo, 135 F). Fuente: definiciones de detectores de calor de NFPA 72; FM Approvals."},
  {id:36, q:"Un detector de calor de tasa de aumento (ROR) opera cuando la temperatura del aire:", opts:["Alcanza solo un punto de ajuste fijo","Permanece constante durante una hora","Cae rápidamente","Aumenta a más de una tasa predeterminada, comúnmente alrededor de 15 F por minuto"], re:"Los detectores ROR responden cuando la temperatura aumenta más rápido que una tasa establecida, comúnmente alrededor de 15 F (≈8.3 C) por minuto. Fuente: NFPA 72; criterios de detectores de calor de FM Approvals."},
  {id:37, q:"Una clasificación de temperatura fija estándar común para detectores de calor de temperatura ordinaria es de aproximadamente:", opts:["55 F","32 F","500 F","135 F"], re:"Los detectores de calor fijos de temperatura ordinaria comúnmente operan cerca de 135 F (y 200 F para clasificaciones intermedias). Fuente: clasificaciones de temperatura de detectores de calor de NFPA 72."},
  {id:38, q:"Un detector de calor de tasa de aumento puede FALLAR en activar la alarma en qué escenario?", opts:["Un incendio de desarrollo muy lento cuya temperatura sube poco a poco por debajo del umbral de tasa","Un incendio súbito que eleva la temperatura rápidamente","Cualquier incendio que produzca calor rápido","Un incendio directamente debajo del detector"], re:"Un incendio que arde lentamente puede elevar la temperatura por debajo del umbral de tasa de aumento y no activar el elemento ROR; por eso el ROR suele combinarse con un elemento de temperatura fija. Fuente: funcionamiento de detectores de calor de NFPA 72."},
  {id:39, q:"Un detector de calor combinado de temperatura fija/tasa de aumento proporciona:", opts:["Solo detección de humo","Alineación de haz","Detección de monóxido de carbono","Respuesta a incendios de desarrollo tanto rápido como lento"], re:"El elemento ROR detecta incendios rápidos mientras que el elemento de temperatura fija detecta los lentos, cubriendo ambos patrones de crecimiento del incendio. Fuente: NFPA 72; detectores de calor combinados de FM Approvals."},
  {id:40, q:"Un detector de calor de compensación de tasa se describe mejor como un detector que:", opts:["Responde cuando el aire circundante alcanza una temperatura establecida con un retardo térmico mínimo","Cuenta partículas de humo","Detecta radiación UV","Mide el flujo de aire del ducto"], re:"Un detector de compensación de tasa responde cuando el aire circundante alcanza una temperatura predeterminada con poco efecto de la tasa de aumento (bajo retardo térmico), comportándose como un detector de temperatura fija rápido. Fuente: definiciones de NFPA 72; FM Approvals."},
  {id:41, q:"En comparación con los detectores de humo, los detectores de calor generalmente:", opts:["Dan una alerta más temprana de un incendio","Son más propensos a alarmas molestas","Responden más tarde pero con menos alarmas molestas","Detectan aerosoles invisibles"], re:"Los detectores de calor responden más tarde (el calor se acumula después del humo) pero son mucho menos propensos a alarmas molestas, lo que los hace adecuados para áreas sucias o adversas. Fuente: selección de detectores de NFPA 72."},
  {id:42, q:"¿En qué entorno se prefiere típicamente un detector de CALOR frente a un detector de humo?", opts:["Una oficina limpia","Una habitación de hospital para dormir","Un área polvorienta, sucia o cargada de humos como una sala de calderas o un garaje","Una sala de servidores informáticos que necesita una alerta muy temprana"], re:"Los detectores de calor se eligen para espacios polvorientos, sucios, con humos o de alta humedad donde los detectores de humo darían alarmas molestas. Fuente: guía de selección de detectores de NFPA 72."},
  {id:43, q:"Un detector de calor de temperatura fija 'no restaurable' (por ejemplo, de tipo enlace fusible o eutéctico) debe ser:", opts:["Restablecido con una llave después de cada prueba","Recargado eléctricamente","Pintado para restaurar su función","Reemplazado después de que opera"], re:"Los detectores no restaurables usan un elemento que se funde (eutéctico) que se destruye al operar y debe reemplazarse; los tipos restaurables se restablecen automáticamente. Fuente: tipos de detectores de calor de NFPA 72."},
  {id:44, q:"El espaciamiento de NFPA 72 de los detectores puntuales de calor usa un 'espaciamiento homologado'. Una regla clave para la cobertura es que cada punto del techo debe estar dentro de:", opts:["0.7 veces el espaciamiento homologado de un detector","2.0 veces el espaciamiento homologado","exactamente 100 ft","el ancho del edificio"], re:"La 'regla del 0.7' requiere que cada punto del techo esté dentro de 0.7 × el espaciamiento homologado de un detector de calor. Fuente: espaciamiento de detectores de calor de NFPA 72 (Regla del Punto 7 de NTC)."},
  {id:45, q:"A medida que aumenta la altura del techo, el espaciamiento requerido de los detectores puntuales de calor generalmente debe:", opts:["Aumentarse","Establecerse en cero","Dejarse sin cambios","Reducirse (multiplicarse por un factor menor que 1)"], re:"NFPA 72 aplica un factor de reducción basado en la altura (<1) al espaciamiento homologado de los detectores de calor a medida que los techos se hacen más altos, porque el calor se estratifica antes de llegar a los detectores distantes. Fuente: Tabla 17.6.3.5.1 de NFPA 72."},
  {id:46, q:"Un detector de calor de tipo lineal comúnmente usa:", opts:["Una sola fuente radiactiva","Un transductor ultrasónico","Una cámara fotoeléctrica","Un cable continuo cuyo aislamiento se degrada a una temperatura establecida, completando un circuito"], re:"La detección de calor lineal (de tipo lineal) usa un cable continuo sensible al calor; a la temperatura nominal, el aislamiento se degrada y los conductores se cortocircuitan, señalando la ubicación del calor. Fuente: detección de calor de tipo lineal de NFPA 72."},
  {id:47, q:"Un detector de calor con clasificación de temperatura más alta (por ejemplo, 190-200 F en lugar de 135 F) se seleccionaría para una ubicación que:", opts:["Normalmente se mantiene muy fría","No tiene riesgo de incendio","Es una oficina limpia","Tiene una temperatura ambiente normal alta, para evitar una operación falsa"], re:"Los detectores de calor se clasifican por encima de la temperatura ambiente normal máxima esperada; las áreas calientes (áticos, salas de calderas) usan detectores de clasificación más alta para evitar la operación por alarmas molestas. Fuente: clasificación de temperatura de NFPA 72."},
  {id:48, q:"El término 'retardo térmico' en la detección de calor se refiere a:", opts:["El retraso antes de que el elemento sensor alcance la temperatura real del aire","El tiempo para cablear el detector","El retraso de la bocina de alarma","El porcentaje de oscurecimiento por humo"], re:"El retardo térmico es la diferencia entre la temperatura real del aire y la temperatura del elemento del detector; los detectores de compensación de tasa están diseñados para minimizarlo. Fuente: principios de detectores de calor de NFPA 72."},
  {id:49, q:"¿Qué tipo de detector de calor se RESTAURA (restablece) por sí mismo después de retirar la fuente de calor, sin reemplazo?", opts:["Un tipo de enlace fusible (eutéctico) no restaurable","Un tipo de pastilla fundible","Un tipo de ampolla de vidrio frágil","Un tipo puntual bimetálico restaurable"], re:"Los detectores bimetálicos restaurables se flexionan con la temperatura y vuelven a la normalidad cuando se enfrían; los tipos de fusible/eutéctico y de ampolla de vidrio se destruyen al operar. Fuente: detectores restaurables vs. no restaurables de NFPA 72."},
  {id:50, q:"¿Por qué NO se recomiendan los detectores de calor como detector principal de seguridad de la vida en áreas para dormir?", opts:["Cuestan demasiado","Solo funcionan al aire libre","No se pueden cablear a un panel","Responden demasiado tarde para proteger a los ocupantes dormidos del humo y los gases tóxicos"], re:"Como el calor se acumula después del humo y el CO, los detectores de calor avisan demasiado tarde para la seguridad de la vida en áreas para dormir, donde se requiere detección de humo en su lugar. Fuente: selección de detectores de NFPA 72; guía de seguridad de la vida de la NFPA."},
  {id:51, q:"Un detector puntual de calor de tasa de aumento neumático funciona mediante:", opts:["Detectar partículas alfa","Fundir una pastilla de metal","Dispersar luz infrarroja","Aire en una cámara sellada que se expande más rápido de lo que un respiradero calibrado puede aliviar, flexionando un diafragma para cerrar contactos"], re:"Los detectores ROR neumáticos usan una cámara de aire sellada con un pequeño respiradero; el calentamiento rápido expande el aire más rápido de lo que puede escapar, flexionando un diafragma que cierra los contactos de la alarma. Fuente: principio de funcionamiento de tasa de aumento de NFPA 72."},
  {id:52, q:"Según NFPA 72, la parte operable de una estación manual de alarma debe montarse a no menos de ___ y a no más de ___ sobre el piso terminado.", opts:["24 in. / 36 in.","12 in. / 24 in.","60 in. / 72 in.","42 in. / 48 in."], re:"NFPA 72 (17.14) requiere que la parte operable de una caja manual de alarma contra incendios esté a un mínimo de 42 in. y un máximo de 48 in. sobre el piso terminado. Fuente: NFPA 72 §17.14; blog de altura de estaciones manuales de la NFPA."},
  {id:53, q:"Una estación manual de alarma de 'doble acción' requiere que el usuario:", opts:["Realice dos acciones distintas, como levantar una cubierta o tapa y luego tirar","Tire dos veces en la misma dirección","Pulse un solo botón una vez","Inserte una moneda"], re:"Las estaciones de doble acción necesitan dos movimientos separados (por ejemplo, levantar/empujar una cubierta, luego tirar), reduciendo la activación accidental o malintencionada. Fuente: guía de cajas manuales de alarma contra incendios de NFPA 72."},
  {id:54, q:"Una estación manual de alarma de 'acción simple' se activa mediante:", opts:["Dos pasos separados","Solo una señal remota","Un movimiento, típicamente un solo tirón de la manija","El calor que alcanza 135 F"], re:"Las estaciones de acción simple operan con un movimiento (un solo tirón), dando la activación manual más rápida. Fuente: tipos de cajas manuales de alarma contra incendios de NFPA 72."},
  {id:55, q:"NFPA 72 requiere que una estación manual de alarma esté ubicada a qué distancia de cada puerta de salida?", opts:["Dentro de 60 in. (5 ft) de la salida","Dentro de 50 ft de la salida","En cualquier lugar del piso","Solo dentro de 200 ft"], re:"Una caja manual de alarma contra incendios debe ubicarse dentro de 60 in. (5 ft) de la abertura de la puerta de salida en cada salida. Fuente: colocación de estaciones manuales de NFPA 72 §17.14."},
  {id:56, q:"En un piso grande, NFPA 72 limita la distancia de recorrido horizontal hasta la estación manual de alarma más cercana a no más de aproximadamente:", opts:["50 ft","100 ft","200 ft","500 ft"], re:"La distancia de recorrido hasta una caja manual de alarma contra incendios no debe exceder 200 ft en el mismo piso; se añaden estaciones adicionales para cumplir con esto. Fuente: NFPA 72 §17.14."},
  {id:57, q:"El color estándar requerido para las estaciones manuales de alarma contra incendios es:", opts:["Verde","Azul","Rojo","Amarillo"], re:"Las cajas manuales de alarma contra incendios deben ser rojas. Fuente: requisitos de cajas manuales de alarma contra incendios de NFPA 72 §17.14."},
  {id:58, q:"¿Dónde se ubican típicamente las estaciones manuales de alarma a lo largo de una ruta de egreso?", opts:["En el acceso natural de salida, cerca de las puertas que la gente usa para salir","Solo dentro de armarios cerrados con llave","Solo en el techo","Ocultas detrás de muebles"], re:"Las estaciones se colocan en la ruta natural de egreso cerca de las salidas para que un ocupante que sale pase junto a una. Fuente: intención de colocación de NFPA 72 §17.14."},
  {id:59, q:"Una razón principal para elegir estaciones manuales de DOBLE acción (o con cubierta) en una escuela u otra área de alto tráfico es:", opts:["Reducir las falsas alarmas malintencionadas o accidentales","Hacerlas más difíciles de encontrar para los bomberos","Eliminar la necesidad de detectores de humo","Bajar la altura de montaje"], re:"El paso adicional (y las cubiertas protectoras) de las estaciones de doble acción reduce las activaciones molestas y malintencionadas en ocupaciones de alto tráfico. Fuente: guía de cajas manuales de alarma contra incendios de NFPA 72."},
  {id:60, q:"Una estación manual de alarma se clasifica dentro de un sistema de alarma contra incendios como un(a):", opts:["Dispositivo de notificación","Fuente de alimentación","Dispositivo de iniciación","Anunciador"], re:"Una estación manual de alarma es un dispositivo de iniciación de actuación manual que señala a la unidad de control. Fuente: definiciones de dispositivos de iniciación de NFPA 72."},
  {id:61, q:"Después de activar una estación manual convencional de romper vidrio o de enganche, restaurarla a la normalidad generalmente requiere:", opts:["Pintarla de rojo de nuevo","Esperar a que se enfríe por debajo de 135 F","Usar una llave o herramienta para restablecer (y reemplazar una varilla de vidrio si está equipada)","Solo apagar y encender la energía del edificio"], re:"Las estaciones manuales de enganche permanecen activadas hasta que se restablecen con la llave/herramienta adecuada; los tipos de varilla rompible también necesitan reemplazar la varilla de vidrio/plástico. Fuente: funcionamiento de cajas manuales de alarma contra incendios del fabricante/NFPA 72."},
  {id:62, q:"Una instrucción de operación clara como la palabra 'PULL' (TIRE) en una estación manual sirve para:", opts:["Decorar el dispositivo","Indicar el calibre del cable","Decir a los ocupantes cómo operarla durante una emergencia","Marcar la fuente radiactiva"], re:"Las cajas manuales de alarma contra incendios llevan instrucciones de operación claras (por ejemplo, PULL/TIRE) para que los ocupantes puedan activarlas bajo estrés. Fuente: marcado de cajas manuales de alarma contra incendios de NFPA 72."},
  {id:63, q:"Una posición de 'prueba' operada por llave en algunas estaciones manuales permite a un técnico:", opts:["Deshabilitar permanentemente el sistema","Aumentar el volumen de notificación","Operar la estación para pruebas sin romper una varilla o vidrio","Cambiar la sensibilidad del detector"], re:"Una función de prueba con llave permite operar y restablecer la estación para pruebas periódicas sin consumir un elemento rompible. Fuente: ITM de NFPA 72; documentación del fabricante."},
  {id:64, q:"Montar todas las estaciones manuales de alarma dentro del rango de 42-48 in. apoya principalmente:", opts:["Una operación consistente y accesible, incluso por personas en sillas de ruedas (ADA)","Reducir la longitud del cable","Ocultarlas a la vista","La detección de calor"], re:"El rango de 42-48 in. proporciona un alcance consistente y accesibilidad, alineándose con los rangos de alcance de la ADA. Fuente: NFPA 72 §17.14; coordinación con los rangos de alcance de la ADA."},
  {id:65, q:"Cuando se activa una estación manual de alarma, la unidad de control de alarma contra incendios debe:", opts:["Ignorarla durante 5 minutos","Iniciar la condición de alarma contra incendios y los dispositivos de notificación","Silenciar todos los detectores","Restablecerse automáticamente"], re:"Operar un dispositivo de iniciación como una estación manual coloca el panel en la condición de alarma y activa la notificación según la programación del sistema. Fuente: operación del sistema de NFPA 72."},
  {id:66, q:"En un sistema de alarma contra incendios direccionable, una estación manual de alarma típicamente:", opts:["Reporta su dirección/ubicación específica al panel","No se puede identificar en absoluto","Solo funciona sin ningún cableado","Funciona únicamente como una bocina"], re:"Las estaciones manuales direccionables reportan una dirección única para que el panel pueda mostrar el dispositivo/ubicación exacto que se activó. Fuente: fundamentos de sistemas direccionables de NFPA 72."},
  {id:67, q:"¿Cuál NO es una consideración de ubicación apropiada para una estación manual de alarma?", opts:["Adyacente a cada salida","En la ruta de egreso","Detrás de una puerta cerrada con llave inaccesible para los ocupantes","A una altura consistente de 42-48 in."], re:"Las estaciones manuales deben ser fácilmente accesibles en la ruta de egreso cerca de las salidas; colocar una detrás de una puerta cerrada con llave e inaccesible anula su propósito. Fuente: colocación de NFPA 72 §17.14."},
  {id:68, q:"Una estación manual de alarma se diferencia de un detector automático en que:", opts:["Requiere acción humana para iniciar una alarma","Detecta humo automáticamente","Detecta calor automáticamente","Detecta CO automáticamente"], re:"Las estaciones manuales son dispositivos de iniciación accionados por humanos, mientras que los detectores automáticos perciben una firma del fuego sin acción humana. Fuente: clasificaciones de dispositivos de iniciación de NFPA 72."},
  {id:69, q:"Un detector de humo de haz proyectado percibe el humo mediante:", opts:["Contar partículas alfa","Medir la reducción de luz (oscurecimiento) a lo largo de un haz desde un transmisor hasta un receptor","Detectar calor a 135 F","Muestrear la concentración de CO"], re:"Los detectores de haz proyectado miden el oscurecimiento de un haz infrarrojo entre un transmisor y un receptor; el humo que cruza el haz atenúa la luz. Fuente: detección de haz proyectado de NFPA 72; referencias de haz óptico."},
  {id:70, q:"Los detectores de humo de haz proyectado son especialmente adecuados para:", opts:["Armarios pequeños","Grandes áreas abiertas con techos altos, como atrios y almacenes","Solo dentro de ductos de HVAC","Gabinetes eléctricos sellados"], re:"Los detectores de haz protegen eficientemente espacios grandes, altos y abiertos (atrios, almacenes, gimnasios) que de otro modo necesitarían muchos detectores puntuales. Fuente: aplicación de haz proyectado de NFPA 72; referencias de ORR/Hochiki."},
  {id:71, q:"En techos lisos, NFPA 72 da una pauta de espaciamiento horizontal entre haces proyectados adyacentes de no más de aproximadamente:", opts:["10 ft","30 ft","60 ft","300 ft"], re:"NFPA 72 usa una pauta de no más de 60 ft entre haces (y la mitad de eso hacia una pared lateral paralela) en techos lisos. Fuente: espaciamiento de haz proyectado de NFPA 72 §17.7 (UpCodes)."},
  {id:72, q:"Un detector de haz proyectado 'reflectivo' (de un solo extremo) usa:", opts:["Dos fuentes radiactivas","Un transmisor/receptor en una unidad apuntado a un reflector remoto","Solo un elemento de calor","Una red de tuberías de muestreo"], re:"Los detectores de haz reflectivo combinan el transmisor y el receptor en una sola carcasa y reflejan el haz en un reflector remoto, simplificando la instalación. Fuente: NFPA 72; guías de aplicación de detectores de haz."},
  {id:73, q:"Un bloqueo TOTAL repentino de la trayectoria de un detector de haz proyectado (por ejemplo, un objeto colocado sobre el receptor) normalmente produce:", opts:["Una alarma de incendio inmediatamente","Una señal de problema (falla) en lugar de una alarma de incendio","Ninguna respuesta en absoluto","Un restablecimiento del panel"], re:"El bloqueo total del haz se trata como una condición de falla/problema (pérdida del haz), lo que lo distingue del oscurecimiento gradual del humo. Fuente: operación de haz proyectado de NFPA 72; homologaciones del fabricante."},
  {id:74, q:"Un sistema de detección de humo por aspiración de aire (muestreo de aire) como VESDA funciona mediante:", opts:["Esperar a que el humo entre a la deriva en una cámara puntual","Extraer aire continuamente a través de una red de tuberías hacia una cámara de detección altamente sensible","Fundir un enlace fusible","Detectar solo monóxido de carbono"], re:"Los sistemas por aspiración usan un ventilador/aspirador para extraer continuamente muestras de aire a través de tuberías de muestreo hacia una cámara láser/óptica sensible, dando una alerta muy temprana. Fuente: muestreo de aire de NFPA 72 §17.7; referencias de Xtralis VESDA."},
  {id:75, q:"Una ventaja clave de la detección por aspiración de aire (tipo VESDA) sobre los detectores puntuales estándar es:", opts:["No necesita energía","Alerta muy temprana / muy alta sensibilidad a niveles mínimos de humo","Detecta el calor más rápido","Elimina la necesidad de un panel de control"], re:"Los sistemas por aspiración de aire ofrecen una alerta muy temprana al detectar concentraciones de humo extremadamente bajas, ideales para espacios de alto valor o de misión crítica. Fuente: NFPA 72 §17.7; guía de aplicación de VESDA."},
  {id:76, q:"En NFPA 72, cada puerto de muestreo de un sistema por aspiración de aire generalmente se trata, para ubicación y espaciamiento, como:", opts:["Un dispositivo de notificación","Un detector de humo de tipo puntual","Una estación manual de alarma","Un detector de calor"], re:"NFPA 72 (17.7) requiere que cada puerto de muestreo se trate como un detector de humo de tipo puntual para ubicación y espaciamiento, a menos que se use un diseño basado en el desempeño. Fuente: NFPA 72 §17.7.3.6.1."},
  {id:77, q:"Un detector de llama percibe un incendio respondiendo a:", opts:["Energía radiante (UV o IR) emitida por las llamas","Conteo de partículas de humo","Solo la temperatura del aire","Concentración de monóxido de carbono"], re:"Los detectores de llama son detectores de energía radiante que perciben las emisiones UV o IR de las llamas. Fuente: definición de detector de energía radiante (llama) de NFPA 72."},
  {id:78, q:"Un detector de llama UV/IR mejora la fiabilidad sobre una unidad de un solo sensor mediante:", opts:["Usar dos bandas espectrales diferentes para confirmar una llama y rechazar fuentes falsas","Añadir una fuente radiactiva","Muestrear el aire del ducto","Fundirse a 135 F"], re:"Combinar la detección ultravioleta e infrarroja requiere que ambas bandas confirmen una llama, mejorando la inmunidad a falsas alarmas. Fuente: principios de funcionamiento de detectores de llama (AZoSensors; MSA)."},
  {id:79, q:"El sensor IR en muchos detectores de llama de hidrocarburos apunta a la emisión cerca de 4.3-4.4 micras porque esa banda corresponde a:", opts:["Luz visible de lámparas","Dióxido de carbono (CO2) caliente producido por la quema de hidrocarburos","Solo vapor de agua","Ondas de radio"], re:"Los hidrocarburos en combustión emiten una fuerte firma IR cerca de 4.3 micras del CO2 caliente; los detectores de llama IR se centran en esta banda. Fuente: referencias espectrales de detectores de llama (AZoSensors)."},
  {id:80, q:"Un detector de llama es una buena opción donde:", opts:["Un incendio puede surgir como llama abierta con poco humo, como en áreas de manejo de combustible o hangares","Solo se espera combustión latente lenta sin llama","No existe riesgo de incendio","La monitorización de CO es la única necesidad"], re:"Los detectores de llama destacan donde pueden ocurrir incendios rápidos con llama y de alta energía (líquidos inflamables, gases) con poco humo temprano. Fuente: aplicación de detectores de energía radiante de NFPA 72."},
  {id:81, q:"Un detector de llama generalmente requiere:", opts:["Línea de visión directa a la posible llama","Ninguna vista del área protegida","Contacto con el combustible","Inmersión en agua"], re:"Como perciben energía radiante, los detectores de llama deben tener una línea de visión sin obstrucciones hacia el área donde pueden aparecer las llamas. Fuente: colocación de detectores de energía radiante de NFPA 72."},
  {id:82, q:"Un detector de monóxido de carbono (CO) comúnmente usa qué tecnología de detección?", opts:["Cámara de ionización","Sensor electroquímico","Tira bimetálica","Haz infrarrojo a través de una habitación"], re:"Los detectores de CO residenciales/comerciales típicamente usan una celda electroquímica que reacciona con el CO para producir una corriente medible. Fuente: referencias de detección de CO (NFPA 720/72; Kidde)."},
  {id:83, q:"¿Qué afirmación sobre los detectores de CO es correcta?", opts:["Un detector de CO es lo mismo que un detector de humo","Un detector de CO percibe el gas tóxico monóxido de carbono, no humo ni llama","Los detectores de CO detectan calor a 135 F","El CO es un gas visible de olor dulce"], re:"Los detectores de CO perciben el monóxido de carbono, un gas tóxico incoloro e inodoro; no reemplazan los detectores de humo o de calor. Fuente: requisitos de detección de CO de NFPA 720/72."},
  {id:84, q:"En las viviendas, las alarmas/detectores de CO generalmente deben ubicarse:", opts:["Solo en el ático","Fuera de cada área separada para dormir y en cada nivel de la vivienda","Dentro de la cámara de combustión de una chimenea","Solo en el garaje"], re:"Los códigos requieren alarmas de CO fuera de cada área separada para dormir y en cada nivel de una vivienda para que los ocupantes sean advertidos del CO. Fuente: colocación de alarmas de CO de NFPA 720/72; IRC."},
  {id:85, q:"Un circuito de dispositivos de iniciación (IDC) se describe mejor como un circuito que:", opts:["Alimenta bocinas y estroboscopios de notificación","Conecta los dispositivos de iniciación (como estaciones manuales y detectores) a la unidad de control","Suministra energía de servicio público al edificio","Lleva solo la línea telefónica"], re:"Un IDC interconecta los dispositivos de iniciación (estaciones manuales, detectores, interruptores de flujo de agua) con la unidad de control de alarma contra incendios. Fuente: definiciones de circuitos de NFPA 72."},
  {id:86, q:"En un IDC convencional de Clase B, la supervisión contra fallas de circuito abierto comúnmente se proporciona mediante:", opts:["Una fuente radiactiva","Una resistencia de fin de línea (EOLR)","Un sensor de llama","La manija de una estación manual"], re:"Un IDC de Clase B termina en una resistencia de fin de línea; el panel envía una pequeña corriente de supervisión a través del lazo, y la pérdida de esa corriente indica un circuito abierto. Fuente: supervisión de circuitos de NFPA 72; trayectorias de NTC."},
  {id:87, q:"Si ocurre una sola APERTURA (corte) en un IDC de Clase B, los dispositivos ubicados MÁS ALLÁ del corte van a:", opts:["Reportar alarmas normalmente de todos modos","No poder reportar al panel (quedar inoperativos)","Cambiar a Clase A automáticamente","Activar los dispositivos de notificación directamente"], re:"En un circuito de Clase B, una sola apertura aísla todo lo que está aguas abajo del corte, por lo que esos dispositivos no pueden señalar al panel; el panel muestra un problema. Fuente: comportamiento de Clase B de NFPA 72; trayectorias de NTC."},
  {id:88, q:"Un IDC de Clase A se diferencia de Clase B en que, después de un solo corte de cable, este:", opts:["Pierde todos los dispositivos","Aún puede comunicarse con cada dispositivo alimentando el lazo desde ambas direcciones","Suena una alarma continua","No requiere supervisión"], re:"Una trayectoria de Clase A regresa al panel, por lo que un solo corte se puentea alimentando el lazo desde ambos extremos y todos los dispositivos siguen reportando. Fuente: trayectorias de Clase A vs. Clase B de NFPA 72."},
  {id:89, q:"Los dispositivos de iniciación convencionales en un IDC básico operan mediante:", opts:["Enviar una dirección digital","Cambiar de un estado normalmente abierto a cerrado (cortocircuitando el lazo) para señalar alarma","Aumentar el valor de la EOLR","Cortar la energía del edificio"], re:"Los dispositivos de iniciación convencionales son contactos normalmente abiertos que se cierran en alarma, dejando caer una baja resistencia a través del lazo que el panel lee como una alarma. Fuente: operación de IDC convencional de NFPA 72."},
  {id:90, q:"En un IDC supervisado de Clase B, un circuito ABIERTO normalmente es reportado por el panel como un(a):", opts:["Alarma","Condición de problema (falla)","Evento de supervisión de CO","Solo apagado"], re:"La pérdida de la corriente de supervisión (una apertura) en un IDC de Clase B produce una señal de problema, distinta de la alarma producida por el cierre de un dispositivo. Fuente: indicación de falla de circuito de NFPA 72."},
  {id:91, q:"En un IDC convencional de Clase B, una alarma se distingue de un estado normal/de problema porque el cierre del dispositivo hace que la resistencia del lazo:", opts:["Suba al infinito (abierto)","Caiga a un valor bajo (cortocircuito a través de la línea)","Permanezca exactamente en el valor de la EOLR","Se vuelva negativa"], re:"Un dispositivo de iniciación cerrado cortocircuita el lazo, dejando caer la resistencia muy por debajo del valor de la EOLR; el panel lee esa caída como alarma. Una apertura (infinito) se lee como problema. Fuente: operación de IDC convencional de NFPA 72."},
  {id:92, q:"El propósito de supervisar un IDC es:", opts:["Mejorar el sonido de las bocinas","Detectar fallas de cableado (aperturas/cortocircuitos/tierras) para que puedan repararse antes de una emergencia","Aumentar la vida útil de la fuente radiactiva","Reducir la altura de montaje de los dispositivos"], re:"La supervisión permite que el panel anuncie las fallas de circuito para que el cableado deteriorado se encuentre y se arregle antes de que deshabilite la protección. Fuente: intención de supervisión de circuitos de NFPA 72."},
  {id:93, q:"En el Artículo 760 del NEC, los circuitos de alarma contra incendios se dividen en dos categorías principales:", opts:["CA y CC","De potencia limitada (PLFA) y de potencia no limitada (NPLFA)","Clase 2 y Clase 3","Alto voltaje y bajo voltaje"], re:"El Artículo 760 del NEC separa los circuitos de alarma contra incendios en circuitos de potencia limitada (PLFA) y de potencia no limitada (NPLFA), cada uno con sus propias reglas de cableado. Fuente: Artículo 760 del NEC (NFPA 70)."},
  {id:94, q:"Un circuito de alarma contra incendios de potencia limitada (PLFA) según el NEC 760 debe tener su voltaje y potencia limitados por:", opts:["Una fuente de alimentación homologada que cumpla los requisitos de potencia limitada","La resistencia de fin de línea","El tendido de cable más largo","El número de detectores"], re:"Los circuitos PLFA son alimentados por una fuente homologada de potencia limitada (según NEC 760.121), que limita inherentemente la corriente y reduce el riesgo de descarga/incendio, permitiendo un cableado menos estricto. Fuente: Artículo 760 del NEC."},
  {id:95, q:"En comparación con los circuitos PLFA, los circuitos de alarma contra incendios de potencia no limitada (NPLFA):", opts:["Pueden operar a mayor voltaje/potencia y tienen reglas de cableado más estrictas","Siempre son de 24 V y fáciles de instalar","No conllevan riesgo eléctrico","No están permitidos por el NEC"], re:"Los circuitos NPLFA (hasta 600 V, con potencia no inherentemente limitada) conllevan mayor riesgo de descarga y deben seguir reglas de instalación más estrictas que los PLFA. Fuente: requisitos NPLFA del Artículo 760 del NEC."},
  {id:96, q:"Los conductores de alarma contra incendios de potencia limitada (PLFA) generalmente deben mantenerse:", opts:["En el mismo cable que los conductores de energía del edificio","Físicamente separados de los conductores de luz, energía y otros de mayor energía a menos que aplique una excepción","Solo en exteriores","Energizados a 600 V"], re:"El NEC 760 requiere que los conductores PLFA estén separados de los conductores de luz, energía, Clase 1 y NPLFA (sin cable/canalización común) excepto donde excepciones específicas lo permitan. Fuente: reglas de separación del Artículo 760 del NEC."},
  {id:97, q:"Una falla a TIERRA en un circuito de dispositivos de iniciación debe ser:", opts:["Ignorada por la unidad de control","Indicada como una condición de problema en la unidad de control","Reportada solo como una alarma","Usada para silenciar los detectores"], re:"NFPA 72 requiere que la unidad de control monitoree la integridad del circuito; una falla a tierra en un circuito monitoreado resulta en una indicación de problema. Fuente: supervisión de circuitos de NFPA 72."},
  {id:98, q:"Mezclar dispositivos de iniciación convencionales en un IDC significa que cuando un dispositivo da la alarma, el panel puede identificar:", opts:["El dispositivo individual exacto","Solo que algún dispositivo de esa zona/circuito operó","El calibre del cable usado","La clasificación de temperatura del detector"], re:"Un IDC convencional reporta por zona/circuito, por lo que el panel sabe que un dispositivo de ese circuito operó pero no cuál; los sistemas direccionables identifican el dispositivo específico. Fuente: convencional vs. direccionable de NFPA 72."},
  {id:99, q:"En un IDC convencional básico, ¿qué estado eléctrico considera el panel como 'normal' (sin alarma, sin problema)?", opts:["Un cortocircuito a través del lazo","Cero voltios en el lazo","Corriente de supervisión que fluye a través de la resistencia de fin de línea","Las bocinas sonando"], re:"La condición normal es una pequeña corriente de supervisión que fluye a través de la EOLR; un cortocircuito se lee como alarma y una apertura se lee como problema. Fuente: supervisión de IDC convencional de NFPA 72."},
  {id:100, q:"¿Por qué se coloca la resistencia de fin de línea en el dispositivo MÁS LEJANO (último) de un IDC de Clase B en lugar de en el panel?", opts:["Para ahorrar cable","Para que la corriente de supervisión deba pasar por todo el tendido, permitiendo detectar una apertura en cualquier punto","Para aumentar el volumen de notificación","Para convertir el circuito a Clase A"], re:"Colocar la EOLR en el extremo obliga a la corriente de supervisión a pasar por todo el circuito; un corte en cualquier punto interrumpe esa corriente y se anuncia como problema. Fuente: principio de supervisión de Clase B de NFPA 72."},
  {id:101, q:"Para notificación audible en modo público, ¿cuántos dBA por encima del nivel sonoro ambiental promedio exige NFPA 72 como mínimo para la señal?", opts:["15 dBA","10 dBA","5 dBA","20 dBA"], re:"NFPA 72 (2022) 18.4.3.1: los aparatos audibles de modo público deben producir un nivel sonoro de al menos 15 dBA por encima del ambiental promedio, o 5 dBA por encima del nivel sonoro máximo que dure 60 s, el que sea mayor."},
  {id:102, q:"Las señales audibles de modo público también deben estar al menos cuántos dBA por encima del nivel sonoro máximo que tenga una duración de al menos 60 segundos?", opts:["10 dBA","5 dBA","15 dBA","25 dBA"], re:"NFPA 72 18.4.3.1: el requisito es 15 dBA por encima del ambiental promedio O 5 dBA por encima del máximo de 60 segundos, el que sea mayor."},
  {id:103, q:"En áreas de dormir, la señal audible en la almohada debe tener al menos qué nivel sonoro, el que sea mayor?", opts:["65 dBA","70 dBA","75 dBA","85 dBA"], re:"NFPA 72 18.4.5: en habitaciones de dormir, la señal debe ser 15 dBA por encima del ambiente, 5 dBA por encima de un máximo de 60 segundos, o al menos 75 dBA en la almohada, el que sea mayor."},
  {id:104, q:"¿A qué altura sobre el piso, en el área ocupable, se miden los niveles sonoros audibles de modo público?", opts:["1.0 m (3 ft)","1.2 m (4 ft)","1.8 m (6 ft)","1.5 m (5 ft)"], re:"NFPA 72 18.4.3: las mediciones se toman a 1.5 m (5 ft) sobre el piso en el área ocupable, con ponderación A."},
  {id:105, q:"El nivel de presión sonora total de todos los aparatos audibles combinados con el ambiente NO deberá exceder qué valor a la distancia mínima de audición?", opts:["110 dBA","105 dBA","100 dBA","120 dBA"], re:"NFPA 72 18.4.4: la presión sonora combinada no deberá exceder 110 dBA a la distancia mínima de audición para proteger la audición."},
  {id:106, q:"Para notificación audible en modo privado, ¿cuántos dBA por encima del nivel sonoro ambiental promedio debe estar la señal como mínimo?", opts:["15 dBA","10 dBA","5 dBA","20 dBA"], re:"NFPA 72 18.4.4 (modo privado): al menos 10 dBA por encima del ambiental promedio o 5 dBA por encima del máximo de 60 segundos, el que sea mayor."},
  {id:107, q:"¿Qué escala de ponderación especifica NFPA 72 para medir los niveles sonoros de notificación?", opts:["Ponderación C (dBC)","Ponderación Z (dBZ)","Ponderación A (dBA)","Lineal (dB SPL)"], re:"NFPA 72 Capítulo 18 especifica la escala con ponderación A (dBA), que aproxima la sensibilidad de la audición humana."},
  {id:108, q:"Para despertar a los ocupantes en áreas de dormir, NFPA 72 exige que la señal de alarma de humo/notificación incluya qué característica de frecuencia?", opts:["Un tono de alta frecuencia de 5000 Hz","Un tono senoidal puro de 1000 Hz","Un tono piloto ultrasónico","Una señal de onda cuadrada de baja frecuencia de 520 Hz"], re:"NFPA 72 18.4.5.3: los aparatos de notificación destinados a despertar a ocupantes dormidos deben producir una señal de onda cuadrada de baja frecuencia de 520 Hz ±10 %, que despierta de forma más eficaz (incluidas las personas con dificultades auditivas)."},
  {id:109, q:"Cuando existe una puerta u otra barrera entre el aparato audible y la almohada, ¿cómo se determina el nivel sonoro del área de dormir?", opts:["Medido con la barrera colocada (cerrada)","Medido con la barrera abierta","Calculado sin la barrera","La barrera se ignora por completo"], re:"NFPA 72 18.4.5: el nivel sonoro se mide con las barreras intermedias (puertas, cortinas, tabiques) en su posición cerrada normal, ya que ese es el peor caso."},
  {id:110, q:"Un 'nivel sonoro ambiental promedio' según NFPA 72 es el valor cuadrático medio de todos los sonidos a lo largo de qué período mínimo en un día de 24 horas?", opts:["1 minuto","Un tiempo suficiente para caracterizar el área","24 horas de medición representativa","5 minutos"], re:"Definiciones de NFPA 72: el ambiental promedio es el nivel sonoro RMS medido durante un tiempo suficiente para ser representativo de la condición normal del espacio."},
  {id:111, q:"Si un espacio tiene un ambiental promedio de 55 dBA, ¿cuál es el nivel mínimo de señal de modo público usando solo la regla de 15 dBA por encima del ambiente?", opts:["60 dBA","65 dBA","70 dBA","75 dBA"], re:"NFPA 72 18.4.3.1: 55 dBA de ambiente + 15 dBA = 70 dBA mínimo (antes de verificar la regla del máximo de 60 segundos)."},
  {id:112, q:"Por lo general, NO se exige que los aparatos audibles de notificación funcionen en cuál de las siguientes áreas?", opts:["Pasillos y vestíbulos","Habitaciones de dormir","Ocupaciones de reunión","Salas mecánicas/eléctricas donde no se espera la presencia de ocupantes"], re:"NFPA 72 / IBC: la notificación se provee donde se debe alertar a los ocupantes; las salas de equipo mecánico/eléctrico no ocupadas normalmente no requieren notificación a ocupantes."},
  {id:113, q:"¿Cuál es el propósito principal del límite máximo de presión sonora de 110 dBA?", opts:["Prevenir daño auditivo a los ocupantes","Ahorrar energía de la batería","Reducir el costo del cableado","Mejorar la sincronización de las luces estroboscópicas"], re:"NFPA 72 18.4.4: el tope de 110 dBA a la distancia mínima de audición protege a los ocupantes de lesiones auditivas durante la evacuación."},
  {id:114, q:"Una bocina clasificada en 90 dBA a 10 ft pierde aproximadamente cuánto nivel sonoro cada vez que la distancia desde ella se duplica (campo libre)?", opts:["3 dBA","6 dBA","10 dBA","12 dBA"], re:"La ley del inverso del cuadrado da aproximadamente una caída de 6 dB por cada duplicación de la distancia en campo libre; esto es fundamental para el diseño de audibilidad según el Anexo A de NFPA 72."},
  {id:115, q:"Para fines de audibilidad, ¿qué tipo de aparato produce la salida más fuerte para una entrada dada y es común en áreas industriales?", opts:["Carillón","Campana","Bocina","Altavoz en derivaciones bajas"], re:"NFPA 72 Anexo/práctica: las bocinas proveen la mayor salida en dBA y se prefieren en espacios industriales de alto ambiente; los carillones/campanas producen niveles más bajos."},
  {id:116, q:"¿Cuál afirmación sobre el listado de aparatos audibles es correcta?", opts:["Puede usarse cualquier altavoz sin listado","El listado aplica solo al panel","El listado solo se requiere para luces estroboscópicas","Los aparatos audibles de notificación deben estar listados para uso de señalización de alarma de incendio"], re:"NFPA 72 10.3 / 18.3: todos los aparatos de notificación deben estar listados para su propósito; los fabricantes publican el dBA nominal a 10 ft (reverberante) para el diseño."},
  {id:117, q:"Las clasificaciones audibles del fabricante (dBA a 10 ft) suelen publicarse bajo qué condición para uso de diseño según código?", opts:["Condiciones reverberantes (UL 464)","Anecoicas (campo libre) solamente","Al aire libre solamente","Bajo el agua"], re:"UL 464 / diseño NFPA 72: los aparatos se clasifican a 10 ft en una cámara reverberante; los diseñadores usan esos valores para verificar el requisito de 15 dBA por encima del ambiente."},
  {id:118, q:"¿Cuál es la clasificación mínima en candelas permitida para una luz estroboscópica en un pasillo de 20 ft de ancho o menos?", opts:["30 cd","15 cd","75 cd","110 cd"], re:"NFPA 72 18.5.5.5: las luces estroboscópicas de pasillo (pasillo ≤ 20 ft de ancho) pueden ser de 15 cd, ubicadas dentro de 15 ft de cada extremo y separadas no más de 100 ft."},
  {id:119, q:"En una aplicación de pasillo, las luces estroboscópicas deberán ubicarse a no más de qué distancia del extremo del pasillo?", opts:["10 ft","20 ft","15 ft","25 ft"], re:"NFPA 72 18.5.5.5: los aparatos visibles deben estar dentro de 15 ft del extremo del pasillo."},
  {id:120, q:"En un pasillo, el espaciamiento máximo permitido entre aparatos visibles de notificación es:", opts:["50 ft","75 ft","130 ft","100 ft"], re:"NFPA 72 18.5.5.5: la separación de las luces estroboscópicas de pasillo no deberá exceder 100 ft entre aparatos."},
  {id:121, q:"Según NFPA 72, un pasillo más ancho que 20 ft debe tratarse, para el espaciamiento de notificación visible, como:", opts:["Una sala (usando las reglas de espaciamiento de salas)","Un pasillo con luces estroboscópicas de 15 cd","Un espacio exterior","Un pleno"], re:"NFPA 72 18.5.5.5: los pasillos de más de 20 ft de ancho se espacian como salas (Tabla 18.5.5.4.1), generalmente requiriendo mayor candela."},
  {id:122, q:"Para una sola luz estroboscópica montada en pared, ¿qué candela mínima se requiere para cubrir una sala de 20 ft × 20 ft?", opts:["30 cd","15 cd","60 cd","75 cd"], re:"NFPA 72 Tabla 18.5.5.4.1(a): una luz montada en pared que cubra una sala de 20×20 ft requiere 15 cd como mínimo."},
  {id:123, q:"Usando una sola luz estroboscópica montada en pared, ¿qué candela mínima cubre una sala de 40 ft × 40 ft?", opts:["30 cd","95 cd","60 cd","135 cd"], re:"NFPA 72 Tabla 18.5.5.4.1(a): una sola luz estroboscópica montada en pared para una sala de 40×40 ft requiere 60 cd."},
  {id:124, q:"Los aparatos visibles de notificación montados en pared deben instalarse con todo el lente en qué rango de altura sobre el piso terminado?", opts:["48 a 72 in.","60 a 80 in.","96 a 120 in.","80 a 96 in."], re:"NFPA 72 18.5.5.2: las luces estroboscópicas montadas en pared deberán tener todo el lente entre 80 in. y 96 in. sobre el piso terminado (o 6 in. por debajo del techo si este es más bajo)."},
  {id:125, q:"La altura máxima de montaje permitida para un aparato visible montado en techo según las tablas de espaciamiento de NFPA 72 es:", opts:["30 ft","25 ft","20 ft","40 ft"], re:"NFPA 72 18.5.5.4 / Tabla 18.5.5.4.1(b): las tablas de espaciamiento de luces estroboscópicas de techo se extienden hasta una altura de montaje de 30 ft; los aparatos por encima de 30 ft se suspenden a 30 ft o menos."},
  {id:126, q:"Para una habitación de dormir, una luz estroboscópica de pared montada a más de 24 in. por debajo del techo debe ser de al menos:", opts:["75 cd","110 cd","135 cd","177 cd"], re:"NFPA 72 18.5.5.7: las luces estroboscópicas de área de dormir requieren 110 cd cuando se montan a más de 24 in. del techo."},
  {id:127, q:"Para una habitación de dormir, una luz estroboscópica montada a menos de 24 in. del techo debe ser de al menos:", opts:["110 cd","135 cd","177 cd","185 cd"], re:"NFPA 72 18.5.5.7: cuando una luz estroboscópica de habitación de dormir está dentro de 24 in. del techo, se requiere un aparato de 177 cd para superar la atenuación de la capa de humo."},
  {id:128, q:"Desde las Normas ADA de 2010, los aparatos visibles de alarma de incendio deben instalarse conforme a:", opts:["Solo ICC A117.1","Solo la preferencia del fabricante","Solo el código de incendios local","NFPA 72"], re:"Las Normas ADA de 2010 (e ICC A117.1) hacen referencia a NFPA 72 para la ubicación y candela de las alarmas visibles, armonizando las reglas de accesibilidad y de alarma de incendio."},
  {id:129, q:"Los aparatos visibles se requieren principalmente para alertar a qué ocupantes?", opts:["Personas sordas o con dificultades auditivas","Solo a los ocupantes que duermen","Solo al personal de mantenimiento","A los peatones en el exterior"], re:"NFPA 72 / ADA: las luces estroboscópicas proveen notificación a las personas sordas o con dificultades auditivas, un requisito de accesibilidad en espacios ocupables."},
  {id:130, q:"Las tablas de cobertura de luces estroboscópicas en NFPA 72 se basan en qué geometría de sala?", opts:["Salas circulares","Salas cuadradas","Salas en forma de L","Salas triangulares"], re:"NFPA 72 18.5.5.4: las tablas de espaciamiento de salas suponen salas cuadradas; las salas no cuadradas se subdividen en cuadrados para la cobertura."},
  {id:131, q:"Para una sala de 50 ft × 50 ft, ¿qué candela mínima se requiere usando una sola luz estroboscópica montada en pared?", opts:["60 cd","75 cd","95 cd","135 cd"], re:"NFPA 72 Tabla 18.5.5.4.1(a): una sola luz estroboscópica montada en pared que cubra una sala de 50×50 ft requiere 95 cd."},
  {id:132, q:"Una luz estroboscópica estándar (de cobertura no extendida) listada por UL NO suele estar disponible en cuál clasificación de candelas?", opts:["15 cd","75 cd","110 cd","185 cd"], re:"Las luces estroboscópicas estándar se listan a 15/30/75/95/110 cd; 177 y 185 cd son clasificaciones de cobertura extendida, no valores de cobertura estándar."},
  {id:133, q:"Si una sala requiere más de dos luces estroboscópicas de pared para lograr la cobertura requerida, NFPA 72 exige que las luces estroboscópicas estén:", opts:["Sincronizadas","De colores diferentes","Montadas solo en el techo","Clasificadas a 15 cd"], re:"NFPA 72 18.5.5.4.6: cuando hay más de dos aparatos visibles dentro de cualquier campo de visión, deben destellar en sincronización para limitar el riesgo de convulsiones."},
  {id:134, q:"Los aparatos visibles de notificación deben producir destellos que sean transparentes o de qué color?", opts:["Rojo","Blanco","Azul","Ámbar"], re:"NFPA 72 18.5.4: los aparatos visibles de alarma de incendio deberán ser transparentes o de color blanco nominal; otros colores (p. ej., ámbar/azul) se reservan para señalización no de incendio, como la MNS."},
  {id:135, q:"Un circuito de aparatos de notificación Clase B se supervisa para verificar su integridad por medio de:", opts:["Una vía de retorno redundante al panel","Solo un detector de falla a tierra","Una resistencia de fin de línea (EOLR)","Un segundo panel de control"], re:"NFPA 72 12.3 / Anexo: un NAC Clase B termina en una resistencia de fin de línea, de modo que una corriente de supervisión baja detecta aberturas; una sola interrupción deshabilita los dispositivos aguas abajo."},
  {id:136, q:"Una ventaja clave de un NAC Clase A sobre un NAC Clase B es que:", opts:["Usa menos conductores","Elimina la necesidad de energía","No requiere supervisión","Continúa operando los aparatos después de una sola abertura (corte de cable)"], re:"NFPA 72 12.3: un circuito Clase A provee una vía de retorno redundante, por lo que una sola abertura no impide la operación de los aparatos; el Clase B pierde todo lo que está aguas abajo del corte."},
  {id:137, q:"¿Cuántos conductores (vías) usa un circuito de aparatos de notificación Clase A?", opts:["4","2","1","6"], re:"NFPA 72 12.3: el Clase A usa 4 cables (el par de salida más un par de retorno redundante) de modo que el circuito se monitorea para verificar su integridad y sobrevive a una sola abertura."},
  {id:138, q:"Los circuitos de aparatos de notificación se supervisan de modo que una sola abertura o falla a tierra resulte en qué?", opts:["Falla silenciosa","Una señal de problema en la unidad de control","Una alarma automática","Evacuación inmediata"], re:"NFPA 72 10.17 / 12.3: las fallas en circuitos supervisados anuncian una señal de problema dentro del tiempo requerido para que la avería sea conocida y reparada."},
  {id:139, q:"La mayoría de los aparatos de notificación polarizados modernos se conectan al NAC usando:", opts:["Cableado de CA no polarizado","Energía trifásica","Cableado de CC polarizado con la polaridad correcta","Cable coaxial"], re:"Práctica de NFPA 72: las bocinas/luces estroboscópicas convencionales son dispositivos de CC polarizados; se requiere la polaridad correcta para que los aparatos se activen y para que la supervisión funcione."},
  {id:140, q:"¿Cuál es el propósito de realizar un cálculo de caída de voltaje en un NAC?", opts:["Establecer el retardo de verificación de alarma","Dimensionar el espaciamiento de los detectores de humo","Seleccionar el color de la luz estroboscópica","Asegurar que el último aparato reciba al menos su voltaje de operación nominal mínimo"], re:"NFPA 72 / práctica de diseño: los cálculos de caída de voltaje confirman que el aparato de fin de línea aún recibe al menos su voltaje mínimo listado por UL para que opere y permanezca en sincronización."},
  {id:141, q:"Si el voltaje en la última luz estroboscópica de un NAC cae por debajo del mínimo listado del aparato, el resultado más probable es:", opts:["El aparato puede no operar o perder la sincronización","La luz estroboscópica destella con más brillo","El panel se reinicia","El nivel sonoro ambiental aumenta"], re:"Práctica de diseño según NFPA 72: un voltaje insuficiente en el aparato puede impedir la activación o causar que las luces estroboscópicas se salgan de sincronización."},
  {id:142, q:"Un panel extensor de potencia (booster) de NAC se usa principalmente para:", opts:["Convertir CA en gas","Proveer potencia regulada adicional y respaldo de batería para más aparatos","Reemplazar la unidad de control de alarma de incendio","Eliminar la necesidad de supervisión de fin de línea"], re:"NFPA 72: un extensor de potencia de NAC listado suministra potencia adicional supervisada y respaldada por batería para que cargas grandes de aparatos excedan la capacidad de NAC del panel principal."},
  {id:143, q:"Los circuitos de aparatos de notificación deben ser supervisados eléctricamente para que se detecten las fallas. Esto lo exige:", opts:["Solo el Artículo 90 del NEC","ASHRAE 90.1","NFPA 72 (monitoreo de integridad)","Solo ADA"], re:"NFPA 72 10.17 / 12.3: las vías que sirven a los aparatos de notificación deben monitorearse para verificar su integridad (supervisarse) a menos que estén específicamente exentas."},
  {id:144, q:"¿Cuál describe una distinción de circuito de 'liberación' frente a 'notificación' relevante para el diseño de NAC?", opts:["Ambos son idénticos","Los circuitos de notificación no pueden supervisarse","Un NAC siempre opera válvulas de rociadores","Un NAC impulsa aparatos audibles/visibles, no la liberación de supresión"], re:"NFPA 72: los circuitos de aparatos de notificación impulsan bocinas/luces estroboscópicas/altavoces; las funciones de liberación usan circuitos de liberación listados separados con sus propios requisitos."},
  {id:145, q:"Cuando se agregan aparatos a un NAC existente, el diseñador debe volver a verificar cuáles dos cosas?", opts:["Consumo de corriente (capacidad del panel) y caída de voltaje de fin de línea","Color de pintura y tamaño de etiqueta","Temperatura ambiente y humedad","Sensibilidad de los detectores de humo"], re:"Práctica de diseño de NFPA 72: los aparatos agregados aumentan la carga de corriente, por lo que tanto el consumo total frente a la clasificación del circuito como el voltaje de fin de línea deben volver a verificarse."},
  {id:146, q:"Un NAC Clase B difiere de un NAC Clase A en que un solo corte de cable en el Clase B:", opts:["No tiene efecto","Deshabilita todos los aparatos conectados después del corte","Aumenta la salida del aparato","Activa una alarma general"], re:"NFPA 72 12.3: en el Clase B, los dispositivos aguas abajo de una abertura se pierden porque no hay vía de retorno redundante; solo la supervisión de fin de línea reporta el problema."},
  {id:147, q:"Los aparatos de notificación en un circuito que deben destellar juntos suelen requerir qué característica del panel o del módulo de sincronización?", opts:["Un generador de destello aleatorio","Una temperatura ambiente más alta","Una señal/protocolo de sincronización","Un lente ámbar"], re:"NFPA 72 18.5.5.4.6: un módulo de sincronización o un panel compatible provee una señal de sincronización para que todas las luces estroboscópicas en un campo de visión destellen juntas."},
  {id:148, q:"La corriente máxima que puede transportar un NAC está limitada principalmente por:", opts:["El color del lente de la luz estroboscópica","El nivel sonoro ambiental","El número de estaciones manuales","La clasificación del circuito del panel/booster y la ampacidad/caída de voltaje del conductor"], re:"Diseño de NFPA 72: la carga del NAC está limitada por la corriente de salida nominal de la fuente y por la caída de voltaje del conductor, asegurando que todos los aparatos permanezcan dentro del voltaje listado."},
  {id:149, q:"¿Qué práctica de conductores ayuda a minimizar la caída de voltaje en un tramo largo de NAC?", opts:["Usar cable de mayor calibre (menor resistencia)","Usar cable de menor calibre","Aumentar el número de empalmes","Agregar más resistencias de fin de línea"], re:"Diseño básico de circuitos según NFPA 72: los conductores de mayor calibre tienen menor resistencia, reduciendo la caída de voltaje para que los aparatos de fin de línea reciban voltaje adecuado."},
  {id:150, q:"¿Por qué deben calcularse las cargas de NAC de las luces estroboscópicas usando la corriente del peor caso (de arranque/pico) del aparato?", opts:["Las luces estroboscópicas nunca consumen corriente","Las luces estroboscópicas consumen un breve pico alto en cada destello que la fuente debe sostener","Solo las bocinas consumen corriente","La corriente es irrelevante para las luces estroboscópicas"], re:"Práctica de diseño: las luces estroboscópicas consumen una breve corriente pico alta en cada destello; la fuente del NAC debe soportar el pico para mantener la salida y la sincronización."},
  {id:151, q:"En general, una 'derivación en T' (rama paralela) NO está permitida en cuál clase de circuito sin perder su clasificación?", opts:["Clase B","Cualquier circuito de bajo voltaje","Clase A (rompería el lazo redundante)","Solo potencia limitada"], re:"NFPA 72 12.3: el Clase A requiere un lazo continuo de regreso al panel; una derivación en T anula el retorno redundante y el beneficio de integridad del Clase A."},
  {id:152, q:"Los Sistemas de Comunicaciones de Emergencia se abordan en cuál capítulo de NFPA 72?", opts:["Capítulo 14","Capítulo 18","Capítulo 29","Capítulo 24"], re:"NFPA 72 Capítulo 24 cubre los Sistemas de Comunicaciones de Emergencia (ECS), incluidos la evacuación por voz de incendio en edificios y los sistemas de notificación masiva (MNS)."},
  {id:153, q:"¿Cuál es el Índice de Transmisión del Habla (STI) promedio que debe cumplirse en cada espacio acústicamente distinguible (ADS) para un ECS inteligible?", opts:["0.50","0.45","0.35","0.70"], re:"NFPA 72 Capítulo 24 / Anexo D: el STI promedio en cada ADS debe ser de al menos 0.50, con al menos el 90 % de los puntos en o por encima de 0.45."},
  {id:154, q:"Al menos el 90 % de los puntos de medición dentro de un ADS deben alcanzar un STI no menor que:", opts:["0.35","0.45","0.55","0.65"], re:"NFPA 72 Anexo D: el 90 % de los puntos medidos en cada ADS debe alcanzar STI ≥ 0.45 (≈0.65 CIS), con un promedio de área ≥ 0.50."},
  {id:155, q:"Un 'espacio acústicamente distinguible' (ADS) es un espacio distinguido por sus:", opts:["Pintura e iluminación","Solo número de salidas","Características acústicas, ambientales o de uso (p. ej., reverberación, nivel ambiental)","Color del techo"], re:"NFPA 72 3.3 / 24: un ADS es un área distinguida de otras por características acústicas, ambientales o de uso, como el tiempo de reverberación y la presión sonora ambiental."},
  {id:156, q:"En un sistema combinado de alarma de incendio / notificación masiva, NFPA 72 permite que cuál mensaje tenga prioridad donde el análisis de riesgos lo requiera?", opts:["Siempre la señal de alarma de incendio","La señal de control de HVAC","Ninguno; no pueden coexistir","El mensaje de notificación masiva (MNS)"], re:"NFPA 72 Capítulo 24: aunque el incendio históricamente tuvo la mayor prioridad, el análisis de riesgos puede dar prioridad a la MNS sobre la alarma de incendio (p. ej., escenarios de amenaza activa)."},
  {id:157, q:"Un mensaje de voz en vivo difundido a través de un sistema de evacuación por voz deberá ser capaz de anular qué?", opts:["El mensaje de evacuación automático (pregrabado)","El suministro de agua del edificio","El sistema de rociadores","Solo el reclamo del ascensor"], re:"NFPA 72 24.4: un anuncio de voz en vivo debidamente autorizado debe poder anular el mensaje pregrabado automático para dar instrucciones en tiempo real."},
  {id:158, q:"Para la MNS en edificios, el nivel requerido de capacidad de supervivencia de la vía se determina mediante:", opts:["La candela de la luz estroboscópica","El análisis de riesgos","La temperatura ambiente","El número de estaciones manuales"], re:"NFPA 72 24.5: la capacidad de supervivencia de la vía para la notificación masiva en edificios se establece mediante el análisis de riesgos documentado en lugar de un nivel fijo."},
  {id:159, q:"La notificación masiva de destinatarios distribuidos (p. ej., alertas por texto/correo electrónico) según NFPA 72:", opts:["Puede reemplazar la alerta audible/visible requerida","Está prohibida por completo","No deberá usarse en lugar de la alerta audible y visible requerida","No requiere integración"], re:"NFPA 72 24.7: la MNS de destinatarios distribuidos complementa pero no deberá reemplazar la notificación audible y visible requerida en el edificio."},
  {id:160, q:"La medición cuantitativa del STI según NFPA 72 es:", opts:["Siempre obligatoria en cada punto","Requerida solo para alarmas residenciales","Prohibida","No obligatoria; una prueba de escucha puede ser aceptable, pero aplican criterios cuando se mide"], re:"NFPA 72 Anexo D: la inteligibilidad puede verificarse mediante una prueba de escucha calificada; si se mide STI/CIS cuantitativo, aplican los criterios de 0.45/0.50."},
  {id:161, q:"La razón principal por la que se usan sistemas de evacuación por voz en lugar de solo bocinas en edificios altos es:", opts:["Proveer instrucciones inteligibles para evacuación por fases/reubicación","Reducir el cableado","Bajar el nivel sonoro ambiental","Evitar las luces estroboscópicas"], re:"NFPA 72 24.4 / IBC: la evacuación por voz permite la evacuación por fases y la reubicación con instrucciones habladas claras, que un tono solo no puede transmitir."},
  {id:162, q:"Antes de una señal de tono de voz (alerta/alarma) en un ECS, NFPA 72 comúnmente usa qué para captar la atención?", opts:["Solo una pausa silenciosa","Una señal preliminar de alerta/atención (p. ej., un tono) que precede al mensaje de voz","Solo un cambio de color de la luz estroboscópica","Una descarga de rociadores"], re:"NFPA 72 24.4: un tono de alerta normalmente precede al mensaje de voz para captar la atención antes de entregar las instrucciones."},
  {id:163, q:"Los aparatos de altavoz en un sistema de voz suelen seleccionarse por su ajuste de 'derivación' de potencia (p. ej., 1/4, 1/2, 1, 2 W) para controlar:", opts:["La candela de la luz estroboscópica","El valor de la resistencia de fin de línea","La salida acústica (nivel sonoro) para el espacio","La química de la batería"], re:"NFPA 72 / diseño: los ajustes de derivación del altavoz establecen el vataje y, por lo tanto, la salida sonora, permitiendo ajustar la audibilidad y la inteligibilidad por espacio."},
  {id:164, q:"Los sistemas de notificación masiva de área amplia (p. ej., 'voz gigante' al aire libre) según el Capítulo 24 de NFPA 72 están destinados principalmente a:", opts:["Proveer solo señales visibles","Reemplazar los detectores de humo interiores","Operar ascensores","Notificar a personas en el exterior sobre áreas grandes"], re:"NFPA 72 24.6: la MNS de área amplia (arreglos de altavoces de alta potencia / voz gigante) entrega mensajes inteligibles a través de grandes áreas exteriores de campus."},
  {id:165, q:"En un ECS, la prioridad más alta generalmente se asigna en función de:", opts:["El riesgo relativo de seguridad de vida según lo establecido por el diseño/análisis de riesgos del sistema","El dispositivo que se activó primero","El orden alfabético de los mensajes","El menor consumo de corriente"], re:"NFPA 72 Capítulo 24: la prioridad del mensaje se establece según el riesgo de seguridad de vida conforme al diseño/análisis de riesgos para que se difunda la instrucción más crítica."},
  {id:166, q:"Una unidad de control autónoma (ACU) en un sistema de notificación masiva funciona como:", opts:["El lente de la luz estroboscópica","El punto de control que monitorea y controla la MNS","Una resistencia de fin de línea","Solo una estación manual"], re:"NFPA 72 24.3: la ACU es el punto principal de control y monitoreo del sistema de notificación masiva, a menudo interconectado con el sistema de alarma de incendio."},
  {id:167, q:"La inteligibilidad de la voz se degrada más en espacios con:", opts:["Baja reverberación y bajo ruido ambiental","Sin ocupantes","Alto tiempo de reverberación y alto ruido ambiental","Solo pisos alfombrados"], re:"NFPA 72 Anexo D: los tiempos de reverberación largos y el alto ruido de fondo reducen el STI, haciendo que tales espacios sean más difíciles de hacer inteligibles."},
  {id:168, q:"¿Qué sección de qué documento provee la metodología y la guía para la inteligibilidad del ECS?", opts:["Solo ICC A117.1","NEC Capítulo 9","OSHA 1926","NFPA 72 Anexo D"], re:"NFPA 72 Anexo D contiene la metodología informativa para evaluar y diseñar la inteligibilidad del habla en ECS."},
  {id:169, q:"¿Cuál es la frecuencia máxima aceptable de destello de luz estroboscópica permitida por NFPA 72?", opts:["2 Hz (120 fpm)","1 Hz (60 fpm)","3 Hz (180 fpm)","5 Hz (300 fpm)"], re:"NFPA 72 18.5.4.4: los aparatos visibles deberán destellar a un máximo de 2 Hz (120 destellos/min) para reducir el riesgo de convulsiones fotosensibles."},
  {id:170, q:"¿Cuál es la frecuencia mínima de destello requerida para una luz estroboscópica de alarma de incendio según NFPA 72?", opts:["0.5 Hz","1 Hz","2 Hz","4 Hz"], re:"NFPA 72 18.5.4.4: la frecuencia mínima de destello es 1 Hz (60 destellos/min) para proveer notificación visible adecuada."},
  {id:171, q:"La sincronización de luces estroboscópicas se requiere principalmente para prevenir:", opts:["Consumo excesivo de corriente","Retroalimentación audible","Convulsiones epilépticas fotosensibles por las frecuencias de destello acumuladas en un campo de visión","Falla de la resistencia de fin de línea"], re:"NFPA 72 18.5.5.4.6 / Anexo: sincronizar las luces estroboscópicas mantiene la frecuencia de destello compuesta en un campo de visión en o por debajo de la frecuencia de dos luces estroboscópicas, limitando el riesgo de convulsiones."},
  {id:172, q:"¿La sincronización se requiere cuando cuántos aparatos visibles están dentro del campo de visión de una persona?", opts:["Cualquier número, siempre 1","Más de 5","Exactamente 1","Más de 2"], re:"NFPA 72 18.5.5.4.6: donde hay más de dos aparatos visibles en cualquier campo de visión, deberán destellar en sincronización."},
  {id:173, q:"Los niveles de capacidad de supervivencia de las vías en NFPA 72 se definen principalmente en cuál capítulo?", opts:["Capítulo 12","Capítulo 10","Capítulo 18","Capítulo 23"], re:"NFPA 72 Capítulo 12 (Circuitos y Vías) define los Niveles 0-3 de capacidad de supervivencia de las vías (el Nivel 4 se agregó en 2022)."},
  {id:174, q:"Para sistemas de evacuación por voz de incendio en edificios que sirven a reubicación o evacuación parcial, ¿qué nivel mínimo de capacidad de supervivencia de la vía se requiere?", opts:["Nivel 0","Nivel 2 (o 3)","Nivel 1","No se necesita capacidad de supervivencia"], re:"NFPA 72 24.3.6 / 12.4: los sistemas que usan reubicación o evacuación parcial requieren capacidad de supervivencia de la vía de Nivel 2 o Nivel 3."},
  {id:175, q:"Los niveles 2 y 3 de capacidad de supervivencia de la vía generalmente requieren:", opts:["Ningún cableado especial","Solo conducto de plástico","Cable o envolvente con clasificación de resistencia al fuego de 2 horas","Solo cable de aluminio"], re:"NFPA 72 12.4: la capacidad de supervivencia de Nivel 2 y Nivel 3 requiere cable o envolvente de integridad de circuito con clasificación de resistencia al fuego de 2 horas; el Nivel 3 también requiere un edificio totalmente rociado."},
  {id:176, q:"¿Qué condición adicional del edificio requiere la capacidad de supervivencia de la vía de Nivel 3 más allá del Nivel 2?", opts:["Solo una tubería vertical (standpipe)","Luces estroboscópicas ámbar","Dos paneles de control","Un edificio totalmente rociado"], re:"NFPA 72 12.4: la capacidad de supervivencia de Nivel 3 requiere protección con clasificación de 2 horas Y un edificio totalmente protegido por rociadores automáticos."},
  {id:177, q:"La capacidad de supervivencia de la vía de Nivel 4, agregada en la edición de 2022, requiere como mínimo:", opts:["Cable o envolvente con clasificación de resistencia al fuego de 1 hora","Ninguna protección","Solo canalización metálica","Enterramiento subterráneo"], re:"NFPA 72 (2022) 12.4: se agregó el Nivel 4, que requiere cables o envolventes con clasificación de resistencia al fuego de 1 hora (una opción distinta de los Niveles 2/3 de 2 horas)."},
  {id:178, q:"El cable de integridad de circuito (CI) se usa en sistemas de alarma de incendio específicamente para proveer:", opts:["Menor costo de instalación","Operación continua durante un incendio por un tiempo clasificado","Mejor velocidad de datos","Solo codificación por color"], re:"NFPA 72 12.4: el cable CI / con clasificación de resistencia al fuego mantiene la operación del circuito durante una duración listada (p. ej., 2 horas) bajo exposición al fuego, apoyando la capacidad de supervivencia."},
  {id:179, q:"Para permanecer en sincronización, las luces estroboscópicas de un circuito generalmente deberían ser:", opts:["De cualquier mezcla de fabricantes","Solo de diferente candela","Compatibles/listadas para sincronización (a menudo del mismo fabricante/protocolo)","Cableadas con polaridad invertida"], re:"NFPA 72 / listado: las luces estroboscópicas deben usar un protocolo de sincronización compatible (comúnmente sincronización del mismo fabricante) para destellar juntas de forma confiable."},
  {id:180, q:"Donde múltiples luces estroboscópicas son visibles en la intersección de un pasillo en forma de L, la sincronización aborda:", opts:["Reducción de la vida de la batería","El llenado del conducto","La interferencia audible","La frecuencia de destello acumulada (compuesta) vista por un observador"], re:"NFPA 72 Anexo: una persona en un cruce de pasillos podría ver varias luces estroboscópicas; la sincronización mantiene la frecuencia de destello compuesta en/por debajo de la frecuencia de dos luces estroboscópicas para limitar el riesgo de convulsiones."},
  {id:181, q:"La capacidad de supervivencia de la vía de Nivel 1 normalmente permite cable estándar con clasificación de resistencia al fuego cuando se instala en un edificio totalmente rociado y se tiende en:", opts:["Canalización metálica o cable con armadura metálica","Aire libre","Solo PVC","Sin canalización alguna"], re:"NFPA 72 12.4: el Nivel 1 permite cable convencional con clasificación de resistencia al fuego en un edificio rociado cuando se instala en canalización metálica (conducto) o cable con armadura metálica."},
  {id:182, q:"Los requisitos de capacidad de supervivencia de la vía existen para asegurar que, durante un incendio, los circuitos de notificación:", opts:["Usen menos energía","Sigan operando el tiempo suficiente para alertar y reubicar a los ocupantes","Destellen un color diferente","Reduzcan la salida sonora"], re:"NFPA 72 12.4 intención: la capacidad de supervivencia mantiene las vías de señalización funcionales durante la exposición al fuego para que los ocupantes puedan ser notificados y trasladados a un lugar seguro."},
  {id:183, q:"Las luces estroboscópicas que se salen de sincronización debido a bajo voltaje crean qué peligro que NFPA 72 busca evitar?", opts:["Audibilidad excesiva","Distorsión de color","Una frecuencia de destello compuesta inaceptable que puede desencadenar convulsiones","Fallas a tierra"], re:"NFPA 72 18.5.5.4.6 / Anexo: la pérdida de sincronización eleva la frecuencia de destello compuesta percibida en un campo de visión, la misma condición que la sincronización pretende prevenir."},
  {id:184, q:"¿Cuál es verdadero sobre el Nivel 0 de capacidad de supervivencia de la vía?", opts:["Provee protección de 2 horas","Exige solo Clase A","Requiere rociadores y cable de 1 hora","No provee capacidad de supervivencia específica (ninguna protección contra incendios adicional de la vía)"], re:"NFPA 72 12.4: el Nivel 0 indica que no se provee capacidad de supervivencia de la vía; los niveles superiores agregan protección contra incendios creciente del circuito."},
  {id:185, q:"El patrón de señal audible estándar de evacuación requerido por NFPA 72 se conoce como:", opts:["ANSI/Patrón temporal tres (T-3)","Código temporal 4 (T-4)","Tiempo de marcha","Tono continuo"], re:"NFPA 72 18.4.2: la señal de evacuación estándar es el patrón temporal tres (T-3) de ANSI S3.41."},
  {id:186, q:"El patrón temporal tres consiste en tres pulsos, cada uno 'encendido' durante aproximadamente:", opts:["0.25 s","0.5 s","1.0 s","1.5 s"], re:"NFPA 72 18.4.2 / ANSI S3.41: el T-3 son tres pulsos 'encendidos' de 0.5 s separados por intervalos 'apagados' de 0.5 s, luego una pausa de 1.5 s, repetidos."},
  {id:187, q:"Después de los tres pulsos, el patrón temporal tres incluye un tiempo de apagado (pausa) de aproximadamente:", opts:["0.5 s","1.0 s","1.5 s","3.0 s"], re:"NFPA 72 / ANSI S3.41: el ciclo T-3 termina con un período 'apagado' de 1.5 s antes de que comience el siguiente conjunto de tres pulsos."},
  {id:188, q:"Un ciclo completo del patrón temporal tres (3 pulsos de encendido/apagado más la pausa larga) dura aproximadamente:", opts:["2 segundos","8 segundos","6 segundos","4 segundos"], re:"NFPA 72 / ANSI S3.41: tres encendidos de 0.5 s + tres apagados de 0.5 s (≈3 s, siendo el último apagado la pausa de 1.5 s) da un ciclo total de ~4 segundos."},
  {id:189, q:"Para una señal de evacuación total, el patrón temporal tres debe sonar de forma continua durante un mínimo de:", opts:["180 segundos (3 minutos)","60 segundos","30 segundos","10 minutos"], re:"NFPA 72 / ANSI S3.41: la señal de evacuación T-3 debe ser capaz de sonar durante al menos 180 segundos cuando se pretende la evacuación total."},
  {id:190, q:"La notificación de modo público está destinada a alertar a:", opts:["Solo al personal capacitado","A los ocupantes generales del edificio","Solo a la estación de monitoreo","Solo al personal de mantenimiento"], re:"NFPA 72 3.3 / 18.4: la señalización de modo público notifica a los ocupantes generales y tiene requisitos de nivel sonoro más altos que el modo privado."},
  {id:191, q:"La notificación de modo privado está destinada a:", opts:["El público en general","Los peatones en el exterior","Las personas directamente involucradas con la implementación/respuesta (p. ej., personal capacitado)","Solo huéspedes que duermen"], re:"NFPA 72 3.3: la señalización de modo privado alerta solo a las personas involucradas con la operación/respuesta del sistema y permite niveles sonoros más bajos (10 dBA por encima del ambiente)."},
  {id:192, q:"Cuando el objetivo es la evacuación total del edificio, ¿cuál señal tiene precedencia sobre otros tonos?", opts:["Una campana continua","Un solo carillón","Una señal codificada de tiempo de marcha","El patrón temporal tres de evacuación"], re:"NFPA 72 18.4.2: el patrón temporal tres es la señal de evacuación distintiva y tiene precedencia cuando se pretende la evacuación total."},
  {id:193, q:"¿Cuál patrón está específicamente reservado por ANSI/NFPA de modo que NO se use para señalización rutinaria de no evacuación?", opts:["Patrón temporal tres (T-3)","Tono continuo","Un solo pitido corto","Encendido/apagado lento a 0.1 Hz"], re:"NFPA 72 / ANSI S3.41: el patrón temporal tres está reservado como la señal de evacuación estándar para que los ocupantes reconozcan de forma confiable 'evacuar ahora'."},
  {id:194, q:"NFPA 72 designa la señal de alarma de monóxido de carbono como un patrón temporal cuatro (T-4) para:", opts:["Coincidir exactamente con la señal de incendio","Distinguir las alarmas de CO de la señal de evacuación de incendio (T-3)","Indicar un problema de supervisión","Señalar el fin de la prueba"], re:"NFPA 72 / legado de NFPA 720: las alarmas de CO usan un patrón temporal cuatro (T-4) distintivo para que los ocupantes no confundan una alarma de CO con la señal de evacuación de incendio T-3."},
  {id:195, q:"Un mensaje de evacuación por voz que instruye a los ocupantes de pisos específicos a reubicarse en lugar de evacuar completamente apoya qué estrategia?", opts:["Alarma silenciosa","Solo evacuación total inmediata","Defensa en el lugar / evacuación por fases (reubicación)","Sin notificación"], re:"NFPA 72 24.4 / IBC: la evacuación por voz permite estrategias de fases/reubicación, moviendo solo a los ocupantes afectados mientras otros se refugian, común en edificios altos y atención médica."},
  {id:196, q:"En ocupaciones con áreas de dormir, la notificación a ocupantes debe satisfacer adicionalmente cuál requisito especial?", opts:["Sonido más bajo que el modo público","No se requiere notificación","Solo luces estroboscópicas, sin audible","75 dBA en la almohada y una señal de baja frecuencia"], re:"NFPA 72 18.4.5: las áreas de dormir requieren al menos 75 dBA en la almohada y una señal de baja frecuencia de 520 Hz para un despertar eficaz."},
  {id:197, q:"El propósito de usar una sola señal de evacuación reconocible (T-3) a nivel nacional es:", opts:["Asegurar que los ocupantes reconozcan universalmente el significado de 'evacuar'","Reducir el costo de los aparatos","Limitar la candela de las luces estroboscópicas","Reemplazar los sistemas de voz"], re:"NFPA 72 / intención de ANSI S3.41: un patrón T-3 estandarizado crea un reconocimiento universal para que las personas respondan correctamente sin importar el edificio."},
  {id:198, q:"Los aparatos de notificación a ocupantes deben instalarse de modo que la señal sea:", opts:["Audible/visible solo en pasillos","Audible (y visible donde se requiera) en todas las áreas que requieren notificación","Limitada al vestíbulo","Activa solo de noche"], re:"NFPA 72 18.4 / 18.5: la notificación debe alcanzar todas las áreas que se requiere notificar, cumpliendo los criterios de nivel sonoro y de cobertura visible en todas esas áreas."},
  {id:199, q:"¿Cuál describe mejor cuándo es aceptable la señalización de modo privado (niveles más bajos) en lugar del modo público?", opts:["Siempre, en cualquier edificio","Solo en viviendas unifamiliares","Solo donde el AHJ/código lo permita y el personal capacitado responda (p. ej., cierta atención médica)","Nunca"], re:"NFPA 72 18.4.4: el modo privado se permite donde los códigos/AHJ lo permiten y el personal es responsable de la respuesta de los ocupantes, como en algunas unidades de atención médica."},
  {id:200, q:"Durante una emergencia real, un anuncio de voz en vivo autorizado en el ECS es valioso porque puede:", opts:["Bajar la temperatura del edificio","Aumentar la candela de las luces estroboscópicas automáticamente","Deshabilitar los rociadores","Proveer instrucciones en tiempo real específicas de la situación que anulan el mensaje pregrabado"], re:"NFPA 72 24.4: un mensaje de voz en vivo da una guía actual y específica y está diseñado para anular el mensaje de evacuación pregrabado automático."},
  {id:201, q:"En la terminología de NFPA 72, ¿cuál es la función principal de la unidad de control de alarma contra incendios (FACU/FACP)?", opts:["Supervisa las entradas iniciadoras y controla las salidas del sistema (notificación y señalización)","Sirve únicamente como aparato de notificación audible del edificio","Es el receptor fuera del predio ubicado en la estación supervisora","Es la estación manual de tiro que se usa para iniciar una evacuación"], re:"NFPA 72 Cap. 10/23: la unidad de control de alarma contra incendios es el componente que supervisa las entradas (dispositivos/circuitos iniciadores) y controla las salidas como la notificación y la señalización fuera del predio: el 'cerebro' del sistema."},
  {id:202, q:"NFPA 72 exige que el suministro de energía secundaria (de respaldo) de una unidad de control de alarma contra incendios típica sostenga el sistema en reposo durante al menos cuánto tiempo?", opts:["4 horas","12 horas","24 horas","72 horas"], re:"NFPA 72 §10.6 exige que la energía secundaria opere el sistema durante 24 horas en reposo seguidas del periodo de alarma requerido."},
  {id:203, q:"Tras 24 horas en reposo con energía secundaria, un sistema básico de alarma contra incendios (sin voz) debe poder operar en alarma plena durante al menos:", opts:["5 minutos","10 minutos","15 minutos","60 minutos"], re:"NFPA 72 §10.6: tras 24 h en reposo, un sistema básico de alarma contra incendios debe sonar la alarma durante 5 minutos; los sistemas de comunicación de voz/alarma de emergencia (EVACS) requieren 15 minutos."},
  {id:204, q:"Para un sistema de comunicación de voz/alarma de emergencia dentro del edificio (EVACS), el periodo de operación de alarma con energía secundaria tras 24 h en reposo es de:", opts:["15 minutos","5 minutos","30 minutos","2 horas"], re:"NFPA 72 §10.6: los sistemas de comunicación de voz/alarma requieren 15 minutos de operación de alarma (frente a 5 minutos de los sistemas básicos) tras el periodo de reposo de 24 horas."},
  {id:205, q:"El tipo de batería más común usado como fuente de energía secundaria dentro de una unidad de control de alarma contra incendios es la:", opts:["Celda inundada de níquel-cadmio (NiCd)","Celda de bolsa de iones de litio","Batería de plomo-ácido regulada por válvula (VRLA)","Celda primaria alcalina"], re:"Guía de suministro de energía de NFPA 72: las baterías selladas de plomo-ácido reguladas por válvula (VRLA) son la fuente de energía secundaria predominante alojada en o cerca de la FACU."},
  {id:206, q:"¿Qué condición tiene la PRIORIDAD MÁS ALTA en la jerarquía de prioridad de señales de NFPA 72 en la unidad de control de alarma contra incendios?", opts:["Problema","Supervisora","Alarma de incendio","Prealarma"], re:"Prioridad de señales de NFPA 72 Cap. 10: las señales de alarma de incendio tienen precedencia sobre la prealarma, que tiene precedencia sobre la supervisora, que tiene precedencia sobre el problema (la alarma de CO se prioriza según sus propias disposiciones)."},
  {id:207, q:"¿Qué secuencia clasifica correctamente la prioridad de señales en la FACU de mayor a menor (señales de incendio)?", opts:["Alarma > prealarma > supervisora > problema","Problema > supervisora > prealarma > alarma","Supervisora > alarma > problema > prealarma","Prealarma > problema > alarma > supervisora"], re:"NFPA 72 Cap. 10: la alarma tiene precedencia sobre la prealarma, la prealarma sobre la supervisora y la supervisora sobre el problema."},
  {id:208, q:"Una válvula de control (de compuerta) de rociadores cerrada y monitoreada por un interruptor antisabotaje produce qué tipo de señal en la FACU?", opts:["Señal supervisora","Señal de alarma","Señal de problema","Señal de prealarma"], re:"NFPA 72 Cap. 10/17: una condición que requiere acción en el equipo monitoreado (p. ej., una válvula cerrada) es una señal supervisora, distinta de una alarma o de un problema del sistema."},
  {id:209, q:"Un cable roto (abierto) en un circuito de dispositivo iniciador hace que la FACU indique una:", opts:["Señal de problema","Señal de alarma","Señal supervisora","Señal de prealarma"], re:"NFPA 72 Cap. 10/12: una falla en el cableado del sistema (como un conductor abierto) es una condición de problema que debe anunciarse como señal de problema."},
  {id:210, q:"NFPA 72 exige que las tres condiciones centrales del sistema se indiquen de manera distintiva en la unidad de control. Esas tres condiciones son:", opts:["Alarma, supervisora y problema","Reposo, prueba y reinicio","Primaria, secundaria y terciaria","Local, remota y propietaria"], re:"NFPA 72 Cap. 10: la unidad de control debe indicar de manera distintiva las condiciones de alarma, supervisora y problema (cada una de forma visible, y de forma audible para alarma/supervisora/problema)."},
  {id:211, q:"Un anunciador ubicado en el vestíbulo del edificio para uso de los primeros respondedores proporciona principalmente:", opts:["Identificación de la zona o dispositivo en alarma/problema para los respondedores","La alimentación principal de 120 VCA del edificio","La carga de la batería secundaria de la panel","La trayectoria de comunicación fuera del predio"], re:"NFPA 72 Cap. 10/18: un anunciador proporciona información de estado/ubicación (zona o punto en alarma, supervisora o problema) para ayudar a los respondedores, separada de las funciones de energía o señalización."},
  {id:212, q:"Cuando falla la energía principal (de la red eléctrica) a la FACU, NFPA 72 exige que la unidad de control:", opts:["Transfiera automáticamente al suministro de energía secundaria e indique un problema","Silencie todas las indicaciones hasta que regrese la energía","Envíe una alarma de incendio inmediata al cuerpo de bomberos","Se apague para proteger las baterías"], re:"NFPA 72 §10.6: la pérdida de energía principal debe transferir automáticamente la carga a la energía secundaria, y se indica un problema de pérdida de energía de CA."},
  {id:213, q:"¿Cuál es la naturaleza del circuito de suministro principal de la FACU y cómo se identifica según NFPA 72?", opts:["Un circuito derivado dedicado, protegido mecánicamente e identificado (p. ej., rojo, rotulado 'ALARMA CONTRA INCENDIOS')","Un circuito compartido con la iluminación general, sin marcar","Cualquier tomacorriente de conveniencia en la sala","Un circuito protegido por GFCI compartido con el HVAC"], re:"NFPA 72 §10.6: el suministro principal debe ser un circuito derivado dedicado, con el medio de desconexión accesible solo al personal autorizado, protegido mecánicamente y claramente identificado (comúnmente rojo y rotulado)."},
  {id:214, q:"Una señal de problema en la FACU que ha sido silenciada (reconocida) debe, según NFPA 72, hacer qué si la condición de problema se restaura más tarde y luego vuelve a ocurrir?", opts:["Volver a sonar para cada nueva condición fuera de lo normal (problema)","Permanecer silenciada de forma permanente","Convertirse automáticamente en una alarma","Reiniciar la panel completa"], re:"NFPA 72 Cap. 10: una notificación audible de problema, aunque se haya silenciado previamente, debe volver a sonar para cada condición fuera de lo normal posterior, garantizando que las nuevas fallas no queden enmascaradas."},
  {id:215, q:"¿Cuál de las siguientes NO es una función de la unidad de control de alarma contra incendios?", opts:["Supervisar la integridad de sus circuitos","Activar los aparatos de notificación en alarma","Extinguir físicamente el incendio con un agente a bordo","Transmitir señales a una estación supervisora"], re:"La FACU monitorea, supervisa, señaliza y controla las salidas; no extingue por sí misma el incendio. La supresión la realizan sistemas separados (rociadores, agente limpio), que la panel puede liberar/monitorear."},
  {id:216, q:"NFPA 72 exige que una condición de falla a tierra que pudiera afectar la operación del sistema de alarma contra incendios sea:", opts:["Indicada mediante una señal de problema distintiva","Ignorada salvo que ocurran dos fallas","Registrada solo en la estación supervisora","Eliminada automáticamente sin indicación"], re:"NFPA 72 Cap. 10/12: una sola falla a tierra que afecte la operación requerida debe producir una indicación de señal de problema en la unidad de control."},
  {id:217, q:"La marca de 'listado' requerida en una unidad de control de alarma contra incendios indica que la unidad:", opts:["Ha sido evaluada conforme a la norma de producto aplicable por un laboratorio de pruebas reconocido","Es propiedad del cuerpo de bomberos local","Fue instalada antes de 1990","Opera solo con 12 VCC"], re:"NFPA 72 §10.3 exige que el equipo esté listado para su propósito; el listado significa que un laboratorio reconocido (p. ej., UL) ha evaluado el producto conforme a la norma aplicable."},
  {id:218, q:"En un sistema convencional (por zonas) de alarma contra incendios, cuando un detector se activa, la unidad de control puede identificar:", opts:["Solo la zona (circuito) en la que se activó un dispositivo","El dispositivo exacto que se activó, por número de serie","La sala y el tipo de dispositivo específicos automáticamente","Nada: las paneles convencionales no dan ubicación"], re:"Los sistemas convencionales agrupan los dispositivos en circuitos de dispositivos iniciadores (zonas); la panel resuelve la ubicación solo hasta la zona, no el dispositivo individual. (NFPA 72 Cap. 23; práctica de la industria.)"},
  {id:219, q:"En un sistema de alarma contra incendios direccionable, cada dispositivo iniciador:", opts:["Tiene su propia dirección única reportada a la unidad de control","Comparte una dirección común con todos los dispositivos del lazo","No puede reportar una ubicación específica","Debe estar en su propio circuito dedicado de dos hilos"], re:"Los sistemas direccionables asignan a cada dispositivo una dirección única en el circuito de línea de señalización, de modo que la panel identifica el dispositivo específico y su ubicación. (NFPA 72 Cap. 23; práctica de la industria.)"},
  {id:220, q:"El tipo de circuito usado para conectar los dispositivos iniciadores convencionales de cambio de estado (humo/calor/estaciones de tiro) a la panel es el:", opts:["Circuito de línea de señalización (SLC)","Circuito de aparatos de notificación (NAC)","Circuito de dispositivo iniciador (IDC)","Bus de comunicación de datos (DCB)"], re:"NFPA 72 Cap. 3/23: un circuito de dispositivo iniciador (IDC) conecta los dispositivos iniciadores convencionales a la unidad de control; la panel detecta un cambio de corriente cuando un dispositivo opera."},
  {id:221, q:"El circuito que transporta la comunicación direccionable y multiplexada entre la panel y los dispositivos inteligentes es el:", opts:["Circuito de línea de señalización (SLC)","Circuito de dispositivo iniciador (IDC)","Circuito de aparatos de notificación (NAC)","Circuito de energía principal"], re:"NFPA 72 Cap. 3: un circuito de línea de señalización (SLC) transporta la señalización de múltiples entradas/salidas entre los dispositivos direccionables y la unidad de control (un lazo de datos)."},
  {id:222, q:"Los dispositivos iniciadores convencionales en un IDC se cablean típicamente de modo que, en reposo normal, sus contactos están:", opts:["Normalmente cerrados y se abren en alarma","Ciclando continuamente entre abierto y cerrado","Normalmente abiertos y se cierran en alarma","Desconectados hasta que se prueban"], re:"Los dispositivos iniciadores convencionales de incendio son dispositivos de cambio de estado normalmente abiertos que se cierran al activarse; la resistencia de fin de línea (EOL) supervisa el circuito ante aberturas/cortocircuitos. (Estándar de la industria; NFPA 72 Cap. 17/23.)"},
  {id:223, q:"Una ventaja clave de un sistema direccionable sobre uno convencional para el mantenimiento es:", opts:["No necesita energía secundaria","Elimina la necesidad de cualquier supervisión del cableado","La localización más rápida del dispositivo exacto en alarma o problema","No puede generar falsas alarmas"], re:"Como cada punto se identifica individualmente, los sistemas direccionables permiten a los técnicos localizar el dispositivo exacto en alarma/problema, reduciendo el tiempo de diagnóstico. (Práctica de la industria; NFPA 72 Cap. 23.)"},
  {id:224, q:"En un sistema convencional, si se necesita mayor granularidad en la ubicación de los dispositivos, el diseñador típicamente:", opts:["Agrega más zonas (más IDC)","Asigna direcciones a cada detector","Retira las resistencias de fin de línea","Convierte el NAC en un SLC"], re:"La resolución de ubicación convencional es por zona, por lo que una ubicación más fina requiere agregar zonas/IDC. El direccionamiento es una característica de los sistemas direccionables (SLC). (Práctica de la industria.)"},
  {id:225, q:"¿Qué afirmación sobre los detectores direccionables es correcta?", opts:["Reportan solo un estado binario de alarma/normal como las unidades convencionales","No se pueden deshabilitar individualmente en la panel","Muchos pueden reportar datos analógicos/de sensibilidad y de mantenimiento (p. ej., 'sucio') a la panel","Requieren una resistencia de fin de línea en cada detector"], re:"Los detectores analógicos/direccionables comúnmente reportan valores de sensibilidad y estado de mantenimiento (p. ej., 'sensor sucio'), habilitando funciones como la compensación por deriva. (NFPA 72 Cap. 17 sensibilidad; práctica de la industria.)"},
  {id:226, q:"El circuito de aparatos de notificación (NAC) en AMBOS sistemas, convencional y direccionable, se usa para:", opts:["Alimentar y controlar bocinas, estroboscópicas y otros aparatos de notificación","Transportar datos de dispositivos direccionables","Proporcionar la energía principal del edificio","Conectarse a la estación supervisora fuera del predio"], re:"NFPA 72 Cap. 3: un circuito de aparatos de notificación (NAC) conecta y alimenta los aparatos de notificación (audibles/visibles). Existe en ambos tipos de sistema."},
  {id:227, q:"En un sistema direccionable, un módulo direccionable usado para conectar un dispositivo o zona convencional al SLC se denomina comúnmente:", opts:["Resistencia de fin de línea","Fusible de potencia limitada","Módulo monitor (de entrada)","Controlador de anunciador"], re:"Un módulo monitor (de entrada) coloca un contacto/IDC convencional en el SLC direccionable, otorgándole una dirección. Los módulos de control (relé/salida) accionan las salidas. (Práctica de la industria; NFPA 72 Cap. 23.)"},
  {id:228, q:"En comparación con un sistema convencional, la topología de cableado de un lazo SLC direccionable con mayor frecuencia:", opts:["Requiere un par de cables separado para cada dispositivo individual","No puede ser supervisada","Usa un solo par enrutado a través de todos los dispositivos (y opcionalmente de regreso a la panel)","Debe ser cable coaxial"], re:"Los SLC direccionables usan un solo par de comunicación enrutado a través de los dispositivos; los lazos Clase A regresan a la panel. Los sistemas convencionales necesitan un circuito por zona. (Práctica de la industria.)"},
  {id:229, q:"¿Cuál es una afirmación precisa sobre el anunciado convencional frente al direccionable de un solo detector de humo?", opts:["El convencional da texto a nivel de dispositivo; el direccionable da solo la zona","Ambos dan una identificación idéntica a nivel de dispositivo","El direccionable puede mostrar el detector/ubicación específicos; el convencional muestra la zona","Ninguno puede indicar la ubicación"], re:"El direccionable resuelve el dispositivo/ubicación específicos; el convencional resuelve solo hasta la zona. (Práctica de la industria; NFPA 72 Cap. 23.)"},
  {id:230, q:"Una panel de alarma contra incendios 'híbrida' es una que:", opts:["Usa solo dispositivos direccionables","No tiene energía secundaria","Admite tanto módulos convencionales IDC/de zona como lazos SLC direccionables","No puede ser supervisada"], re:"Las paneles híbridas aceptan tarjetas de zona convencionales y tarjetas de lazo direccionable, permitiendo a los diseñadores mezclar tecnologías. (Práctica de la industria.)"},
  {id:231, q:"En un sistema convencional, dos detectores separados cableados en la MISMA zona (IDC) que ambos entran en alarma:", opts:["Serán distinguidos individualmente por la panel","Se cancelarán mutuamente","Ambos simplemente indicarán que esa zona está en alarma","Causarán un problema en lugar de una alarma"], re:"Los circuitos de zona convencionales no pueden distinguir cuál dispositivo de la zona se activó; la panel muestra la zona en alarma. (Práctica de la industria; NFPA 72 Cap. 23.)"},
  {id:232, q:"¿Qué tipo de circuito generalmente NO está presente en un sistema puramente convencional (no direccionable)?", opts:["Circuito de dispositivo iniciador (IDC)","Circuito de aparatos de notificación (NAC)","Circuito de línea de señalización (SLC)","Circuito de energía principal"], re:"Los SLC transportan señalización direccionable y son característicos de los sistemas direccionables; los sistemas puramente convencionales usan IDC y NAC. (Definiciones de NFPA 72 Cap. 3.)"},
  {id:233, q:"Una ventaja que se cita con frecuencia para los sistemas convencionales sobre los direccionables es:", opts:["El direccionamiento individual de dispositivos","El reporte de sensibilidad analógica","Menor costo y simplicidad para edificios muy pequeños","La comunicación incorporada con la estación central"], re:"Para instalaciones muy pequeñas, los sistemas convencionales pueden tener menor costo y ser más simples; los beneficios del direccionamiento (identificación de puntos, datos analógicos) escalan con el tamaño del edificio. (Práctica de la industria.)"},
  {id:234, q:"En los términos de NFPA 72, un 'dispositivo direccionable' es uno que:", opts:["Tiene una dirección discreta reconocida individualmente por la unidad de control","No puede comunicar su estado","Siempre es un aparato de notificación","Opera solo en el NAC"], re:"NFPA 72 Cap. 3: un dispositivo direccionable tiene una identificación discreta (dirección) que permite a la unidad de control identificarlo individualmente en el circuito de línea de señalización."},
  {id:235, q:"Un circuito de línea de señalización (SLC) se describe mejor como un circuito que:", opts:["Suministra la energía principal de 120 VCA a la panel","Conecta solo aparatos de notificación","Transporta múltiples entradas y/o salidas de dispositivos direccionables a la unidad de control","Nunca es supervisado"], re:"NFPA 72 Cap. 3: un SLC es un circuito/trayectoria entre los dispositivos y la unidad de control sobre el cual se transportan múltiples entradas/salidas del sistema: el lazo de datos direccionable."},
  {id:236, q:"En un SLC Clase B, una sola abertura (ruptura) en el lazo:", opts:["No tendrá efecto sobre ningún dispositivo","Convertirá el lazo en Clase A","Causará la pérdida de comunicación con los dispositivos más allá de la ruptura","Causará una alarma inmediata en todo el edificio"], re:"NFPA 72 Cap. 12: una trayectoria Clase B no tiene trayectoria de retorno redundante, por lo que los dispositivos más allá de una sola abertura se pierden (y se anuncia un problema)."},
  {id:237, q:"En un SLC Clase A, una sola abertura en el lazo resulta en:", opts:["La pérdida de todos los dispositivos del lazo","Una condición de alarma permanente","La comunicación continua con todos los dispositivos a través de la trayectoria de retorno redundante","Ninguna indicación de problema"], re:"NFPA 72 Cap. 12: la Clase A proporciona una trayectoria de retorno redundante; ante una sola abertura, la panel alimenta ambos extremos, manteniendo la comunicación con todos los dispositivos mientras anuncia el problema."},
  {id:238, q:"Un dispositivo instalado en un lazo SLC que abre el circuito a cualquier lado de sí mismo cuando detecta un cortocircuito, para proteger el resto del lazo, es un:", opts:["Resistencia de fin de línea","Módulo de control/relé","Módulo aislador de cortocircuito (de aislamiento)","Relé supervisor de energía"], re:"Los módulos aisladores de cortocircuito segmentan un SLC: ante un cortocircuito se abren para aislar el segmento con falla de modo que los dispositivos restantes sigan operando. (NFPA 72 Cap. 12 aislamiento de fallas; práctica de la industria.)"},
  {id:239, q:"Según las ediciones de 2016 y posteriores de NFPA 72, una sola falla en un SLC que sirve a dispositivos direccionables no debe causar la pérdida de dispositivos en más de:", opts:["El edificio completo","50 edificios","Una zona de dispositivos direccionables","Tres pisos"], re:"NFPA 72 (2016+) revisó la regla anterior de '50 dispositivos' para exigir que una sola falla del SLC no deshabilite más de un área de notificación/zona de dispositivos direccionables; se usan aisladores para cumplirlo."},
  {id:240, q:"Los dispositivos direccionables establecen su dirección con mayor frecuencia mediante:", opts:["Únicamente el color físico de su cable","La estación supervisora","La longitud del cable desde la panel","Un ajuste de interruptor DIP/rotatorio o direccionamiento electrónico (por software)"], re:"Las direcciones se establecen mediante interruptores DIP/rotatorios o se asignan electrónicamente por la panel (software/auto-direccionamiento), según el fabricante. (Práctica de la industria.)"},
  {id:241, q:"Si dos dispositivos direccionables en el mismo SLC se configuran inadvertidamente con la MISMA dirección, el resultado típico es:", opts:["Ambos funcionan perfectamente","La panel los renumera silenciosamente","Una alarma automática","Una falla/problema (conflicto de direcciones) o un dispositivo que no reporta"], re:"Las direcciones duplicadas causan un conflicto de reporte; las paneles típicamente anuncian un problema o no logran comunicarse con uno de los dispositivos hasta que se corrige. (Práctica de la industria.)"},
  {id:242, q:"El SLC se clasifica (Clase A, B, X, N) según:", opts:["Únicamente su calibre de cable","El color de los conductores","La marca de la panel","Su desempeño bajo condiciones de falla (abertura, cortocircuito, tierra)"], re:"NFPA 72 Cap. 12: las designaciones de clase de trayectoria describen el desempeño requerido bajo condiciones de falla específicas, no solo el cable físico."},
  {id:243, q:"Un SLC Clase X se diferencia de un SLC Clase A en que la Clase X adicionalmente:", opts:["No requiere trayectoria de retorno","Usa solo dispositivos convencionales","No puede ser supervisada","Opera durante un solo CORTOCIRCUITO además de una sola abertura (con aislamiento entre dispositivos)"], re:"NFPA 72 Cap. 12: la Clase X es un circuito de trayectoria redundante que, a diferencia de la Clase A, también debe seguir operando durante un solo cortocircuito aislando las fallas entre elementos."},
  {id:244, q:"Un módulo de control (de salida) en un SLC se usa para:", opts:["Ajustar el reloj de la panel","Reemplazar la resistencia EOL en el NAC","Proporcionar energía principal","Accionar una salida como un relé, NAC o liberación de puerta desde una dirección"], re:"Los módulos de control/relé ocupan una dirección del SLC y accionan salidas (relés, NAC convencionales, liberación, funciones de puerta) bajo el mando de la panel. (Práctica de la industria; NFPA 72 Cap. 23.)"},
  {id:245, q:"Un módulo monitor (de entrada) en un SLC se usa para:", opts:["Alimentar directamente los aparatos de notificación","Comunicarse con la estación supervisora","Cargar las baterías secundarias","Llevar un contacto convencional o IDC al lazo direccionable con una dirección"], re:"Los módulos monitor/de entrada proporcionan una dirección para un contacto seco o un IDC convencional (p. ej., flujo de agua, interruptor supervisor) en el SLC. (Práctica de la industria; NFPA 72 Cap. 23.)"},
  {id:246, q:"NFPA 72 exige que la integridad de un SLC sea:", opts:["Probada solo en la instalación, nunca de nuevo","Dejada sin supervisión si es direccionable","Monitoreada solo por la estación supervisora","Monitoreada automática y continuamente ante condiciones de falla"], re:"NFPA 72 Cap. 12/10: los conductores y trayectorias de instalación, incluidos los SLC, deben monitorearse automáticamente para verificar su integridad de modo que las fallas produzcan una señal de problema."},
  {id:247, q:"¿Qué falla en un SLC Clase B anunciaría como problema una panel debidamente supervisada?", opts:["Solo un cortocircuito, nunca una abertura","No se anuncian fallas en Clase B","Solo un sensor sucio a nivel de dispositivo","Una sola abertura O una sola falla a tierra en el lazo"], re:"NFPA 72 Cap. 12: una sola abertura o una sola falla a tierra en una trayectoria monitoreada debe anunciarse como problema dentro del tiempo requerido."},
  {id:248, q:"El uso de aisladores de cortocircuito en un SLC mejora principalmente:", opts:["La capacidad de energía principal de la panel","La reproducción cromática de las estroboscópicas","La audibilidad de las bocinas","La capacidad de supervivencia del lazo al limitar cuántos dispositivos puede deshabilitar un solo cortocircuito"], re:"Los aisladores confinan un cortocircuito a un segmento de modo que el resto del lazo siga comunicándose, mejorando la tolerancia a fallas/capacidad de supervivencia del SLC. (NFPA 72 Cap. 12; práctica de la industria.)"},
  {id:249, q:"En un SLC, el término 'T-tap' (derivación) en el cableado se refiere a:", opts:["Una trayectoria de retorno redundante de regreso a la panel","Únicamente un aislador de cortocircuito","Una ubicación de resistencia de fin de línea","Un ramal/derivación del recorrido principal del lazo"], re:"Un T-tap es una derivación del tronco del SLC; si se permiten los T-taps depende de la clase de trayectoria y del fabricante (las Clases A/X requieren una continuidad que limita las derivaciones no supervisadas). (Práctica de la industria.)"},
  {id:250, q:"En un sistema direccionable, la panel sabe que un dispositivo ha sido RETIRADO del SLC porque:", opts:["La dirección del dispositivo deja de responder al sondeo y se genera un problema","Los dispositivos retirados no tienen efecto","Se activa la alarma del edificio","La estación supervisora llama de regreso"], re:"La panel sondea continuamente cada dirección; una dirección ausente/que no responde produce un problema (p. ej., 'dispositivo faltante'). (NFPA 72 Cap. 10/12 supervisión; práctica de la industria.)"},
  {id:251, q:"Según NFPA 72 Cap. 12, una trayectoria Clase B es aquella que:", opts:["Incluye una trayectoria de retorno redundante a la unidad de control","Está reservada para trayectorias de red (Ethernet)","Continúa operando durante una sola abertura y un solo cortocircuito","Opera sin trayectoria redundante; los dispositivos más allá de una sola abertura se pierden"], re:"NFPA 72 Cap. 12: la Clase B no tiene trayectoria redundante; una sola abertura deshabilita los dispositivos aguas abajo de la falla (se anuncia un problema)."},
  {id:252, q:"Según NFPA 72 Cap. 12, una trayectoria Clase A:", opts:["No tiene supervisión","Requiere cable de fibra óptica","No puede detectar una falla a tierra","Incluye una trayectoria redundante y continúa operando durante una sola abertura"], re:"NFPA 72 Cap. 12: la Clase A incluye una trayectoria redundante (de retorno) de modo que la operación continúa durante una sola abertura; la falla aún se anuncia como problema."},
  {id:253, q:"Según NFPA 72 Cap. 12, una trayectoria Clase X debe continuar operando durante:", opts:["Solo una sola abertura","Ninguna falla en absoluto","Solo una sola falla a tierra","Tanto una sola abertura como un solo cortocircuito (con aislamiento de fallas)"], re:"NFPA 72 Cap. 12: la Clase X es una trayectoria redundante que continúa operando durante una sola abertura Y un solo cortocircuito, proporcionando aislamiento entre dispositivos."},
  {id:254, q:"Según NFPA 72 Cap. 12, una trayectoria Clase N se refiere a:", opts:["Un solo recorrido de cable no supervisado","Únicamente un enlace de radiofrecuencia bidireccional","Un IDC convencional con una resistencia EOL","Una trayectoria de red con redundancia verificada mediante comunicación de extremo a extremo"], re:"NFPA 72 Cap. 12: la Clase N es una trayectoria de red (p. ej., Ethernet); donde existen dos o más trayectorias, la capacidad operacional hacia cada dispositivo se verifica mediante comunicación de extremo a extremo y su pérdida se anuncia como problema."},
  {id:255, q:"En una trayectoria Clase N, una sola abertura, cortocircuito o falla a tierra en una trayectoria debe:", opts:["Deshabilitar toda la red","Disparar una alarma del edificio","Ser ignorada por completo","No afectar la operación de ninguna otra trayectoria (redundante)"], re:"NFPA 72 Cap. 12: para la Clase N, una sola falla en una trayectoria no debe afectar ninguna otra trayectoria, y la pérdida de la comunicación prevista se anuncia como problema."},
  {id:256, q:"¿Qué designación heredada de 'Estilo' (Style) corresponde al circuito de línea de señalización Clase A moderno?", opts:["Style 4","Style 0.5","Style Z","Style 6"], re:"Historia de NFPA 72: el antiguo SLC Style 6 (trayectoria redundante, sobrevive a una sola abertura) corresponde a la Clase A actual; Style 4 corresponde a Clase B; Style 7 corresponde a Clase X."},
  {id:257, q:"¿Qué designación heredada de 'Estilo' (Style) de SLC corresponde al circuito Clase B moderno?", opts:["Style 4","Style 6","Style 7","Style N"], re:"Historia de NFPA 72: el SLC Style 4 (sin trayectoria redundante) corresponde a Clase B; Style 6 a Clase A; Style 7 a Clase X."},
  {id:258, q:"¿Qué designación heredada de 'Estilo' (Style) de SLC corresponde al circuito Clase X moderno?", opts:["Style 4","Style 6","Style 7","Style B"], re:"Historia de NFPA 72: el SLC Style 7 (trayectoria redundante que también sobrevive a un cortocircuito, con aislamiento) corresponde a la Clase X."},
  {id:259, q:"La CAPACIDAD DE SUPERVIVENCIA de la trayectoria de NFPA 72 aborda la capacidad de una trayectoria de:", opts:["Resistir el ruido eléctrico","Reducir el costo de instalación","Transportar mayor voltaje","Continuar operando durante un periodo bajo el ataque del fuego"], re:"NFPA 72 Cap. 12: la capacidad de supervivencia de la trayectoria se refiere a si se mantiene la integridad del circuito durante la exposición al fuego, de modo que los mensajes aún lleguen a las áreas aún no notificadas."},
  {id:260, q:"El Nivel 0 (Level 0) de capacidad de supervivencia de la trayectoria de NFPA 72 significa que la trayectoria:", opts:["Requiere cable con clasificación de fuego de 2 horas","Requiere canalización metálica","Debe estar en un edificio totalmente con rociadores","No tiene requisito de capacidad de supervivencia definido"], re:"NFPA 72 Cap. 12: el Level 0 no impone ningún requisito de capacidad de supervivencia sobre la trayectoria."},
  {id:261, q:"El Nivel 1 (Level 1) de capacidad de supervivencia de la trayectoria de NFPA 72 generalmente se basa en:", opts:["Cable de integridad de circuito con clasificación de fuego de 2 horas","Un sistema de rociadores automáticos solo, sin canalización","Ninguna protección en absoluto","Conductores en canalización metálica/cable armado dentro de un edificio totalmente con rociadores"], re:"NFPA 72 Cap. 12: el Level 1 usa trayectorias en un edificio totalmente protegido por rociadores automáticos con los conductores en canalización metálica o cable con armadura metálica."},
  {id:262, q:"El Nivel 2 (Level 2) de capacidad de supervivencia de la trayectoria de NFPA 72 se logra mediante métodos como:", opts:["THHN ordinario en EMT, sin clasificación","Únicamente cable con clasificación para plénum","Operación a 12 VCC","Cable de integridad de circuito (CI) con clasificación de fuego de 2 horas, un sistema de cable con clasificación de fuego de 2 horas, o un recinto con clasificación de 2 horas"], re:"NFPA 72 Cap. 12: el Level 2 consiste en cable CI con clasificación de fuego de 2 horas, un sistema protector de circuito eléctrico listado de 2 horas, o un recinto/área protegida con clasificación de fuego de 2 horas."},
  {id:263, q:"El Nivel 3 (Level 3) de capacidad de supervivencia de la trayectoria de NFPA 72 se diferencia del Nivel 2 en que el Nivel 3 además requiere:", opts:["Ninguna clasificación de fuego en absoluto","Una segunda unidad de control","Cable de fibra óptica","Que el edificio esté totalmente protegido por un sistema de rociadores automáticos (añadido a los métodos del Level 2)"], re:"NFPA 72 Cap. 12: el Level 3 combina los métodos con clasificación de 2 horas del Level 2 con un edificio totalmente con rociadores."},
  {id:264, q:"Para un sistema de comunicaciones de emergencia que emplea evacuación parcial o reubicación, NFPA 72 exige una capacidad de supervivencia de la trayectoria de al menos:", opts:["Level 0","Level 1","Level 2 (o Level 3)","Sin requisito"], re:"NFPA 72 Cap. 12/24: los sistemas que usan reubicación o evacuación parcial deben tener una capacidad de supervivencia de la trayectoria de Level 2 o Level 3 de modo que los mensajes lleguen a los ocupantes aún no notificados."},
  {id:265, q:"Un matiz importante de los niveles de capacidad de supervivencia de NFPA 72 es que son:", opts:["Estrictamente jerárquicos, con los números más altos siempre superiores","Solo sobre la sonoridad de los aparatos de notificación","Idénticos a las clases de trayectoria A/B/X/N","Una lista de diferentes métodos de desempeño, no una simple clasificación de 'más alto es mejor'"], re:"NFPA 72 Cap. 12 anexo/intención: los niveles describen diferentes métodos/criterios de protección; no son una clasificación estricta donde un número más alto sea automáticamente superior en todos los aspectos."},
  {id:266, q:"Los requisitos de capacidad de supervivencia de la trayectoria generalmente aplican a los circuitos hasta que estos:", opts:["Salen del edificio","Reciben energía","Llegan al primer dispositivo","Entran a la zona de notificación a la que sirven"], re:"NFPA 72 Cap. 12/24: la capacidad de supervivencia se requiere para los circuitos que pasan por otras zonas; una vez que un circuito está dentro de la zona de notificación a la que sirve, puede aceptarse una capacidad de supervivencia menor."},
  {id:267, q:"¿Qué afirmación contrasta correctamente la CLASE de trayectoria con la CAPACIDAD DE SUPERVIVENCIA de la trayectoria?", opts:["La clase aborda la exposición al fuego; la capacidad de supervivencia aborda las fallas eléctricas","Ninguna se relaciona con la tolerancia a fallas","Son el mismo requisito","La clase aborda el desempeño ante fallas eléctricas; la capacidad de supervivencia aborda la protección física/contra incendios de la trayectoria"], re:"NFPA 72 Cap. 12: la CLASE de trayectoria (A/B/X/N) define el desempeño bajo fallas eléctricas; la CAPACIDAD DE SUPERVIVENCIA de la trayectoria (Level 0-3) define la resistencia física a la exposición al fuego: dos conceptos separados."},
  {id:268, q:"El propósito principal de una resistencia de fin de línea (EOLR) en un IDC o NAC convencional es:", opts:["Aumentar la sonoridad de los aparatos de notificación","Establecer la dirección del dispositivo","Proporcionar energía secundaria","Permitir que la panel supervise el cableado ante condiciones de abertura y cortocircuito"], re:"La EOLR establece una corriente de supervisión conocida de modo que la panel pueda detectar una abertura (pérdida de corriente) o un cortocircuito (corriente excesiva) en el circuito, generando un problema. (NFPA 72 Cap. 10/23; práctica de la industria.)"},
  {id:269, q:"En un IDC convencional supervisado, un circuito ABIERTO (cable roto) típicamente aparece ante la panel como:", opts:["Pérdida de corriente de supervisión → problema","Corriente excesiva → alarma","Normal","Voltaje aumentado en el dispositivo"], re:"Con la EOLR en su lugar, una abertura elimina la trayectoria de corriente de supervisión; la panel detecta la pérdida de corriente y anuncia un problema. (Práctica de la industria; NFPA 72 Cap. 10.)"},
  {id:270, q:"En un IDC convencional supervisado con dispositivos normalmente abiertos, un CORTOCIRCUITO entre los conductores típicamente produce:", opts:["Solo un problema","Una indicación de ALARMA (el cortocircuito imita a un dispositivo cerrado)","Nada","Una señal supervisora"], re:"Como los dispositivos iniciadores convencionales generan alarma al cortocircuitar/cerrar el lazo, un cortocircuito del cableado en un IDC generalmente se lee como una alarma. (Práctica de la industria; por esto importan la supervisión y las prácticas de cableado adecuadas.)"},
  {id:271, q:"¿Dónde debe ubicarse físicamente la resistencia de fin de línea en un circuito convencional supervisado?", opts:["Solo dentro de la panel de control","En las terminales de la panel","En el extremo eléctrico del circuito (después del último dispositivo)","En el punto medio del recorrido"], re:"La EOLR debe estar en el extremo más lejano/eléctrico del circuito de modo que todo el recorrido del cableado quede dentro del lazo supervisado; colocarla en la panel dejaría el cableado de campo sin supervisar. (Práctica de la industria; NFPA 72 Cap. 10.)"},
  {id:272, q:"NFPA 72 exige que una sola abertura o falla a tierra en un circuito se anuncie como problema dentro de un máximo de:", opts:["200 seconds","10 minutos","1 hora","24 horas"], re:"NFPA 72 Cap. 12/10: una sola abertura o una sola falla a tierra debe detectarse y anunciarse como problema dentro de 200 seconds."},
  {id:273, q:"En un circuito de aparatos de notificación (NAC), el dispositivo de fin de línea también permite a la panel verificar:", opts:["La dirección de cada estroboscópica","La integridad del cableado (abertura/cortocircuito) de modo que se detecte una ruptura antes de que se necesite una alarma","La temperatura de color de las estroboscópicas","El voltaje principal del edificio"], re:"El dispositivo de fin de línea del NAC supervisa la continuidad/polaridad del cableado de modo que una falla se anuncie como problema, garantizando que los aparatos operarán cuando se les requiera. (NFPA 72 Cap. 10; práctica de la industria.)"},
  {id:274, q:"¿Por qué los aparatos de NAC convencionales típicamente están polarizados (con diodos de bloqueo)?", opts:["Para hacerlos más fuertes","Para que el circuito pueda supervisarse en reposo con polaridad inversa y energizarse con polaridad normal en alarma","Para establecer su dirección","Para reducir su consumo de corriente a cero"], re:"Los aparatos polarizados permiten a la panel aplicar un pequeño voltaje de supervisión de polaridad inversa en reposo (aparatos apagados) y polaridad normal en alarma (aparatos encendidos), habilitando la supervisión. (Práctica de la industria; NFPA 72 Cap. 10.)"},
  {id:275, q:"La 'supervisión' del circuito en NFPA 72 significa fundamentalmente que el sistema:", opts:["Graba video de la panel","Monitorea automáticamente la integridad de los conductores/trayectorias y señaliza las fallas","Requiere un guardia que vigile la panel","Prueba los dispositivos solo anualmente"], re:"NFPA 72 Cap. 10/12: la supervisión/monitoreo de la integridad significa que el sistema detecta automáticamente las fallas (aberturas, tierras, etc.) en sus circuitos e indica un problema."},
  {id:276, q:"Una falla a tierra en el cableado de alarma contra incendios es una preocupación porque puede:", opts:["Mejorar la confiabilidad del circuito","Potencialmente afectar la operación correcta, por lo que debe anunciarse como problema","Aumentar la vida de la batería","Establecer las direcciones de los dispositivos automáticamente"], re:"NFPA 72 Cap. 10/12: una falla a tierra que pudiera afectar la operación requerida debe detectarse y anunciarse como problema dentro del tiempo requerido (200 s)."},
  {id:277, q:"En un sistema direccionable, la función que realiza una EOLR en los circuitos convencionales se logra en su lugar mediante:", opts:["Una batería más grande","La supervisión por sondeo/comunicación continua de cada dispositivo direccionable","La eliminación de toda la supervisión","Una bocina más fuerte"], re:"Los lazos direccionables supervisan mediante el sondeo de cada dirección; la pérdida de respuesta produce un problema, reemplazando el papel de la EOLR en los circuitos convencionales. (Práctica de la industria; NFPA 72 Cap. 10/12.)"},
  {id:278, q:"Reemplazar una resistencia de fin de línea requerida con un puente (cortocircuitándola) en un NAC convencional:", opts:["No tendría efecto","Anularía la supervisión y podría enmascarar una falla de abertura/cortocircuito: una violación del código","Haría los aparatos más brillantes","Añadiría una dirección al circuito"], re:"Retirar/puentear la EOLR anula la supervisión del cableado, violando el requisito de monitoreo de la integridad de NFPA 72 y arriesgando fallas no detectadas. (NFPA 72 Cap. 10; práctica de la industria.)"},
  {id:279, q:"El valor de una resistencia de fin de línea para un circuito dado está determinado por:", opts:["La preferencia del instalador","Las especificaciones del fabricante de la panel de control para ese circuito","La estación supervisora","La longitud del edificio"], re:"El valor de la EOLR debe coincidir con el diseño de circuito listado de la panel; usar el valor incorrecto puede impedir la discriminación correcta entre abertura/cortocircuito. (Especificación del fabricante; NFPA 72 Cap. 10.)"},
  {id:280, q:"La supervisión de la energía secundaria (de batería) se requiere para que la panel pueda detectar una:", opts:["Detector de humo sucio","Batería desconectada, baja o fallada e indicar un problema","Válvula de rociadores cerrada","Pérdida de sincronización de las estroboscópicas"], re:"NFPA 72 §10.6: el sistema debe monitorear la presencia/condición de la fuente de energía secundaria (batería), indicando un problema ante una batería ausente o baja."},
  {id:281, q:"Un 'cambio de clase' de cableado Clase B a Clase A mejora la supervisión al añadir:", opts:["Una EOLR más grande","Una trayectoria de retorno redundante de modo que una sola abertura aún permita la operación","Más aparatos de notificación","Una segunda estación supervisora"], re:"La Clase A enruta el circuito de regreso a la panel (trayectoria redundante); una sola abertura queda entonces puenteada, manteniendo la operación mientras aún se anuncia el problema. (NFPA 72 Cap. 12.)"},
  {id:282, q:"NFPA 72 generalmente exige que una condición de problema en el sistema sea:", opts:["Visible en la unidad de control y producir una notificación audible de problema","Registrada solo en la estación supervisora, nunca mostrada localmente","Indicada solo durante el horario laboral","Silenciada de forma permanente tras la primera ocurrencia"], re:"NFPA 72 Cap. 10: las condiciones de problema deben indicarse visiblemente en la unidad de control y acompañarse de una señal audible de problema (que vuelve a sonar para nuevos problemas)."},
  {id:283, q:"¿Qué describe mejor por qué los circuitos de alarma contra incendios están 'supervisados' en lugar de simplemente cableados?", opts:["Para reducir el costo del cable","Para que las fallas del cableado se detecten automáticamente y la disponibilidad del sistema se verifique continuamente","Para eliminar la necesidad de pruebas","Para hacer la instalación más rápida"], re:"La supervisión garantiza que las fallas latentes del cableado (aberturas/tierras/cortocircuitos) se encuentren y anuncien antes de que impidan que el sistema opere en una emergencia. (NFPA 72 Cap. 10/12.)"},
  {id:284, q:"En un IDC convencional, la corriente de supervisión que fluye a través de la EOLR en reposo normal es:", opts:["Cero amperios","Una pequeña corriente demasiado baja para activar la notificación pero suficiente para que la panel detecte la integridad","La misma que la corriente de alarma plena","Igual a los 120 VCA principales"], re:"En reposo fluye una pequeña corriente de supervisión a través de la EOLR; la panel la detecta para confirmar la continuidad, mientras es demasiado pequeña para operar los aparatos. (Práctica de la industria; NFPA 72 Cap. 10.)"},
  {id:285, q:"El Capítulo 26 de NFPA 72 cubre qué categoría de sistemas?", opts:["Alarmas domésticas de estación única y de estaciones múltiples","Sistemas de alarma de estación supervisora (central, propietaria, remota)","Espaciamiento de aparatos de notificación","Pruebas de sensibilidad de detectores"], re:"NFPA 72 Cap. 26 aborda los sistemas de alarma de estación supervisora: servicio de estación central, propietaria y de estación supervisora remota."},
  {id:286, q:"Un transmisor comunicador de alarma digital (DACT) en el predio protegido, al transmitir, debe:", opts:["Dejar la línea telefónica libre para llamadas salientes","Tomar la línea telefónica (toma de línea) y desconectar cualquier llamada en curso para enviar la señal","Esperar hasta el horario laboral","Usar solo cable de fibra óptica"], re:"NFPA 72 Cap. 26: un DACT debe tomar la línea (descolgarse), desconectando cualquier llamada existente, e impedir las llamadas salientes hasta que se envíe la señal, garantizando que la alarma llegue."},
  {id:287, q:"El tiempo máximo desde el inicio de una sola señal de alarma en el predio protegido hasta que se registra en la estación supervisora no debe exceder:", opts:["10 segundos","90 seconds","10 minutos","1 hora"], re:"NFPA 72 Cap. 26: el tiempo máximo transcurrido desde el inicio de una sola señal de alarma hasta su registro en la estación supervisora es de 90 seconds."},
  {id:288, q:"Una disposición tradicional de DACT que usa líneas telefónicas históricamente requería que el transmisor estuviera conectado a:", opts:["Solo una línea no supervisada","Dos medios de transmisión (p. ej., dos líneas telefónicas, o una línea más otra tecnología)","Cuatro líneas telefónicas","Ninguna trayectoria supervisada"], re:"NFPA 72 Cap. 26: los DACT heredados usaban dos líneas telefónicas; las ediciones posteriores permiten una línea más otra tecnología (celular/IP) de modo que una sola falla no bloquee el reporte."},
  {id:289, q:"La falla de la estación supervisora en recibir la señal de prueba programada de un DACT/comunicador se trata como una:", opts:["Señal de alarma","Señal de problema","Señal supervisora","Evento normal"], re:"NFPA 72 Cap. 26: la falla en recibir una señal de prueba/registro esperada indica una posible pérdida de comunicaciones y se maneja como una señal de problema."},
  {id:290, q:"Las tecnologías de comunicación basadas en desempeño reconocidas por NFPA 72 para la señalización de incendios fuera del predio incluyen:", opts:["Solo líneas telefónicas de cobre","Comunicadores celulares y de Protocolo de Internet (IP)","Señales de humo","Solo megafonía"], re:"La tecnología basada en desempeño de NFPA 72 Cap. 26 abarca los comunicadores IP y celulares, que pueden servir como tecnologías de trayectoria única cuando cumplen los requisitos de desempeño/supervisión."},
  {id:291, q:"En el 'servicio de estación central' de NFPA 72, las responsabilidades en sitio que forman parte del servicio incluyen instalación, prueba, mantenimiento y:", opts:["Fabricar la panel","Servicio de mensajero (de respuesta)","Redactar el código de construcción","Proporcionar la energía principal de la red eléctrica"], re:"NFPA 72 Cap. 26: el servicio de estación central incluye las funciones de la estación supervisora (monitoreo, retransmisión, registro) más las funciones del predio protegido de instalación, prueba, mantenimiento y servicio de mensajero."},
  {id:292, q:"Cuando una condición requiere que se despache un mensajero al predio protegido, el servicio de estación central de NFPA 72 exige la llegada dentro de:", opts:["15 minutos","30 minutos","2 horas","8 horas"], re:"NFPA 72 Cap. 26: donde se requiere un mensajero (p. ej., una condición no restaurada), el mensajero debe llegar al predio protegido dentro de 2 horas de la señal."},
  {id:293, q:"Una estación supervisora propietaria se diferencia de una estación central en que la estación propietaria es:", opts:["Operada por una empresa externa para muchos propietarios","Propiedad del dueño de la propiedad y operada por él, monitoreando propiedades bajo esa única titularidad","Ubicada solo dentro del cuerpo de bomberos","Nunca atendida"], re:"NFPA 72 Cap. 26: una estación supervisora propietaria es propiedad del dueño de la propiedad protegida y operada por él, y sirve a propiedades contiguas/relacionadas bajo esa titularidad, con personal capacitado en atención."},
  {id:294, q:"Un sistema de alarma de estación supervisora remota se caracteriza por:", opts:["Servir a múltiples propietarios no relacionados, a menudo con señales recibidas en una ubicación remota como un centro de bomberos/comunicaciones","Estar ubicado solo en el predio protegido","No requerir personal de monitoreo","Usar solo el reporte telefónico manual"], re:"NFPA 72 Cap. 26: el servicio de estación supervisora remota recibe señales en una ubicación remota del predio protegido (p. ej., un cuerpo de bomberos o instalación contratada) para propiedades bajo diversas titularidades."},
  {id:295, q:"El suministro de energía secundaria para los transmisores/equipos en el predio protegido necesarios para la señalización fuera del predio debe proporcionar un mínimo de:", opts:["2 horas","8 horas","24 horas","7 días"], re:"NFPA 72 Cap. 26: la energía secundaria para el equipo de transmisión en el predio protegido debe ser de un mínimo de 24 horas."},
  {id:296, q:"Un DACR (receptor comunicador de alarma digital) se ubica:", opts:["En el predio protegido","En la estación supervisora, donde recibe señales de los DACT","Dentro de cada detector de humo","En el circuito de aparatos de notificación"], re:"NFPA 72 Cap. 26: el DACR es el equipo receptor en la estación supervisora que acepta y reconoce las señales transmitidas por los DACT en los predios protegidos."},
  {id:297, q:"Para un DACT, el tiempo desde descolgarse hasta colgarse en un intento de transmisión no debe exceder:", opts:["5 segundos","90 seconds","5 minutos","30 minutos"], re:"NFPA 72 Cap. 26: un intento de transmisión de un DACT (de descolgarse a colgarse) no debe exceder 90 seconds por intento."},
  {id:298, q:"El principal beneficio para la seguridad humana de la señalización fuera del predio (de estación supervisora) es que:", opts:["Silencia las bocinas del edificio","Se notifica al personal calificado y el servicio de bomberos puede ser despachado incluso si no hay nadie en el sitio","Elimina la necesidad de una unidad de control","Reemplaza los sistemas de rociadores"], re:"Intención de NFPA 72 Cap. 26: el servicio de estación supervisora garantiza que las señales de alarma, supervisoras y de problema lleguen al personal en atención para la respuesta/despacho sin importar la ocupación del edificio."},
  {id:299, q:"¿Qué señales se transmiten típicamente fuera del predio a la estación supervisora?", opts:["Solo señales de alarma de incendio","Señales de alarma, supervisoras y de problema","Solo señales de problema","Solo el consumo de energía del edificio"], re:"NFPA 72 Cap. 26: la conexión fuera del predio transmite señales de alarma, supervisoras y de problema de modo que cada condición pueda atenderse apropiadamente."},
  {id:300, q:"Cuando se usa una sola tecnología de comunicación (p. ej., una trayectoria IP o celular) para la señalización fuera del predio, NFPA 72 exige que una falla de esa trayectoria sea:", opts:["Nunca reportada","Anunciada/registrada en la estación supervisora dentro del intervalo de supervisión requerido por el código","Reportada solo en la siguiente prueba anual","Permitida pasar sin detectarse durante una semana"], re:"NFPA 72 Cap. 26: las trayectorias de tecnología única deben supervisarse de modo que una falla de comunicaciones se anuncie en la estación supervisora dentro del intervalo prescrito (p. ej., 60 minutos en ediciones recientes). (El intervalo exacto depende de la edición.)"},
  {id:301, q:"Según NFPA 72, ¿cuál de las siguientes es, con mayor frecuencia, la fuente de energía primaria de un sistema de alarma contra incendios?", opts:["El circuito ramal de la red comercial de alumbrado y fuerza","El banco de baterías de almacenamiento de reserva","Un generador de arranque automático accionado por motor","Un sistema de alimentación ininterrumpida (UPS) usado por sí solo"], re:"NFPA 72 Cap.10 identifica la fuente primaria (principal) como el servicio de alumbrado y fuerza, normalmente un circuito ramal dedicado de la red comercial. (NFPA 72-2022, 10.6.5)"},
  {id:302, q:"¿Cuál es el período MÍNIMO de reserva (en reposo) que la fuente de energía secundaria de un sistema de alarma contra incendios de local protegido debe poder sostener antes de aplicar cualquier carga de alarma?", opts:["24 h","12 h","48 h","60 h"], re:"NFPA 72 exige que la fuente secundaria mantenga la carga en reposo durante al menos 24 h. (NFPA 72-2022, 10.6.7.2.1)"},
  {id:303, q:"Tras el período de reserva requerido, la energía secundaria de un sistema de alarma contra incendios sin voz debe operar todos los aparatos de notificación de evacuación durante al menos cuánto tiempo?", opts:["10 min","5 min","15 min","30 min"], re:"NFPA 72 exige 5 min de operación plena de alarma tras 24 h de reserva para un sistema estándar (sin voz). (NFPA 72-2022, 10.6.7.2)"},
  {id:304, q:"Para un sistema de comunicación de emergencia por voz/alarma en el interior del edificio (EVACS), la duración de la alarma con energía secundaria tras la reserva aumenta de 5 min a qué valor?", opts:["15 min","10 min","20 min","60 min"], re:"Cuando el sistema incluye comunicaciones por voz/alarma dentro del edificio, el tiempo de operación de alarma tras la reserva es de 15 min. (NFPA 72-2022, 10.6.7.2.2)"},
  {id:305, q:"NFPA 72 permite que la fuente de energía secundaria de un sistema de local protegido sea cuál de las siguientes?", opts:["Solo una batería de almacenamiento en todos los casos","Solo un generador en todos los casos","Un banco de capacitores dimensionado para 24 h","Una batería de almacenamiento, O un generador de arranque automático accionado por motor"], re:"Las fuentes secundarias aceptables son una batería de almacenamiento o un generador de arranque automático accionado por motor. (NFPA 72-2022, 10.6.7)"},
  {id:306, q:"Cuando se usa un generador accionado por motor como fuente de energía secundaria, NFPA 72 todavía exige baterías de almacenamiento dimensionadas para al menos cuántas horas, de modo que el sistema funcione si el generador no arranca?", opts:["1 h","4 h","2 h","24 h"], re:"Un generador usado como energía secundaria debe respaldarse con baterías que provean al menos 4 h de operación en caso de que no arranque. (NFPA 72-2022, 10.6.7.2)"},
  {id:307, q:"La pérdida de la fuente de energía primaria (CA) de una unidad de control de alarma contra incendios debe indicarse como qué tipo de señal en la unidad de control?", opts:["Una señal de problema","Una señal de alarma","Una señal de prealarma","No se requiere indicación"], re:"La pérdida de energía primaria es una condición de falla; NFPA 72 exige que se anuncie como señal de problema. (NFPA 72-2022, 10.6 / 10.15)"},
  {id:308, q:"El circuito ramal dedicado que alimenta la energía primaria de una unidad de control de alarma contra incendios debe tener identificado su medio de desconexión. La marca normalmente dice:", opts:["\"NO TOCAR\" en amarillo","\"CONTROL DEL CIRCUITO DE ALARMA CONTRA INCENDIOS\" en rojo","\"ALUMBRADO GENERAL\" en negro","No se requiere marca"], re:"NFPA 72 / NEC 760.41 exigen que la desconexión del circuito ramal se identifique en rojo como control del circuito de alarma contra incendios, con medio de bloqueo/etiqueta. (NFPA 72-2022, 10.6.6; NEC 760.41)"},
  {id:309, q:"Un UPS o sistema de energía eléctrica almacenada usado como fuente de energía secundaria de un sistema de alarma contra incendios debe construirse y mantenerse de acuerdo con qué norma?", opts:["NFPA 13","NFPA 111 (con generadores de motor según NFPA 110)","NFPA 25","Solo NFPA 1221"], re:"NFPA 72 hace referencia a los sistemas de energía almacenada/UPS según NFPA 111 y a los generadores de motor según NFPA 110. (NFPA 72-2022, 10.6.9)"},
  {id:310, q:"La unidad de control de alarma contra incendios debe poder recargar por completo una batería secundaria totalmente descargada en qué tiempo máximo?", opts:["24 h","72 h","96 h","48 h"], re:"NFPA 72 exige que la batería pueda recargarse por completo desde la unidad de control en un plazo de 48 h tras la descarga total. (NFPA 72-2022, 10.6.10.3.2)"},
  {id:311, q:"¿Qué documento rige los métodos de cableado y las clasificaciones de circuito (de potencia limitada vs. no limitada) para los conductores de un sistema de alarma contra incendios?", opts:["NEC (NFPA 70) Artículo 760","NFPA 13","NFPA 101 Capítulo 7","ASME A17.1"], re:"El Artículo 760 del NEC cubre la instalación del cableado de circuitos de alarma contra incendios, incluyendo las clasificaciones PLFA y NPLFA. (NEC-2020, Art. 760)"},
  {id:312, q:"Un circuito de alarma contra incendios de potencia limitada (PLFA) tiene su tensión y potencia limitadas por qué dispositivo?", opts:["Un disyuntor ramal común de 20 A","Una fuente de alimentación listada que cumple con NEC 760.121","Una bobina de relé","El propio aparato de notificación"], re:"Los circuitos PLFA están limitados por una fuente de alimentación listada según NEC 760.121; la salida suele ser de 24 VCC o menos. (NEC-2020, 760.121)"},
  {id:313, q:"¿Cuál es la tensión de salida nominal típica de una fuente de alimentación de un circuito de alarma contra incendios de potencia limitada usada en circuitos de iniciación y notificación?", opts:["120 VCA","240 VCA","24 VCC o menos","600 VCC"], re:"Las fuentes listadas PLFA para la mayoría de los circuitos de alarma contra incendios operan a 24 VCC nominales o menos. (NEC-2020, 760.121; NFPA 72 Cap.10)"},
  {id:314, q:"NEC 760.136 exige cuál de las siguientes entre los conductores de alarma contra incendios de potencia limitada y los conductores de alumbrado, fuerza y Clase 1?", opts:["Se requiere compartir el mismo conducto","Color de aislamiento idéntico","Separación física (no en el mismo conducto/envolvente salvo lo permitido)","Solo un tornillo de puesta a tierra común"], re:"NEC 760.136 exige que los conductores PLFA se separen de los conductores de alumbrado, fuerza, Clase 1 y NPLFA. (NEC-2020, 760.136)"},
  {id:315, q:"Las baterías selladas de plomo-ácido (SLA) son el almacenamiento de energía secundaria más común para paneles de alarma contra incendios principalmente porque son:", opts:["La química de batería más liviana disponible","Capaces de ciclos de recarga ilimitados","Libres de mantenimiento, recargables y disponibles en tamaños de gabinete estandarizados","Completamente inmunes a los efectos de la temperatura"], re:"Las baterías SLA son el estándar de la industria para FACU: selladas, libres de mantenimiento, recargables, en tamaños estándar como 12 V 7 Ah / 12 V 12 Ah. (NFPA 72 Cap.10; práctica de la industria)"},
  {id:316, q:"Una batería estándar sellada de plomo-ácido de 12 voltios está constituida internamente por cuántas celdas de 2 voltios en serie?", opts:["3 celdas","12 celdas","24 celdas","6 celdas"], re:"Cada celda de plomo-ácido es nominalmente de 2 V, por lo que seis celdas en serie producen una batería de 12 V. (Fundamentos de baterías)"},
  {id:317, q:"NFPA 72 exige que la transferencia de la energía primaria a la secundaria sea:", opts:["Manual, realizada por un operador en el sitio","Retardada por un temporizador fijo de 5 min","Realizada solo después de 24 h","Automática, sin pérdida de señales ni de función del sistema"], re:"El cambio a energía secundaria debe ser automático y no afectar la operación, de modo que la protección sea ininterrumpida. (NFPA 72-2022, 10.6.8)"},
  {id:318, q:"En un cálculo de batería de reserva de alarma contra incendios, la corriente de reserva (en reposo) se multiplica por cuántas horas?", opts:["5 h","12 h","48 h","24 h"], re:"Energía de reserva = corriente de reserva x 24 h, el período mínimo en reposo. (NFPA 72-2022, 10.6.7.2.1)"},
  {id:319, q:"Para un sistema estándar (sin voz), la corriente de alarma en un cálculo de batería se multiplica por qué tiempo, expresado en horas?", opts:["15 min = 0.25 h","30 min = 0.5 h","60 min = 1.0 h","5 min = 0.083 h"], re:"Cinco minutos equivalen a 5/60 = 0.0833 h para la parte de alarma de un sistema estándar. (NFPA 72-2022, 10.6.7.2)"},
  {id:320, q:"La edición 2022 de NFPA 72 exige qué multiplicador de reducción/seguridad debe aplicarse a la capacidad de batería calculada en amperios-hora para tener en cuenta el envejecimiento y la temperatura?", opts:["1.10","1.25","1.20","2.00"], re:"La edición 2022 elevó el factor de corrección a 1.25 (un factor de seguridad del 25%). (NFPA 72-2022, 10.6.7.2.14)"},
  {id:321, q:"Un sistema consume 0.5 A en reposo y 2.0 A en alarma. Usando 24 h de reserva, 5 min de alarma y un factor de 1.25, la capacidad mínima de batería es la más cercana a:", opts:["15.2 Ah","12.2 Ah","13.5 Ah","18.0 Ah"], re:"(0.5x24)+(2x0.0833)=12.0+0.167=12.167 Ah; x1.25=15.21 Ah. (NFPA 72-2022, 10.6.7.2)"},
  {id:322, q:"Un sistema consume 0.25 A en reposo y 1.5 A en alarma. Con 24 h de reserva, 5 min de alarma y el factor de 1.25, la capacidad mínima es la más cercana a:", opts:["6.1 Ah","9.0 Ah","7.7 Ah","11.0 Ah"], re:"(0.25x24)+(1.5x0.0833)=6.0+0.125=6.125 Ah; x1.25=7.66 Ah. (NFPA 72-2022, 10.6.7.2)"},
  {id:323, q:"Un sistema por voz (EVACS) consume 0.3 A en reposo y 3.0 A en alarma. Usando 24 h de reserva, 15 min de alarma y el factor de 1.25, la capacidad mínima es la más cercana a:", opts:["9.9 Ah","7.2 Ah","8.5 Ah","12.0 Ah"], re:"(0.3x24)+(3x0.25)=7.2+0.75=7.95 Ah; x1.25=9.94 Ah. Por voz se usan 15 min = 0.25 h. (NFPA 72-2022, 10.6.7.2.2)"},
  {id:324, q:"¿Cuál es la energía de reserva (amperios-hora) aportada por una carga en reposo de 0.4 A durante el período de reserva requerido de 24 horas?", opts:["4.8 Ah","12.0 Ah","9.6 Ah","19.2 Ah"], re:"0.4 A x 24 h = 9.6 Ah de energía de reserva antes de sumar la carga de alarma y el factor de 1.25. (NFPA 72-2022, 10.6.7.2.1)"},
  {id:325, q:"Un sistema tiene 0.4 A en reposo y 2.5 A en alarma (24 h / 5 min / 1.25). La capacidad mínima de batería es la más cercana a:", opts:["12.3 Ah","10.0 Ah","11.0 Ah","14.0 Ah"], re:"(0.4x24)+(2.5x0.0833)=9.6+0.208=9.808 Ah; x1.25=12.26 Ah. (NFPA 72-2022, 10.6.7.2)"},
  {id:326, q:"¿Cómo se determina la corriente de reserva TOTAL de un sistema antes del cálculo?", opts:["Usar solo la corriente de reserva del panel","Usar la corriente de reserva del dispositivo individual más grande","Usar la corriente de alarma dividida entre 2","Multiplicar la corriente de reserva de cada dispositivo por su cantidad y sumar todos los dispositivos más el panel"], re:"Corriente de reserva total = suma de (corriente de reserva de cada dispositivo x cantidad), incluida la unidad de control. (NFPA 72 Cap.10; hoja de cálculo estándar)"},
  {id:327, q:"En la columna de alarma de una hoja de cálculo de batería, los aparatos de notificación se contabilizan a su:", opts:["Corriente de reserva","Mitad de la corriente de alarma","Cero, porque el panel los alimenta","Corriente de alarma (activa) completa"], re:"Los aparatos de notificación consumen su corriente de alarma nominal cuando están activos; ese valor llena la columna de alarma. (Hoja de cálculo estándar de NFPA 72)"},
  {id:328, q:"Tras calcular los amperios-hora requeridos, el instalador selecciona una batería cuya capacidad nominal sea:", opts:["Exactamente igual al valor calculado","Igual o mayor que el valor calculado","Al menos 50% por debajo del valor calculado","Cualquier valor, ya que los paneles se autoajustan"], re:"La capacidad nominal en Ah de la batería instalada debe igualar o superar el mínimo calculado; subdimensionarla es una violación del código. (NFPA 72 Cap.10)"},
  {id:329, q:"¿Por qué NFPA 72 aplica un factor de seguridad/reducción a la capacidad de batería calculada?", opts:["Para tener en cuenta el envejecimiento de la batería y la pérdida de capacidad relacionada con la temperatura a lo largo de su vida útil","Para pagar la mano de obra de instalación","Para reducir el tiempo de reserva por debajo de 24 h","Porque los paneles suelen sobrecargar las baterías"], re:"El factor de 1.25 compensa la pérdida de capacidad por envejecimiento y temperatura, de modo que la batería siga cumpliendo su servicio al final de su vida útil. (NFPA 72-2022, 10.6.7.2.14)"},
  {id:330, q:"Si un sistema requiere 15.2 Ah, ¿cuál capacidad nominal de una sola batería SLA estándar es la opción aceptable más pequeña?", opts:["12 V 7 Ah","12 V 18 Ah","12 V 12 Ah","12 V 5 Ah"], re:"18 Ah es el tamaño estándar listado más pequeño que cumple o supera 15.2 Ah. (Principio de dimensionamiento de NFPA 72 Cap.10)"},
  {id:331, q:"Dos baterías de 12 V (cada una de 12 V 7 Ah) conectadas en SERIE para alimentar un panel de 24 V proporcionan qué tensión y capacidad del sistema?", opts:["12 V, 14 Ah","24 V, 14 Ah","24 V, 7 Ah","12 V, 7 Ah"], re:"La conexión en serie suma la tensión (12+12=24 V) pero la capacidad permanece igual (7 Ah). (Fundamentos de baterías)"},
  {id:332, q:"Dos baterías de 12 V 7 Ah conectadas en PARALELO proporcionan:", opts:["12 V, 14 Ah","24 V, 7 Ah","24 V, 14 Ah","6 V, 7 Ah"], re:"La conexión en paralelo mantiene la tensión (12 V) pero suma la capacidad (7+7=14 Ah). (Fundamentos de baterías)"},
  {id:333, q:"Agregar un banco de retenciones magnéticas de puerta a un sistema aumenta de manera más directa cuál valor en el cálculo de batería?", opts:["Solo la corriente de alarma","La corriente de reserva (y por ende los Ah de reserva)","Ninguna corriente","Solo el tiempo de recarga"], re:"Las retenciones de puerta se energizan continuamente para mantener las puertas abiertas, por lo que se suman a la corriente en reposo/reserva y aumentan el tamaño de la batería. (NFPA 72 Cap.10; práctica de la industria)"},
  {id:334, q:"Cuando las cargas hacen que la capacidad requerida supere el límite de batería recargable de un solo panel, la solución correcta es:", opts:["Sobredimensionar la batería interna más allá del límite de carga del panel","Reducir el tiempo de reserva a 12 h","Agregar una fuente de alimentación remota listada / amplificador de NAC con sus propias baterías monitoreadas","Quitar aparatos de notificación del diseño"], re:"Las cargas grandes se respaldan con fuentes de alimentación auxiliares/amplificadoras listadas (amplificadores de NAC) con sus propias baterías secundarias monitoreadas. (NFPA 72 Cap.10; NEC 760)"},
  {id:335, q:"En NFPA 72, las funciones del edificio que el sistema de alarma contra incendios activa (parada de ventiladores, retorno de ascensor, liberación de puertas, control de humo) se denominan colectivamente:", opts:["Derivaciones de supervisión","Salidas de problema","Cargas en reposo","Funciones de control de emergencia"], re:"El Capítulo 21 rige las funciones de control de emergencia (ECF) y sus interfaces. (NFPA 72-2022, Cap. 21)"},
  {id:336, q:"NFPA 72 Capítulo 21 permite que la interconexión entre un dispositivo de interfaz de función de control de emergencia y el equipo controlado use qué método?", opts:["Contactos eléctricos listados para la carga conectada, o un circuito de línea de señalización dedicado/compartido","Solo tubería neumática","Solo fibra óptica","Solo radio inalámbrica"], re:"El Capítulo 21 permite contactos eléctricos listados para la carga conectada o comunicaciones de datos por un SLC. (NFPA 72-2022, 21.2)"},
  {id:337, q:"Un relé o dispositivo de interfaz usado para realizar una función de control de emergencia debe ubicarse:", opts:["En cualquier lugar conveniente; el monitoreo es opcional","Al menos a 100 ft del componente controlado","A menos de 3 ft (1 m) del componente controlado, O el cableado debe monitorearse por integridad","Solo en exteriores"], re:"El Capítulo 21 exige que el relé de interfaz esté a menos de 3 ft del equipo controlado, o que los conductores de conexión se monitoreen por integridad. (NFPA 72-2022, 21.2.4)"},
  {id:338, q:"Un contacto de relé 'Form C' provisto en una unidad de control de alarma contra incendios le da al instalador qué disposición de contacto?", opts:["Solo normalmente abierto","Solo normalmente cerrado","Un común con un contacto normalmente abierto y otro normalmente cerrado (SPDT)","Un contacto de enclavamiento sin común"], re:"Un contacto Form C es unipolar de doble tiro: un terminal común con contactos NA y NC para una interfaz flexible. (Convenciones de relé/contacto)"},
  {id:339, q:"Para controlar una carga que consume más corriente o mayor tensión de la que puede conmutar el relé integrado de un panel, el técnico debe usar:", opts:["Un relé de control (intermediario) listado y dimensionado para la carga, accionado por el panel","Solo un fusible más grande","Un tendido de cable más largo","El circuito de notificación directamente"], re:"Un relé intermediario/de control listado y dimensionado para la carga la aísla y conmuta mientras el panel acciona la bobina del relé. (NFPA 72 Cap.21; NEC 760)"},
  {id:340, q:"Cuando el sistema de alarma contra incendios acciona el sistema de HVAC con fines de control de humo, NFPA 72 exige que las zonas de iniciación estén:", opts:["Ignoradas durante la alarma","Coordinadas con las zonas de control de humo que accionan","Cableadas al circuito de notificación","Deshabilitadas para evitar alarmas molestas"], re:"Cuando la FACU acciona el HVAC para control de humo, las zonas de iniciación de alarma deben coordinarse con las zonas de control de humo que accionan. (NFPA 72-2022, 21.7)"},
  {id:341, q:"Un relé de control que libera una retención magnética de puerta al activarse la alarma debe, ante la pérdida de energía o una falla del sistema, hacer que la puerta:", opts:["Permanezca abierta","Se bloquee eléctricamente","Suene solo una bocina local","Se libere y se cierre (a prueba de fallos)"], re:"Los dispositivos de retención son a prueba de fallos: la pérdida de energía libera el imán para que la puerta se cierre, manteniendo la barrera contra fuego/humo. (NFPA 72 Cap.21; NFPA 80)"},
  {id:342, q:"Los conductores que llevan una función de control de emergencia pero que NO son monitoreados por integridad por el sistema de alarma contra incendios deben, como mínimo:", opts:["Quedar sin monitoreo sin límite de longitud","Usar aislamiento de 600 V sin importar la tensión","Instalarse en un edificio separado","Tener el relé de interfaz ubicado a menos de 3 ft (1 m) del aparato controlado"], re:"El cableado de ECF sin monitoreo se limita manteniendo el relé a menos de 3 ft del equipo controlado, según el Capítulo 21. (NFPA 72-2022, 21.2.4)"},
  {id:343, q:"Un 'módulo de relé (control) direccionable' en un circuito de línea de señalización se usa principalmente para:", opts:["Aumentar el volumen del aparato de notificación","Reemplazar la batería del sistema","Medir fallas a tierra","Proporcionar un contacto seco/de relé controlable en un punto remoto del SLC para funciones de control"], re:"Los módulos de relé direccionables dan al panel un contacto ubicado de forma remota e individualmente direccionable para accionar funciones de control por el SLC. (NFPA 72 Cap.10/23 funciones de dispositivo)"},
  {id:344, q:"¿Cuál de las siguientes es un ejemplo de función de control de seguridad contra incendios en contraposición a una función de notificación?", opts:["Hacer sonar una bocina/estrobo en un corredor","Destellar un estrobo en un baño","Retornar un ascensor al nivel designado","Anunciar un mensaje de evacuación por voz"], re:"El retorno de ascensor es una función de control de emergencia (seguridad contra incendios) bajo el Capítulo 21; las bocinas, estrobos y mensajes por voz son notificación. (NFPA 72-2022, Cap.21 vs Cap.18)"},
  {id:345, q:"Para una función de control de emergencia, NFPA 72 exige que una falla entre la FACU y un dispositivo de interfaz monitoreado resulte en:", opts:["Ninguna indicación","Una alarma general inmediata","Una señal de problema en la unidad de control","Activación automática de la función"], re:"Una falla en un circuito de interfaz de ECF monitoreado debe producir una señal de problema en la FACU. (NFPA 72-2022, 21.2.5)"},
  {id:346, q:"Un módulo de relé usado para apagar ventiladores al activarse la alarma se cablea de modo que el ventilador se detenga cuando el relé:", opts:["Es activado por la FACU al activarse la alarma, abriendo/cambiando el circuito de control del ventilador","Tiene la bobina simplemente desenergizada en todo momento","Se retira del panel","Alcanza 24 h de funcionamiento"], re:"Al activarse la alarma, la FACU activa el relé de interfaz, que abre/cambia el circuito de control del ventilador para ordenar la parada. (NFPA 72-2022, 21.7; NFPA 90A)"},
  {id:347, q:"La prioridad de señales en una unidad de control de alarma contra incendios coloca qué tipo de señal en el nivel más alto?", opts:["Señales de problema","Señales de supervisión","Señales en reposo","Señales de alarma"], re:"NFPA 72 establece las señales de alarma como de máxima prioridad, por encima de las de supervisión y luego las de problema. (NFPA 72-2022, prioridad de señales)"},
  {id:348, q:"Una función de control de 'liberación' (p. ej., para descargar un sistema de supresión por agente limpio) requiere que el circuito de liberación sea:", opts:["Sin supervisión ni monitoreo","Supervisado/monitoreado, usando equipo listado para servicio de liberación","Cableado al circuito de retención de puerta","Alimentado solo por las retenciones de puerta"], re:"El servicio de liberación usa paneles/circuitos de liberación listados que son supervisados; las fallas de integridad se anuncian. (NFPA 72-2022 Cap.23; interfaz NFPA 12/2001)"},
  {id:349, q:"Cuando un solo módulo direccionable provee TANTO el monitoreo de un dispositivo COMO el control de una función, el cableado debe asegurar que:", opts:["El control y el monitoreo compartan un cable sin supervisión","El módulo ignore las fallas a tierra","La pérdida de integridad se detecte y se reporte como problema","La función se active ante cualquier problema"], re:"Independientemente de la función combinada, la integridad de la interfaz debe supervisarse y las fallas reportarse como problema. (NFPA 72-2022, 21.2.5)"},
  {id:350, q:"Una función de control que debe seguir operando durante un incendio (p. ej., ventiladores de presurización de escaleras para control de humo) suele alimentarse y cablearse como:", opts:["Un circuito ramal estándar no resistente al fuego","Un circuito de retención de puerta","Un circuito de solo problema","Un circuito sobreviviente / protegido según los requisitos de control de humo y los Capítulos 21/24"], re:"El equipo de control de humo que debe funcionar durante un incendio requiere integridad de circuito sobreviviente y energía de reserva según las disposiciones aplicables. (NFPA 72-2022, 21.7; NFPA 92)"},
  {id:351, q:"La Operación de Retorno de Emergencia Fase I de un ascensor, iniciada por el sistema de alarma contra incendios, hace que la cabina:", opts:["Regrese automáticamente a un nivel de retorno designado y se retire del servicio normal","Se detenga de inmediato entre pisos","Acelere hacia el piso superior","Abra todas las puertas del pasadizo"], re:"El retorno Fase I devuelve la cabina al rellano designado y la retira del servicio normal, según la operación de emergencia de bomberos de ASME A17.1. (NFPA 72-2022, 21.3; ASME A17.1)"},
  {id:352, q:"¿Qué norma define el comportamiento real del ascensor (Operación de Emergencia de Bomberos, Fase I y Fase II) con la que el sistema de alarma contra incendios se interconecta?", opts:["NFPA 13","ASME A17.1 / CSA B44","NFPA 25","NEC Artículo 700"], re:"ASME A17.1/CSA B44 define la FEO Fase I/II; NFPA 72 Cap.21 define cómo se interconecta la alarma contra incendios. (NFPA 72-2022, 21.3; ASME A17.1 2.27)"},
  {id:353, q:"La activación de qué dispositivo normalmente inicia el retorno Fase I del ascensor al nivel DESIGNADO (primario)?", opts:["Un detector de humo en un vestíbulo de ascensor (distinto del nivel designado), sala de máquinas o pasadizo","Una estación manual de tiro en un corredor","Un interruptor de flujo de agua en el tercer piso","Un detector de ducto en el HVAC del vestíbulo"], re:"Los detectores de humo de vestíbulo, sala de máquinas y pasadizo (excepto en el nivel designado) retornan la cabina al nivel designado. (NFPA 72-2022, 21.3.5; ASME A17.1)"},
  {id:354, q:"Cuando se activa el detector de humo en el nivel de retorno DESIGNADO, el ascensor se retorna a:", opts:["El mismo nivel designado","El piso superior","Solo el sótano, en todos los casos","Un nivel de retorno alterno (secundario)"], re:"Si se activa el detector del nivel designado, el retorno se envía al nivel alterno para que la cabina no abra hacia el vestíbulo designado con humo. (NFPA 72-2022, 21.3.6; ASME A17.1)"},
  {id:355, q:"Los detectores de humo usados únicamente para el retorno del ascensor deben iniciar el retorno y también:", opts:["Estar ocultos a la vista","Alimentarse solo por el controlador del ascensor","Hacer sonar solo un zumbador local","Hacer que el sistema de alarma contra incendios del edificio indique alarma (se conectan a la FACU)"], re:"Los detectores de retorno se conectan a la FACU del edificio y son monitoreados por ella, e inician una alarma/retorno, no solo una función local. (NFPA 72-2022, 21.3 / 21.2)"},
  {id:356, q:"NFPA 72 exige que se provean salidas SEPARADAS de la unidad de control de alarma contra incendios para implementar qué funciones del ascensor?", opts:["Solo la bocina de alarma","El retorno Fase I Y cualquier corte de energía requerido (disparo por cortocircuito/shunt trip), como salidas dedicadas distintas","Solo el sistema de música del ascensor","Solo la iluminación de la cabina del ascensor"], re:"El Capítulo 21 exige salidas separadas y dedicadas para el retorno Fase I y para el corte de energía (disparo por cortocircuito/shunt trip). (NFPA 72-2022, 21.3 / 21.4)"},
  {id:357, q:"El 'disparo por cortocircuito' (shunt trip) de la energía del ascensor (desconexión automática de la energía del ascensor) se provee donde hay rociadores instalados en la sala de máquinas o el pasadizo, de modo que la energía se retire:", opts:["Mucho después de la descarga de agua","Antes de la descarga de agua de los rociadores sobre el equipo energizado del ascensor","Solo durante las pruebas de rutina","Nunca, porque el disparo por cortocircuito está prohibido"], re:"El disparo por cortocircuito (shunt trip) retira la energía del ascensor antes de la descarga de los rociadores para evitar movimientos descontrolados y riesgos de choque. (NFPA 72-2022, 21.4; ASME A17.1)"},
  {id:358, q:"Para activar el disparo por cortocircuito (shunt trip) ANTES de que opere el rociador, se instala un detector de calor cerca de cada rociador afectado. NFPA 72 exige que ese detector sea:", opts:["De temperatura más alta y más lento que el rociador","A menos de 2 ft (0.6 m) de cada rociador, respondiendo antes que el rociador","Ubicado a 25 ft del rociador","Solo un detector de humo"], re:"Un detector de calor a menos de 2 ft de cada rociador, con temperatura/respuesta apropiada, acciona el disparo por cortocircuito (shunt trip) antes de la operación del rociador. (NFPA 72-2022, 21.4.2; ASME A17.1)"},
  {id:359, q:"¿Por qué el retorno del ascensor debe usar detección de humo (no de calor) en vestíbulos, salas de máquinas y pasadizos para la función de retorno?", opts:["Para retornar las cabinas temprano, antes de que el humo ponga en peligro a los ocupantes que usan o salen del ascensor","Porque los detectores de calor son más baratos","Porque los detectores de humo nunca dan falsas alarmas","Porque el código prohíbe el calor en cualquier lugar cerca de los ascensores"], re:"La detección de humo provee un retorno temprano para que los ocupantes no queden atrapados por el humo; el calor se reserva para la función de disparo por cortocircuito (shunt trip). (NFPA 72-2022, 21.3 vs 21.4)"},
  {id:360, q:"Una señal visual dedicada (el indicador iluminado del 'casco de bombero') dentro de la cabina del ascensor indica a los ocupantes que:", opts:["La operación de emergencia de bomberos (retorno) está en efecto","La cabina necesita mantenimiento","La batería está baja","Las puertas están bloqueadas mecánicamente"], re:"El casco iluminado/señal visual indica que el retorno Fase I/FEO está activo según ASME A17.1; la alarma contra incendios provee la señal de iniciación. (ASME A17.1; NFPA 72-2022, 21.3)"},
  {id:361, q:"¿Cuál dispositivo de iniciación NO debe usarse para iniciar el retorno Fase I del ascensor?", opts:["Un detector de humo de vestíbulo de ascensor","Una caja manual de alarma contra incendios (estación de tiro)","Un detector de humo de sala de máquinas de ascensor","Un detector de humo de pasadizo de ascensor"], re:"El retorno lo inician los detectores de humo en vestíbulos, salas de máquinas y pasadizos, no las estaciones manuales de tiro. (NFPA 72-2022, 21.3.5)"},
  {id:362, q:"En un edificio con varios ascensores en un pasadizo común o agrupados, la activación de un dispositivo de iniciación de retorno generalmente retorna:", opts:["Solo una cabina elegida al azar","Todos los ascensores servidos por ese vestíbulo/grupo, según el diseño y ASME A17.1","Ningún ascensor","Solo los ascensores de carga"], re:"El retorno afecta a los ascensores servidos por la zona/grupo activado, coordinado con el diseño del ascensor y ASME A17.1. (NFPA 72-2022, 21.3; ASME A17.1)"},
  {id:363, q:"La interfaz entre el sistema de alarma contra incendios y el controlador del ascensor para el retorno normalmente se hace a través de:", opts:["El circuito de aparatos de notificación","El circuito de retención de puerta","Salidas/contactos de relé dedicados listados para la interfaz del ascensor","El interruptor de flujo de agua del rociador"], re:"Las señales de retorno y corte se entregan mediante salidas de relé dedicadas y monitoreadas al controlador del ascensor. (NFPA 72-2022, 21.3 / 21.2)"},
  {id:364, q:"Los detectores de humo instalados en vestíbulos de ascensor para el retorno se espacian de acuerdo con:", opts:["Un espaciado fijo de 100 ft sin importar la geometría","Solo uno por edificio","Las reglas estándar de espaciado de detectores de humo puntuales, con al menos uno en cada vestíbulo","El espaciado de las cabezas de rociadores"], re:"Los detectores de retorno de vestíbulo siguen el espaciado/ubicación estándar de detectores de humo, cubriendo cada vestíbulo de ascensor. (NFPA 72-2022, 17.7; 21.3)"},
  {id:365, q:"Si una sala de máquinas de ascensor tiene tanto un detector de humo como (donde hay rociadores) un detector de calor, sus funciones son:", opts:["Idénticas: ambos retornan la cabina","Ambos cortan de inmediato la energía","Ninguno se conecta a la FACU","El detector de humo retorna la cabina; el detector de calor inicia el corte de energía por disparo por cortocircuito (shunt trip)"], re:"El humo de la sala de máquinas retorna (Fase I); el detector de calor cerca del rociador maneja el disparo por cortocircuito (shunt trip). (NFPA 72-2022, 21.3 / 21.4)"},
  {id:366, q:"Después de que el retorno Fase I devuelve la cabina al nivel de retorno, las puertas de la cabina:", opts:["Permanecen cerradas y la cabina sigue en servicio","Se abren y cierran continuamente","Se abren y permanecen abiertas, y la cabina se retira del servicio automático normal","Encierran a los ocupantes dentro de la cabina"], re:"En el nivel de retorno las puertas se abren y la cabina se retira del servicio normal, disponible solo para la operación Fase II de bomberos. (ASME A17.1; NFPA 72-2022, 21.3)"},
  {id:367, q:"Combinar la detección de retorno del ascensor y el disparo por cortocircuito (shunt trip) en el MISMO dispositivo está prohibido porque:", opts:["El retorno (temprano, humo) y el corte (calor, justo antes del agua) sirven a objetivos y tiempos distintos y necesitan salidas separadas","Ahorra demasiado dinero","Los detectores de calor no pueden monitorearse","Los detectores de humo no están permitidos en salas de máquinas"], re:"NFPA 72 exige salidas separadas: retorno (temprano, humo) frente a corte (calor, inmediatamente antes de la descarga del rociador). (NFPA 72-2022, 21.3 / 21.4)"},
  {id:368, q:"El propósito principal requerido por el código de un detector de humo de ducto bajo NFPA 90A es:", opts:["Reemplazar la detección de humo de área (espacio abierto)","Hacer sonar por sí solo la alarma de evacuación del edificio","Detener el ventilador de manejo de aire para evitar la distribución de humo por los ductos","Mantener abiertas las puertas cortafuego"], re:"Según NFPA 90A, los detectores de humo de ducto apagan el ventilador de suministro para detener la recirculación/propagación de humo; no reemplazan la detección de área. (NFPA 90A; NFPA 72-2022, 17.7.5)"},
  {id:369, q:"NFPA 90A exige detectores de humo de ducto en sistemas de manejo de aire con una capacidad del lado de suministro mayor a qué valor de flujo de aire?", opts:["500 cfm","1,000 cfm","2,000 cfm","5,000 cfm"], re:"NFPA 90A exige detección de humo de ducto en sistemas de suministro que superen 2,000 cfm. (NFPA 90A)"},
  {id:370, q:"Un detector de humo de ducto del lado de suministro debe instalarse:", opts:["Aguas abajo de los filtros y antes de cualquier conexión de ramal","En el extremo del ducto ramal más largo","Solo en el cielorraso del espacio ocupado","En el exterior del edificio"], re:"NFPA 90A ubica el detector de ducto de suministro aguas abajo de los filtros y aguas arriba de cualquier derivación de ramal. (NFPA 90A)"},
  {id:371, q:"Los detectores de humo de ducto están listados para operar dentro de un rango especificado de velocidad de aire del ducto, comúnmente dado aproximadamente como:", opts:["0 a 50 fpm","5,000 a 10,000 fpm","100 a 4,000 fpm (verificar el listado de cada unidad)","No aplican límites de velocidad"], re:"Los detectores de ducto listados operan en una banda de velocidad nominal (comúnmente ~100-4,000 fpm); la unidad debe aplicarse dentro de su listado. (Listados; NFPA 72-2022, 17.7.5)"},
  {id:372, q:"Cuando la ÚNICA función de un detector de humo de ducto es la parada del ventilador, NFPA 90A permite cuál de las siguientes respecto a la energía de respaldo?", opts:["Siempre debe tener 24 h de reserva como la FACU","Puede carecer de energía secundaria (batería) cuando su única función es la parada del ventilador de HVAC","Debe operar durante 15 min en alarma","Debe alimentarse desde el controlador del ascensor"], re:"NFPA 90A permite que un detector de ducto carezca de energía de respaldo solo cuando su única función es la parada del ventilador. (NFPA 90A)"},
  {id:373, q:"Una retención magnética de puerta mantiene abierta una puerta cortafuego/cortahumo de cierre automático. En condición normal (sin alarma) la retención está:", opts:["Desenergizada","Pulsada una vez por hora","Alimentada solo durante las pruebas","Energizada continuamente para mantener la puerta abierta"], re:"Las retenciones de puerta se energizan continuamente para mantener las puertas abiertas; al activarse la alarma o perderse la energía se desenergizan y la puerta se cierra. (NFPA 72 Cap.21; NFPA 80)"},
  {id:374, q:"Una compuerta combinada cortafuego/cortahumo controlada por el sistema de alarma contra incendios, al activarse la alarma:", opts:["Se abre por completo para aumentar el flujo de aire","Permanece en su última posición","Vibra para despejar residuos","Se cierra para bloquear el paso de humo/fuego a través de la penetración del ducto"], re:"Al activarse la alarma, la FACU ordena a la compuerta cerrarse, manteniendo la barrera nominal en la penetración del ducto. (NFPA 72-2022, 21.6; NFPA 90A; NFPA 80/105)"},
  {id:375, q:"La activación de un detector de humo de ducto debe producir qué respuesta, según NFPA 72 y NFPA 90A?", opts:["Como mínimo una señal anunciada en la FACU (de supervisión, o de alarma donde se requiera) y la parada del ventilador","No se requiere indicación","Solo una luz verde de 'normal'","Solo una liberación de retención de puerta"], re:"La activación del detector de ducto se anuncia (comúnmente de supervisión, o de alarma donde el código/AHJ lo requiera) e inicia la parada del ventilador. (NFPA 72-2022, 17.7.5; 21.7)"},
  {id:376, q:"¿Por qué los detectores de humo de ducto NO son un sustituto de la detección de humo de área (puntual) en espacio abierto?", opts:["El humo puede no llegar al ducto y el ventilador puede estar apagado, por lo que un incendio en una habitación puede pasar desapercibido","Son mucho más sensibles que los detectores puntuales","Cuestan más de instalar","No pueden monitorearse eléctricamente"], re:"Los detectores de ducto solo muestrean el aire en movimiento del ducto; con el ventilador apagado o sin humo entrando al retorno, un incendio en una habitación puede pasar desapercibido. (NFPA 72-2022, 17.7.5.1; NFPA 90A)"},
  {id:377, q:"Cuando el sistema de alarma contra incendios apaga un manejador de aire al activarse la alarma, el objetivo es:", opts:["Detener el movimiento/distribución mecánica del humo por el edificio","Aumentar la toma de aire fresco","Enfriar el fuego","Presurizar la habitación del incendio"], re:"La parada del ventilador detiene la propagación de humo por los ductos hacia otras áreas. (NFPA 90A; NFPA 72-2022, 21.7)"},
  {id:378, q:"Una estación de prueba remota / accesorio para un detector de humo de ducto normalmente provee:", opts:["Una manera de recargar la batería del sistema","Volumen de notificación adicional","Energía para accionar compuertas","LED remotos de alarma/problema y un reinicio/prueba operado por llave para el sensor en el ducto"], re:"Las estaciones de prueba remotas exponen LED de estado y prueba/reinicio para un detector de ducto montado en un ducto inaccesible. (Listados; NFPA 72-2022, 17.7.5)"},
  {id:379, q:"Para sistemas de control de humo de ingeniería, NFPA 72 se coordina con qué norma que define el diseño y la operación del control de humo?", opts:["NFPA 13","NFPA 25","NFPA 92","NFPA 1221"], re:"NFPA 92 (Sistemas de Control de Humo) define el diseño/operación; NFPA 72 Cap.21 cubre la interfaz y el monitoreo de la alarma contra incendios. (NFPA 72-2022, 21.7; NFPA 92)"},
  {id:380, q:"Un sistema de retención/cierre magnético de puerta que forma parte del sistema de alarma contra incendios debe liberar las puertas al:", opts:["Solo una orden manual desde el panel","Activarse el sistema de alarma contra incendios (p. ej., detección de humo de área) o perderse la energía","Solo una señal de flujo de agua del rociador","Solo una señal de retorno de ascensor"], re:"Los dispositivos de retención se liberan al activarse la alarma contra incendios (comúnmente detección local de humo) y al perderse la energía, permitiendo que las puertas se cierren por sí solas. (NFPA 72 Cap.21; NFPA 80)"},
  {id:381, q:"Los detectores de humo dedicados que liberan dispositivos de retención de puerta abierta son un ejemplo de detección usada para:", opts:["Una función de control (seguridad contra incendios) - liberación de puerta - integrada con la FACU","Solo evacuación general del edificio","Gestión de energía","Reemplazar detectores de ducto"], re:"La detección de liberación de puerta es una función de control bajo el Capítulo 21, monitoreada por la FACU. (NFPA 72-2022, Cap.21; NFPA 80)"},
  {id:382, q:"En un sistema de control de humo de ingeniería, la actuación del equipo de HVAC por el sistema de alarma contra incendios debe coordinarse de modo que:", opts:["Todos los ventiladores simplemente se apaguen","Las zonas correctas se presuricen/extraigan según la secuencia de control de humo (que puede mantener algunos ventiladores ENCENDIDOS)","Las puertas encierren a los ocupantes","Los ascensores aceleren"], re:"El control de humo de ingeniería puede mantener ventiladores funcionando para presurización/extracción; las zonas de alarma deben coincidir con la secuencia de control de humo. (NFPA 72-2022, 21.7; NFPA 92)"},
  {id:383, q:"El cableado de interconexión de la FACU a un actuador de compuerta de humo se trata como qué tipo de circuito?", opts:["Un circuito de aparatos de notificación","Un circuito de función de control de emergencia (monitoreado según Cap.21, o relé a menos de 3 ft)","Solo un circuito ramal de retención de puerta","Un circuito de supervisión de rociadores"], re:"El control de compuertas es una función de control de emergencia; su interfaz sigue las reglas de integridad del Capítulo 21. (NFPA 72-2022, 21.2 / 21.6)"},
  {id:384, q:"Si un detector de humo de ducto también sirve para iniciar la evacuación del edificio (no solo la parada del ventilador), entonces requiere:", opts:["Ninguna energía de respaldo en absoluto","Solo un emisor de sonido local","Energía secundaria (de reserva), como otros dispositivos de iniciación de alarma","Conexión al controlador del ascensor"], re:"Una vez que un detector de ducto desempeña un papel de iniciación de alarma más allá de la parada del ventilador, debe tener energía secundaria según NFPA 72. (NFPA 72-2022, 10.6; NFPA 90A)"},
  {id:385, q:"Un interruptor de flujo de agua en un sistema de rociadores de tubería húmeda que detecta flujo genera qué señal en la unidad de control de alarma contra incendios?", opts:["Una señal de alarma","Una señal de supervisión","Solo una señal de problema","Ninguna señal"], re:"El flujo de agua indica que un rociador está operando (una condición de incendio), por lo que es una señal de alarma. (NFPA 72-2022, 17.12; NFPA 13)"},
  {id:386, q:"Un interruptor de manipulación/supervisión (tamper) de una válvula de control (de compuerta) que detecta una válvula cerrada genera qué señal?", opts:["Una señal de supervisión","Una señal de alarma","Una señal de problema","Una señal de prealarma"], re:"La manipulación de válvula (posición fuera de lo normal de una válvula) es una señal de supervisión que advierte que el sistema puede estar deteriorado. (NFPA 72-2022, 17.16; 17.12)"},
  {id:387, q:"Un interruptor de flujo de agua tipo paleta incorpora un retardo (demora) integrado principalmente para:", opts:["Demorar la alarma para que la gente pueda evacuar","Ahorrar energía de la batería","Permitir que la válvula de control se cierre","Evitar falsas alarmas por sobrepresiones/golpes de ariete en el suministro"], re:"El retardo absorbe sobrepresiones momentáneas de modo que solo el flujo sostenido dispare la alarma, reduciendo alarmas molestas. (NFPA 72-2022, 17.12; NFPA 13)"},
  {id:388, q:"Un interruptor de supervisión de una válvula de control de rociadores debe iniciar una señal cuando la válvula se ha movido de su posición totalmente abierta no más de:", opts:["La mitad de su recorrido","Solo cuando está totalmente cerrada","Un quinto (alrededor del 20%) del camino desde totalmente abierta","75% cerrada"], re:"NFPA 72 exige la señal de supervisión dentro de las dos vueltas o un quinto (alrededor del 20%) del recorrido de la válvula desde totalmente abierta. (NFPA 72-2022, 17.16.4)"},
  {id:389, q:"Un dispositivo de iniciación por flujo de agua debe indicar el flujo dentro de cuántos segundos de un flujo igual al de un solo rociador más pequeño?", opts:["30 s","60 s","90 s","120 s"], re:"NFPA 13/72 permiten que el dispositivo de flujo de agua opere dentro de 90 s de tal flujo. (NFPA 72-2022, 17.12; NFPA 13)"},
  {id:390, q:"Después de que el dispositivo de iniciación por flujo de agua se activa, los aparatos de notificación deben operar dentro de cuántos segundos adicionales?", opts:["30 s","60 s","10 s","90 s"], re:"La notificación debe seguir dentro de 10 s del dispositivo de iniciación, de modo que el total pueda acercarse a ~100 s. (NFPA 72-2022 / NFPA 13)"},
  {id:391, q:"En un sistema de rociadores de tubería seca, la baja presión de aire que podría causar un disparo no deseado de la válvula se monitorea y reporta como qué señal?", opts:["Una señal de alarma","Una señal de problema","No se requiere señal","Una señal de supervisión"], re:"La presión de aire/agua fuera de lo normal en un sistema seco/de preacción es una condición de supervisión. (NFPA 72-2022, 17.16; NFPA 13)"},
  {id:392, q:"La baja temperatura en un espacio que contiene tubería de rociadores de tubería húmeda (riesgo de congelamiento) se monitorea y reporta como:", opts:["Una señal de alarma","Una señal de problema","Una señal de supervisión","Una señal de notificación"], re:"La supervisión de baja temperatura de la habitación que protege contra el congelamiento es una señal de supervisión bajo NFPA 72. (NFPA 72-2022, 17.16)"},
  {id:393, q:"Un interruptor de flujo de agua tipo presión en una válvula de retención de alarma detecta el flujo al sensar:", opts:["Una caída en la tensión de la batería","La velocidad del aire del ducto","La posición de la puerta","El cambio/sobrepresión de presión de agua en la línea de alarma cuando la válvula opera"], re:"Los interruptores de presión sensan el aumento de presión/flujo en la línea de alarma cuando los badajos de la válvula de retención de alarma se abren. (NFPA 13; NFPA 72-2022, 17.12)"},
  {id:394, q:"Según NFPA 72, las válvulas que controlan el suministro de agua, la energía de la bomba, los niveles de tanque y la presión de aire de los sistemas de rociadores deben estar:", opts:["Sin monitoreo","Monitoreadas solo durante el horario laboral","Verificadas anualmente en lugar de supervisadas","Supervisadas eléctricamente por una unidad de control de alarma contra incendios listada"], re:"NFPA 72/13 exigen supervisión eléctrica de tales válvulas y condiciones por una FACU listada. (NFPA 72-2022, 17.16; NFPA 13)"},
  {id:395, q:"Condiciones como una bomba contra incendios en funcionamiento y el estado de su fuente de energía se monitorean y reportan (donde se requiere) como qué señal?", opts:["Solo una señal de problema","Una señal de supervisión","Una señal de notificación","No se permite monitoreo"], re:"Las condiciones de la bomba contra incendios, como bomba-en-funcionamiento y estado de la fuente de energía, son señales de supervisión. (NFPA 72-2022, 17.16; NFPA 20)"},
  {id:396, q:"La actuación (agente liberado) de un sistema de supresión por agente limpio o CO2 se reporta al sistema de alarma contra incendios como:", opts:["Una señal de supervisión","Una señal de alarma (alarma de liberación/descarga)","Una señal de problema","Ninguna señal"], re:"La descarga/liberación de un agente de supresión es una condición de alarma; el sistema de liberación se interconecta con la FACU. (NFPA 72-2022 Cap.23; NFPA 2001/12)"},
  {id:397, q:"La pérdida de integridad de monitoreo (una falla abierta o a tierra) en un circuito de supervisión de rociadores resulta en:", opts:["Una señal de alarma","Una señal de supervisión","Una señal de problema","Activación de los rociadores"], re:"Una falla de cableado/integridad es una señal de problema, distinta de la propia señal de supervisión (válvula/presión). (NFPA 72-2022, 10.15; 17.16)"},
  {id:398, q:"¿Cuál de las siguientes empareja correctamente el evento relacionado con rociadores con su tipo de señal según NFPA 72?", opts:["Flujo de agua = supervisión; válvula cerrada = alarma","Flujo de agua = alarma; válvula cerrada = supervisión","Tanto el flujo de agua como el cierre de válvula = problema","Tanto el flujo de agua como el cierre de válvula = supervisión"], re:"El flujo de agua es una alarma (agua fluyendo = incendio); una válvula cerrada/manipulada es supervisión (sistema posiblemente deteriorado). (NFPA 72-2022, 17.12 / 17.16)"},
  {id:399, q:"Un sistema de rociadores de preacción normalmente se acciona mediante:", opts:["Solo flujo de agua","Un interruptor de manipulación (tamper)","Una retención de puerta","Detección de incendio independiente (humo/calor) que abre la válvula de preacción, y luego las cabezas de rociadores controlan el agua"], re:"Los sistemas de preacción usan la detección de la FACU para abrir la válvula, cargando la tubería; luego las cabezas liberan el agua. La detección se interconecta con la FACU. (NFPA 72-2022 Cap.23; NFPA 13)"},
  {id:400, q:"La razón fundamental por la que la manipulación de válvula (tamper) es de supervisión mientras que el flujo de agua es de alarma es que:", opts:["La manipulación es más peligrosa que un incendio","Una válvula cerrada solo advierte de un posible deterioro, mientras que el flujo de agua indica un incendio/descarga real que requiere evacuación","Ambos deben hacer sonar la evacuación por igual","El flujo de agua es menos urgente que la manipulación"], re:"La supervisión advierte al personal de una condición que afecta la confiabilidad (válvula cerrada); la alarma señala un evento de incendio real (flujo). (NFPA 72-2022, definiciones; 17.12/17.16)"},
  {id:401, q:"¿Cuál es el título oficial de NFPA 72?", opts:["Código Nacional de Alarmas y Señalización de Incendios","Código Eléctrico Nacional","Código de Seguridad Humana","Norma para Extintores Portátiles de Incendios"], re:"NFPA 72 es el Código Nacional de Alarmas y Señalización de Incendios; regula la aplicación, instalación, ubicación, desempeño, inspección, prueba y mantenimiento de los sistemas de alarma y señalización de incendios. Fuente: portada de NFPA 72."},
  {id:402, q:"Según NFPA 72, ¿quién tiene la autoridad para conceder equivalencias y aprobar disposiciones alternativas no descritas específicamente en el Código?", opts:["La autoridad competente (AHJ)","El instalador del sistema","El fabricante del equipo","El propietario del edificio"], re:"El Capítulo 1 de NFPA 72 asigna la aprobación de equipos, materiales y disposiciones alternativas/equivalentes a la autoridad competente (AHJ). Fuente: NFPA 72, administración del Capítulo 1 (disposiciones de Aprobado / Equivalencia)."},
  {id:403, q:"En NFPA 72, el término 'deberá' (shall) indica ¿qué?", opts:["Un requisito obligatorio","Solo una recomendación","Una opción permisiva","Una nota explicativa"], re:"Según el Manual de Estilo de NFPA adoptado en NFPA 72, 'deberá' (shall) denota un requisito obligatorio, mientras que 'debería' (should) indica una recomendación. Fuente: convención de lenguaje obligatorio/consultivo de NFPA 72."},
  {id:404, q:"El material en un Anexo de NFPA 72 (como el Anexo A) es ¿cuál de los siguientes?", opts:["Explicativo/informativo, no parte de los requisitos","Obligatorio y exigible","Una norma independiente","Aplicable solo a sistemas residenciales"], re:"Los anexos en los documentos de NFPA no forman parte de los requisitos exigibles; son informativos/explicativos a menos que se adopten específicamente. Fuente: designación del material de anexo de NFPA 72."},
  {id:405, q:"NFPA 72 define ¿qué tipo de sistema como uno instalado dentro o sobre una estructura para proteger la estructura y sus ocupantes?", opts:["Sistema de alarma de incendios de la propiedad protegida (local)","Sistema público de reporte de alarmas de emergencia","Sistema de notificación masiva de área amplia","Sistema de servicio de liberación"], re:"Un sistema de alarma de incendios de la propiedad protegida (local) se instala en la propiedad protegida para proporcionar detección, notificación y control para esa propiedad. Fuente: definiciones de NFPA 72 / Capítulo sobre sistemas de la propiedad protegida."},
  {id:406, q:"¿Qué documento referencia NFPA 72 para los símbolos que se utilizarán en los planos de taller de alarmas de incendios, a menos que otros símbolos sean aceptables para la AHJ?", opts:["NFPA 170","NFPA 13","NFPA 101","Artículo 760 del NEC"], re:"NFPA 72 requiere que los planos de alarmas de incendios usen los símbolos de NFPA 170, Norma para Símbolos de Seguridad contra Incendios y de Emergencia, a menos que otros símbolos sean aceptables para la AHJ. Fuente: NFPA 170 referenciado por NFPA 72."},
  {id:407, q:"Según NFPA 72, el tiempo máximo de respuesta para la transmisión de una señal de alarma fuera del predio a una estación de supervisión es generalmente de cuántos segundos?", opts:["10 segundos","30 segundos","90 segundos","180 segundos"], re:"NFPA 72 limita el tiempo desde el inicio hasta la recepción de una alarma en la estación de supervisión a 90 segundos. Fuente: requisitos de temporización de comunicaciones de estación de supervisión de NFPA 72."},
  {id:408, q:"La energía secundaria (de reserva) para un sistema de alarma de incendios de la propiedad protegida debe ser capaz de operar el sistema bajo carga normal durante al menos cuánto tiempo?", opts:["4 horas","12 horas","24 horas","72 horas"], re:"NFPA 72 requiere que el suministro de energía secundario soporte el sistema en condición normal (en reposo) durante 24 horas, y luego active la carga de notificación requerida (típicamente 5 o 15 minutos). Fuente: requisitos de suministro de energía de NFPA 72."},
  {id:409, q:"Después de 24 horas con energía secundaria, un sistema de alarma de incendios en una propiedad protegida típica debe poder operar la carga de notificación de alarma durante al menos cuánto tiempo?", opts:["5 minutos","15 minutos","30 minutos","60 minutos"], re:"NFPA 72 requiere que el suministro secundario soporte la carga de notificación de alarma durante 5 minutos después del periodo de reserva de 24 horas (la notificación masiva dentro del edificio usa 15 minutos). Fuente: capacidad de energía secundaria de NFPA 72."},
  {id:410, q:"Una señal de problema (trouble) en un sistema de alarma de incendios indica ¿qué condición?", opts:["Un incendio confirmado","La activación de un interruptor de flujo de agua de rociadores","Una falla como un circuito abierto o una conexión a tierra en el cableado supervisado","Una condición de supervisión normal"], re:"Una señal de problema indica una falla (circuito abierto, conexión a tierra, pérdida de energía, etc.) en el sistema que podría afectar su operación; es distinta de las señales de alarma y de supervisión. Fuente: definiciones de señales de NFPA 72."},
  {id:411, q:"Una señal de supervisión en un sistema de alarma de incendios indica más comúnmente ¿qué?", opts:["Una condición de incendio que requiere evacuación","Un circuito abierto en el cableado del dispositivo iniciador","Una condición anormal de un sistema de protección contra incendios o sus componentes (p. ej., una válvula cerrada)","Una batería de reserva agotada"], re:"Una señal de supervisión indica una condición anormal de un recorrido de vigilancia, sistema de supresión de incendios u otra característica protectora que se está supervisando (p. ej., un interruptor de manipulación en una válvula de control). Fuente: definiciones de señales de NFPA 72."},
  {id:412, q:"Según NFPA 72, el nivel de audibilidad de una señal de evacuación en modo público debe ser de al menos cuántos dBA por encima del nivel de sonido ambiental promedio?", opts:["5 dBA","10 dBA","15 dBA","20 dBA"], re:"Los dispositivos audibles en modo público deben producir al menos 15 dBA por encima del nivel de sonido ambiental promedio, o 5 dBA por encima del nivel de sonido máximo que dure 60 segundos, lo que sea mayor. Fuente: requisitos de audibilidad de NFPA 72."},
  {id:413, q:"El patrón temporal estándar utilizado para las señales de evacuación por incendio según NFPA 72 se llama ¿cómo?", opts:["Código Temporal 3 (Temporal-Tres)","Tono continuo","Tiempo de marcha","Pulso codificado"], re:"NFPA 72 especifica el patrón audible Temporal-Tres (Código Temporal 3) para la evacuación por incendio: tres pulsos seguidos de una pausa, repetidos. Fuente: patrón de señal de evacuación de NFPA 72."},
  {id:414, q:"¿Qué tipo de señal debe tener prioridad y anular todas las demás señales en una unidad de control de alarma de incendios?", opts:["Señal de supervisión","Señal de problema","Señal de alarma","Señal de prueba"], re:"NFPA 72 establece que las señales de alarma reciben la máxima prioridad; la unidad de control debe dar precedencia a la señal de alarma de incendios sobre las de supervisión y problema. Fuente: requisitos de prioridad de señales de NFPA 72."},
  {id:415, q:"Según NFPA 72, el personal calificado de sistemas de alarma de incendios debe poder demostrar su competencia ¿por qué medio?", opts:["Solo una afirmación verbal de experiencia","Membresía en un sindicato","Certificación, licencia, registro o capacitación de fábrica reconocida y aceptable para la AHJ","Posesión de equipo de prueba"], re:"NFPA 72 requiere que el personal de servicio esté calificado, evidenciado por certificación (p. ej., NICET), licencia/registro o capacitación del fabricante aceptable para la AHJ. Fuente: requisitos de calificación del personal de NFPA 72."},
  {id:416, q:"Cuando se agrega equipo nuevo de alarma de incendios a un sistema existente, NFPA 72 requiere ¿qué tipo de prueba de las funciones afectadas?", opts:["Ninguna prueba si el panel no cambia","Un reemplazo completo del sistema","Una prueba de reaceptación de las porciones modificadas y las interfaces afectadas","Solo una inspección visual"], re:"NFPA 72 requiere una prueba de reaceptación siempre que se modifique un sistema, para verificar los cambios y que otras porciones/interfaces no se vean afectadas adversamente. Fuente: prueba de reaceptación del Capítulo 14 de NFPA 72."},
  {id:417, q:"NFPA 72 requiere que el nivel de la señal audible en modo privado sea de al menos cuántos dBA por encima del nivel de sonido ambiental promedio en la ubicación de la parte que escucha?", opts:["6 dBA","10 dBA","15 dBA","20 dBA"], re:"Los dispositivos audibles en modo privado deben proporcionar al menos 6 dBA por encima del ambiente promedio o 5 dBA por encima del nivel de sonido máximo que dure 60 segundos, lo que sea mayor. Fuente: requisitos de audibilidad en modo privado de NFPA 72."},
  {id:418, q:"En un cielo raso liso, el espaciamiento nominal (máximo) entre detectores de humo tipo puntual según NFPA 72 es ¿cuál valor?", opts:["20 ft","40 ft","30 ft","50 ft"], re:"NFPA 72 establece un espaciamiento nominal de 30 ft (9,1 m) para los detectores de humo tipo puntual en cielos rasos lisos, con los detectores dentro de la mitad de ese espaciamiento desde las paredes. Fuente: espaciamiento de detectores de humo del Cap. 17 de NFPA 72."},
  {id:419, q:"En un cielo raso liso, un detector de humo tipo puntual debe ubicarse dentro de qué distancia, medida en ángulo recto desde todas las paredes o tabiques?", opts:["Un cuarto del espaciamiento nominal","El espaciamiento nominal completo","La mitad del espaciamiento nominal","El doble del espaciamiento nominal"], re:"NFPA 72 requiere que los detectores estén dentro de la mitad del espaciamiento nominal (es decir, dentro de 15 ft para el nominal de 30 ft) desde las paredes, medido en ángulo recto. Fuente: espaciamiento en cielo raso liso del Cap. 17 de NFPA 72."},
  {id:420, q:"La 'regla del Punto 7' para la distribución de detectores requiere que todos los puntos del cielo raso estén dentro de qué distancia de un detector?", opts:["0,5 veces el espaciamiento listado/nominal","1,0 veces el espaciamiento listado/nominal","0,9 veces el espaciamiento listado/nominal","0,7 veces el espaciamiento listado/nominal"], re:"La regla 0,7S requiere que cada punto del cielo raso esté dentro de 0,7 veces el espaciamiento nominal/listado de un detector cuando se usan distribuciones no estándar (p. ej., irregulares). Fuente: Cap. 17 de NFPA 72 (método de espaciamiento 0,7S)."},
  {id:421, q:"Para un detector de humo puntual montado en el cielo raso, NFPA 72 requiere que la distancia mínima desde cualquier pared sea de al menos cuánto?", opts:["1 inch","36 inches","12 inches","4 inches"], re:"NFPA 72 requiere que los detectores de humo puntuales montados en el cielo raso se ubiquen a un mínimo de 4 in. (100 mm) de cualquier pared para evitar el espacio de aire muerto en la unión cielo raso-pared. Fuente: colocación del Cap. 17 de NFPA 72."},
  {id:422, q:"Un detector de humo puntual montado en pared (lateral) debe tener su parte superior ubicada dentro de qué zona medida hacia abajo desde el cielo raso?", opts:["Dentro de las 4 in. superiores","En cualquier parte de la pared","Entre 12 in. y 24 in. hacia abajo","Entre 4 in. y 12 in. hacia abajo"], re:"NFPA 72 permite los detectores de humo montados en pared lateral con la parte superior del detector entre 4 in. y 12 in. (100 mm a 300 mm) hacia abajo desde el cielo raso. Fuente: colocación del Cap. 17 de NFPA 72."},
  {id:423, q:"¿La altura del cielo raso por sí sola requiere una reducción en el espaciamiento de detectores de HUMO según NFPA 72?", opts:["Sí, aplica la misma tabla que para detectores de calor","Sí, el espaciamiento se duplica por encima de 20 ft","Sí, el espaciamiento se reduce a la mitad por encima de 10 ft","No, el espaciamiento nominal de detectores de humo no se reduce únicamente por la altura del cielo raso (dentro de los límites listados)"], re:"A diferencia de los detectores de calor, NFPA 72 no requiere una reducción del espaciamiento de detectores de humo basada únicamente en el aumento de la altura del cielo raso (otros factores como vigas, flujo de aire y estratificación todavía aplican). Fuente: Cap. 17 de NFPA 72."},
  {id:424, q:"Para los detectores de CALOR, a medida que aumenta la altura del cielo raso, NFPA 72 requiere ajustar el espaciamiento usando ¿qué método?", opts:["Nunca se requiere ajuste","Usar el espaciamiento de detectores de humo en su lugar","Duplicar el espaciamiento listado","Un factor de corrección por altura (multiplicador) de la tabla de espaciamiento de detectores de calor"], re:"NFPA 72 requiere que el espaciamiento listado de los detectores de calor se multiplique por un factor de reducción que disminuye a medida que aumenta la altura del cielo raso (según la tabla de altura de cielo raso para detectores de calor). Fuente: tabla de espaciamiento de detectores de calor del Cap. 17 de NFPA 72."},
  {id:425, q:"La profundidad de una viga se vuelve un factor en el espaciamiento de detectores de humo en un cielo raso a nivel cuando la profundidad de la viga excede qué fracción de la altura del cielo raso?", opts:["5% (0,05H)","40% (0,40H)","25% (0,25H)","10% (0,10H)"], re:"Cuando la profundidad de la viga es del 10% o más de la altura del cielo raso (>0,1H), las vigas afectan el espaciamiento; las vigas menos profundas que el 10% de la altura del cielo raso permiten el espaciamiento de cielo raso liso. Fuente: reglas de cielo raso con vigas del Cap. 17 de NFPA 72."},
  {id:426, q:"Para un cielo raso con vigas donde la profundidad de la viga es de al menos el 10% de la altura del cielo raso Y el espaciamiento de las vigas es de al menos el 40% de la altura del cielo raso, NFPA 72 requiere que los detectores de humo se ubiquen ¿dónde?", opts:["Solo en la parte inferior de las vigas","Espaciados al nominal completo de 30 ft","Solo en el centro del cuarto","En cada bolsillo de viga"], re:"Cuando las vigas son profundas (>=0,1H) y están muy espaciadas (>=0,4H), cada bolsillo de viga se trata como un área separada, por lo que se requiere un detector en cada bolsillo de viga. Fuente: reglas de cielo raso con vigas del Cap. 17 de NFPA 72."},
  {id:427, q:"Para un cielo raso con vigas donde la profundidad de la viga es de al menos el 10% de la altura del cielo raso pero el espaciamiento de las vigas es MENOR al 40% de la altura del cielo raso, el espaciamiento de detectores de humo perpendicular a las vigas se reduce a ¿cuánto?", opts:["Sin reducción","El doble del espaciamiento de cielo raso liso","Un cuarto del espaciamiento de cielo raso liso","La mitad del espaciamiento de cielo raso liso"], re:"Cuando las vigas son profundas pero están muy juntas (<0,4H), el espaciamiento medido perpendicular (en ángulo recto) a las vigas se reduce a la mitad del valor de cielo raso liso. Fuente: reglas de cielo raso con vigas del Cap. 17 de NFPA 72."},
  {id:428, q:"En un cielo raso inclinado (a dos aguas) con pendiente mayor a 1 en 8, la primera fila de detectores debe ubicarse ¿dónde?", opts:["En el punto más bajo de la pendiente","Solo en los aleros","Centrada en cada pared","En o dentro de 36 in. de la cumbrera (punto alto)"], re:"NFPA 72 requiere una fila de detectores en o dentro de 36 in. (910 mm) de la cumbrera de un cielo raso inclinado/a dos aguas, medido horizontalmente desde la cumbrera. Fuente: colocación en cielo raso inclinado del Cap. 17 de NFPA 72."},
  {id:429, q:"NFPA 72 (orientación del Anexo A) recomienda que los detectores de humo puntuales no se ubiquen más cerca de qué distancia de un difusor de suministro de aire?", opts:["12 in.","24 in.","36 in.","60 in."], re:"El Anexo A de NFPA 72 recomienda mantener los detectores de humo puntuales fuera del flujo de aire directo y no más cerca de 36 in. (910 mm) de un difusor de suministro de aire para evitar diluir el humo. Fuente: NFPA 72 Anexo A.17.7.4."},
  {id:430, q:"Un detector de calor de tasa de aumento (rate-of-rise) está diseñado para activarse cuando la temperatura del aire aumenta más rápido que aproximadamente ¿cuál tasa?", opts:["5 deg F por minuto","10 deg F por minuto","15 deg F por minuto","50 deg F por minuto"], re:"Los detectores de calor de tasa de aumento típicamente responden cuando la temperatura aumenta unos 15 deg F (8,3 deg C) o más por minuto. Fuente: descripciones de detectores de calor del Cap. 17 de NFPA 72 / listados de detectores."},
  {id:431, q:"Un detector de calor combinado de temperatura fija/tasa de aumento proporciona el beneficio de ¿cuál comportamiento?", opts:["Ignora por completo los aumentos lentos de temperatura","Detecta humo, no calor","Funciona solo por encima de 200 deg F","Responde a un aumento rápido de temperatura Y a una temperatura máxima fija"], re:"Los detectores combinados se activan ante una tasa rápida de aumento y también al alcanzar una temperatura de punto fijo establecido, cubriendo tanto incendios de desarrollo rápido como lento. Fuente: tipos de detectores de calor del Cap. 17 de NFPA 72."},
  {id:432, q:"Para un cielo raso a nivel de 12 ft de altura o menos, una viga que se proyecta menos de 4 in. (menos del 10% de la altura del cielo raso) se trata ¿cómo para el espaciamiento de detectores de humo?", opts:["Requiere detectores en cada bolsillo","Prohíbe los detectores montados en el cielo raso","Requiere un cuarto del espaciamiento","Como un cielo raso liso (sin reducción del espaciamiento)"], re:"Una viga poco profunda (<10% de la altura del cielo raso, p. ej., <~4 in. en un cielo raso de 12 ft) no tiene efecto sobre el espaciamiento de detectores de humo; el cielo raso se trata como liso. Fuente: reglas de cielo raso con vigas del Cap. 17 de NFPA 72."},
  {id:433, q:"¿Cuál es el propósito principal de un detector de humo de ducto instalado en un sistema HVAC?", opts:["Servir como la detección de humo primaria de área del edificio","Reemplazar los detectores de calor de área","Medir solo la temperatura del aire","Detectar humo en la corriente de aire y apagar el manejador de aire para limitar la propagación del humo"], re:"Los detectores de humo de ducto de NFPA 72 / NFPA 90A detectan humo en el aire de suministro/retorno e inician el apagado del ventilador o el control de compuertas; no sustituyen la detección de área (espacio abierto) requerida. Fuente: Cap. 17 de NFPA 72 y NFPA 90A."},
  {id:434, q:"Al usar la corrección por altura de cielo raso para detectores de calor, NFPA 72 generalmente limita el espaciamiento reducido para que no sea menor a qué fracción de la altura del cielo raso?", opts:["0,2 veces la altura del cielo raso","1,0 veces la altura del cielo raso","0,7 veces la altura del cielo raso","0,4 veces la altura del cielo raso"], re:"Después de aplicar la corrección por altura, el espaciamiento de detectores de calor no necesita reducirse por debajo de 0,4 veces la altura del cielo raso, según la orientación de NFPA 72. Fuente: disposiciones de corrección por altura de detectores de calor del Cap. 17 de NFPA 72."},
  {id:435, q:"Un diagrama de montante (riser) de alarma de incendios muestra principalmente ¿cuál de los siguientes?", opts:["La ubicación física exacta en el piso de cada dispositivo","El plano arquitectónico de cielo raso reflejado","Solo el cronograma del panel eléctrico","La disposición vertical del sistema y la interconexión de circuitos/dispositivos de piso a piso"], re:"Un diagrama de montante es un esquema que muestra la distribución vertical del sistema: unidad de control, circuitos, dispositivos e interconexiones entre pisos/áreas (no la colocación física exacta). Fuente: requisitos de documentación / planos de taller de NFPA 72."},
  {id:436, q:"¿Qué documento se completa y proporciona al momento de la aceptación del sistema para certificar que la instalación cumple con los planos aprobados y NFPA 72?", opts:["Registro de Terminación","Permiso de construcción","Plano arquitectónico del piso","Hoja de datos del fabricante"], re:"El Registro de Terminación de NFPA 72 se ejecuta en la aceptación para documentar que el sistema fue instalado y probado según el diseño aprobado y el Código. Fuente: documentación del Cap. 7 de NFPA 72."},
  {id:437, q:"La matriz de 'secuencia de operación' (entrada/salida) en la documentación de alarmas de incendios describe ¿qué?", opts:["Los colores de los cables utilizados","El cronograma de llenado de conductos","Solo el cálculo de la batería","La relación causa-efecto entre las entradas (eventos iniciadores) y las salidas (respuestas del sistema)"], re:"La secuencia de operación (causa-efecto / matriz entrada-salida) define qué hace cada entrada y qué salidas resultan, y es documentación requerida para el diseño y las pruebas. Fuente: documentación del Cap. 7 de NFPA 72."},
  {id:438, q:"Los planos 'as-built' (registro) proporcionados después de la instalación deben reflejar ¿qué?", opts:["Solo la intención del diseño original","La distribución genérica de catálogo del fabricante","Solo la expansión futura","El sistema tal como fue realmente instalado, incluyendo los cambios de campo"], re:"Los planos as-built/de registro documentan el sistema tal como fue realmente instalado, incorporando todas las modificaciones de campo, y se requiere que se proporcionen al propietario. Fuente: requisitos de documentación del Cap. 7 de NFPA 72."},
  {id:439, q:"Los cálculos de batería (energía de reserva) presentados con los planos de alarma de incendios se utilizan para verificar ¿qué?", opts:["El tamaño del conducto","El espaciamiento de los detectores","La audibilidad en dBA","Que el suministro secundario pueda soportar la carga de reserva durante las horas requeridas más la carga de alarma"], re:"Los cálculos de batería demuestran que la fuente de energía secundaria puede soportar la carga en reposo durante el periodo de reserva requerido (p. ej., 24 h) y luego la carga de alarma (p. ej., 5 min). Fuente: suministro de energía / documentación de NFPA 72."},
  {id:440, q:"Los cálculos de caída de tensión para un circuito de dispositivos de notificación aseguran ¿qué?", opts:["Que los detectores estén espaciados 30 ft entre sí","Que el cable sea apto para plenum","Que el panel tenga una batería","Que el último dispositivo del circuito todavía reciba al menos su tensión mínima de operación listada"], re:"Los cálculos de caída de tensión confirman que el dispositivo al final de la línea recibe al menos su tensión mínima de operación listada por UL bajo las condiciones del peor caso. Fuente: práctica de diseño / documentación de NAC de NFPA 72."},
  {id:441, q:"En los planos de alarma de incendios, un triángulo sólido o un conjunto de símbolos estandarizados similares se dibuja a partir de ¿cuál referencia?", opts:["Símbolos de rociadores de NFPA 13","Símbolos de ductos de ASHRAE","Símbolos de canalizaciones del NEC","Símbolos de seguridad contra incendios de NFPA 170"], re:"Los símbolos de dispositivos de alarma de incendios en los planos siguen NFPA 170, Norma para Símbolos de Seguridad contra Incendios y de Emergencia, a menos que otros símbolos sean aceptados por la AHJ. Fuente: NFPA 170 referenciado por NFPA 72."},
  {id:442, q:"¿Cuál elemento NO es típicamente parte de un envío completo de planos de taller de alarma de incendios?", opts:["Planos de piso que muestran las ubicaciones de los dispositivos","Diagrama de montante","Secuencia de operación","La tasación del impuesto predial del edificio"], re:"Los envíos incluyen planos de piso, diagrama de montante, secuencia de operación, cableado punto a punto, cálculos de batería/caída de tensión y hojas de corte; una tasación de impuestos no tiene relación. Fuente: documentación del Cap. 7 de NFPA 72."},
  {id:443, q:"Un diagrama de cableado punto a punto se utiliza principalmente para mostrar ¿qué?", opts:["Las conexiones exactas de los terminales y el cableado de campo entre los dispositivos y la unidad de control","Las elevaciones arquitectónicas","El enrutamiento de ductos de HVAC","La curva de la bomba de incendios"], re:"Los diagramas de cableado punto a punto muestran las conexiones terminal por terminal de los conductores entre la unidad de control, los módulos y los dispositivos de campo, apoyando la instalación y la resolución de problemas. Fuente: documentación del Cap. 7 de NFPA 72."},
  {id:444, q:"Según NFPA 72, el propietario debe conservar una copia permanente de la documentación de registro ¿en qué ubicación?", opts:["Solo en la oficina del contratista","Solo con el fabricante","Solo con la AHJ","En la propiedad protegida (p. ej., en un gabinete de documentación) u otra ubicación aprobada"], re:"NFPA 72 requiere que la documentación de registro (as-built) se mantenga durante la vida útil del sistema en la propiedad protegida o una ubicación aprobada, a menudo en un gabinete de documentación en la FACU. Fuente: Cap. 7 de NFPA 72."},
  {id:445, q:"Antes de la prueba de aceptación, NFPA 72 requiere que el contratista instalador proporcione ¿qué garantía sobre la instalación?", opts:["Solo una confirmación verbal","Solo la tarjeta de garantía","Una copia de la ordenanza municipal","Documentación completada/ejecutada que incluya una certificación previa a la prueba de que el 100% del sistema fue instalado y probado previamente"], re:"El instalador proporciona documentación completada y una declaración de que el sistema fue instalado y probado al 100% por el instalador antes de la prueba de aceptación (de la AHJ). Fuente: documentación de aceptación del Cap. 14 / Cap. 7 de NFPA 72."},
  {id:446, q:"Una 'matriz de operaciones' debe verificarse contra ¿qué durante la prueba de aceptación?", opts:["La respuesta real programada del sistema para cada entrada","El esquema de colores del arquitecto","El color de pintura del conducto","Las ubicaciones de los extintores de incendios"], re:"La prueba de aceptación confirma que la causa-efecto instalada/programada coincide con la secuencia de operación (matriz) aprobada. Fuente: prueba de aceptación del Cap. 14 de NFPA 72."},
  {id:447, q:"¿Qué color requiere NFPA/NEC para identificar el medio de desconexión del circuito ramal dedicado que alimenta una unidad de control de alarma de incendios?", opts:["Azul","Verde","Rojo","Amarillo"], re:"La identificación al estilo NEC 760.121/695 requiere que el dispositivo de sobrecorriente/desconexión del circuito ramal de alarma de incendios esté marcado en rojo y etiquetado 'CIRCUITO DE ALARMA DE INCENDIOS'. Fuente: marcado de fuente de energía del Artículo 760 del NEC."},
  {id:448, q:"¿Qué representa una 'zona' en el plano de un sistema de alarma de incendios convencional?", opts:["Una sola dirección de dispositivo","Solo el tendido del conducto","El compartimiento de la batería","Un área definida servida por un circuito, usada para anunciar la ubicación general de un evento"], re:"Una zona es un área definida del edificio (a menudo un circuito) usada para indicar el origen general de una condición de alarma/supervisión/problema en el anunciador. Fuente: requisitos de zonificación/anunciación de NFPA 72."},
  {id:449, q:"Para un sistema direccionable, la identidad de cada dispositivo en el plano corresponde a ¿qué?", opts:["Una dirección/punto único reportado individualmente a la unidad de control","Una zona compartida sin identidad individual","Solo una campana de cableado fijo","Un terminal de batería"], re:"Cada dispositivo direccionable reporta una dirección/punto único, de modo que la unidad de control y los planos identifican la ubicación del dispositivo específico en lugar de solo una zona. Fuente: operación de sistema direccionable de NFPA 72."},
  {id:450, q:"El 'registro de terminación' de alarma de incendios debe ser firmado por ¿cuáles partes?", opts:["Solo el propietario del edificio","Solo el arquitecto","Solo el proveedor del equipo","Representantes del contratista instalador y del propietario/AHJ del sistema según corresponda"], re:"El Registro de Terminación es firmado por el representante del contratista instalador y el representante del propietario (y la AHJ cuando se requiera) para certificar la instalación correcta. Fuente: Registro de Terminación del Cap. 7 de NFPA 72."},
  {id:451, q:"Los manuales de operación y mantenimiento (O&M) entregados al propietario deben incluir ¿qué?", opts:["Solo la factura de venta","Datos del fabricante, registros de programación/configuración e instrucciones de ITM para el equipo instalado","El currículum del arquitecto","El informe de balanceo de HVAC"], re:"La entrega de O&M incluye la literatura del fabricante, los registros de configuración/software tal como fue programado e instrucciones de inspección-prueba-mantenimiento para que el propietario pueda mantener el sistema. Fuente: documentación del propietario del Cap. 7 de NFPA 72."},
  {id:452, q:"Una prueba de aceptación de un nuevo sistema de alarma de incendios verifica ¿qué?", opts:["Solo que el panel se encienda","Que todo el sistema instalado opere según el diseño aprobado y NFPA 72 antes de ponerse en servicio","Solo la tensión de la batería","La carga de ocupación del edificio"], re:"La prueba de aceptación (inicial) confirma que el 100% del sistema instalado funciona de acuerdo con los planos aprobados, la secuencia de operación y NFPA 72 antes de ponerse en servicio. Fuente: prueba de aceptación del Cap. 14 de NFPA 72."},
  {id:453, q:"Durante la prueba de aceptación de los dispositivos iniciadores, ¿qué porcentaje de dispositivos debe probarse?", opts:["10%","25%","50%","100%"], re:"En la aceptación inicial, se debe probar el 100% de los dispositivos iniciadores, dispositivos de notificación y funciones. Fuente: alcance de la prueba de aceptación del Cap. 14 de NFPA 72."},
  {id:454, q:"La prueba de aceptación de un detector de humo tipo puntual debe confirmar la entrada de humo usando ¿qué?", opts:["Solo un imán","Humo o un aerosol listado/aprobado para el detector que entre en la cámara de detección","Una lectura de multímetro","Solo inspección visual"], re:"Los detectores de humo deben probarse con humo o un aerosol listado que realmente entre en la cámara de detección para verificar la respuesta, no meramente un imán (que solo prueba el circuito de alarma/relé). Fuente: métodos de prueba de detectores del Cap. 14 de NFPA 72."},
  {id:455, q:"Usar un imán de prueba en un detector de humo direccionable durante la prueba de aceptación verifica principalmente ¿qué?", opts:["Que el humo realmente entra en la cámara","La electrónica/señalización de alarma y el direccionamiento del detector, pero NO la entrada de humo","La deriva de sensibilidad del detector","La altura del cielo raso"], re:"Una prueba con imán verifica la señalización de alarma/direccionamiento (respuesta funcional) pero no confirma que el humo pueda entrar en la cámara; también debe verificarse la entrada de humo/aerosol. Fuente: métodos de prueba del Cap. 14 de NFPA 72."},
  {id:456, q:"Durante la aceptación, la cobertura de los dispositivos audibles de notificación se verifica midiendo ¿qué?", opts:["Solo la frecuencia en hertz","El nivel de presión sonora (dBA) para confirmar la audibilidad requerida por encima del ambiente","Los amperios-hora de la batería","La resistencia del conductor"], re:"La audibilidad se verifica midiendo el nivel de presión sonora (dBA) para confirmar el margen requerido por encima del ambiente (p. ej., 15 dBA en modo público). Fuente: Cap. 14 de NFPA 72 / requisitos de audibilidad."},
  {id:457, q:"La prueba de aceptación de luces estroboscópicas (notificación visible) verifica la conformidad con ¿cuál parámetro de listado?", opts:["Clasificación de candelas (cd) y sincronización donde se requiera","Clasificación de decibeles","Química de la batería","Oscurecimiento por humo"], re:"Los dispositivos visibles se verifican para la salida/colocación de candelas adecuada y, donde se requiera, la sincronización para prevenir tasas de destello que induzcan convulsiones. Fuente: Cap. 14 de NFPA 72 y requisitos de señalización visible."},
  {id:458, q:"Como parte de la prueba de aceptación, la integridad del circuito supervisado se verifica ¿haciendo qué?", opts:["Pintando el conducto","Introduciendo fallas (circuito abierto, conexión a tierra) y confirmando que el panel reporta la condición de problema correcta","Desconectando la batería permanentemente","Quitando todos los detectores"], re:"La supervisión del circuito se verifica introduciendo fallas de circuito abierto/conexión a tierra y confirmando la anunciación de problema adecuada, demostrando el monitoreo de integridad. Fuente: prueba de aceptación del cableado del Cap. 14 de NFPA 72."},
  {id:459, q:"Durante la prueba de aceptación, el suministro de energía secundario se prueba ¿haciendo qué?", opts:["Midiendo la luz ambiental","Desconectando la energía primaria (CA) y verificando que el sistema opere con energía de reserva durante la duración requerida","Reemplazando el panel","Contando los detectores"], re:"La energía secundaria se verifica quitando la energía primaria y confirmando que el sistema opera con batería durante el periodo de reserva y luego soporta la carga de alarma. Fuente: prueba de suministro de energía del Cap. 14 de NFPA 72."},
  {id:460, q:"La prueba de aceptación debe verificar la transmisión de señales fuera del predio confirmando ¿qué?", opts:["Que la estación de supervisión reciba correctamente las señales de alarma, supervisión y problema","Que la campana sea roja","Que la batería esté cargada a 12 V","Que el detector esté a 30 ft de la pared"], re:"Donde un sistema transmite fuera del predio, la prueba de aceptación confirma que la estación de supervisión recibe e identifica correctamente las señales de alarma, supervisión y problema. Fuente: Cap. 14 de NFPA 72 / prueba de estación de supervisión."},
  {id:461, q:"Durante la prueba de aceptación de un sistema de comunicación de voz/alarma de emergencia (EVACS), la inteligibilidad se evalúa para asegurar ¿qué?", opts:["Que el volumen del mensaje exceda 120 dBA en todas partes","Que los mensajes de voz sean comprensibles en los espacios acústicamente distinguibles","Que las luces estroboscópicas destellen más rápido","Que la batería dure 72 horas"], re:"La aceptación de EVACS incluye verificar la inteligibilidad del habla en los espacios acústicamente distinguibles requeridos, no meramente el volumen. Fuente: requisitos de inteligibilidad del Cap. 14 y Cap. 18 de NFPA 72."},
  {id:462, q:"¿Quién típicamente presencia la prueba de aceptación final de un sistema de alarma de incendios?", opts:["La autoridad competente (AHJ) y el representante del propietario","Solo el contratista de HVAC","El jardinero","No se requiere de nadie"], re:"La AHJ (y el representante del propietario) típicamente presencia la prueba de aceptación para confirmar el cumplimiento del código antes de que el sistema sea aprobado para servicio. Fuente: proceso de aceptación del Cap. 14 de NFPA 72."},
  {id:463, q:"Cuando la iniciación de la alarma de incendios provoca el apagado del ventilador de HVAC, la prueba de aceptación debe verificar ¿qué?", opts:["Que los ventiladores realmente se apaguen (o realicen la acción programada) ante la entrada correcta","El color del ducto","El punto de ajuste del termostato","El tamaño del filtro"], re:"Las funciones de interfaz como el apagado del ventilador, el cierre de compuertas, la liberación de puertas y el rellamado de ascensores deben verificarse para que operen según la secuencia de operación durante la aceptación. Fuente: prueba de interfaz del Cap. 14 de NFPA 72."},
  {id:464, q:"Para la iniciación por alarma de incendios del rellamado de ascensores (Fase I), la prueba de aceptación debe confirmar ¿qué?", opts:["Los ascensores se rellaman al nivel designado/alterno ante la activación del detector correcto","La cabina del ascensor se repinta","El detector de humo del hueco se retira","La capacidad del carro aumenta"], re:"La prueba de aceptación verifica el rellamado de ascensores de Fase I al nivel designado o alterno tras la activación del detector apropiado del vestíbulo/cuarto de máquinas/hueco según NFPA 72 y ASME A17.1. Fuente: Cap. 21 / prueba de interfaz del Cap. 14 de NFPA 72."},
  {id:465, q:"La prueba de aceptación de la iniciación de alarma por flujo de agua de un sistema de rociadores verifica ¿qué?", opts:["El interruptor de flujo de agua inicia una alarma dentro del tiempo de retardo permitido","El color de la tubería de rociadores","La presión del agua excede 300 psi","El espaciamiento de los detectores es 30 ft"], re:"Los interruptores de flujo de agua deben iniciar una alarma no más de 90 segundos después de que comienza el flujo (dentro de los límites de retardo); la aceptación verifica la iniciación y anunciación correctas. Fuente: Cap. 14 de NFPA 72 / interfaz con NFPA 13."},
  {id:466, q:"Si una prueba de aceptación revela una deficiencia, ¿cuál es la acción adecuada según NFPA 72?", opts:["Poner el sistema en servicio de todos modos","Documentar la deficiencia, corregirla y volver a probar la función afectada antes de la aprobación final","Ignorar las deficiencias menores","Retirar permanentemente los dispositivos afectados"], re:"Las deficiencias encontradas durante las pruebas deben documentarse, corregirse y las funciones afectadas volverse a probar antes de que el sistema pueda aceptarse/ponerse en servicio. Fuente: manejo de aceptación/deficiencias del Cap. 14 de NFPA 72."},
  {id:467, q:"¿Se requiere una prueba de reaceptación después de cuál evento?", opts:["Inspección anual de rutina sin cambios","Agregar, reubicar o modificar dispositivos iniciadores, dispositivos de notificación o programación","Limpiar el exterior del panel","Cambiar la pintura de la pared cerca de un dispositivo"], re:"La prueba de reaceptación se requiere cuando se agregan, eliminan o reubican dispositivos/aparatos, o cuando cambia el software/programación que afecta la operación, para confirmar la operación correcta y la ausencia de impacto adverso. Fuente: reaceptación del Cap. 14 de NFPA 72."},
  {id:468, q:"Durante la aceptación, las cajas manuales de alarma de incendios (estaciones manuales) se prueban ¿haciendo qué?", opts:["Midiendo solo su altura","Operando cada estación y confirmando la señal de alarma e identificación correctas","Pintándolas de rojo","Quitando solo la cubierta"], re:"Cada estación manual se opera para verificar que inicie la alarma correcta y esté debidamente identificada/anunciada. Fuente: prueba de aceptación de estaciones manuales del Cap. 14 de NFPA 72."},
  {id:469, q:"Según el Capítulo 14 de NFPA 72, los detectores de humo tipo puntual deben probarse funcionalmente con ¿qué frecuencia mínima?", opts:["Mensualmente","Trimestralmente","Anualmente","Cada 5 años"], re:"El Cap. 14 de NFPA 72 requiere la prueba funcional de los detectores de humo al menos anualmente (además de la inspección visual semestral). Fuente: NFPA 72 Tabla 14.4.3.2."},
  {id:470, q:"La SENSIBILIDAD de los detectores de humo debe probarse primero dentro de qué tiempo después de la instalación, luego en un intervalo de años alternos?", opts:["Dentro de 6 meses","Dentro de 1 año","Dentro de 2 años","Dentro de 5 años"], re:"NFPA 72 requiere que la sensibilidad de los detectores de humo se pruebe dentro de 1 año de la instalación, luego cada año alterno; los intervalos pueden extenderse a 5 años si los resultados se mantienen en rango. Fuente: prueba de sensibilidad del Cap. 14 de NFPA 72."},
  {id:471, q:"Después de dos pruebas exitosas de sensibilidad de detectores de humo que muestren lecturas dentro del rango listado, el intervalo puede extenderse a un máximo de ¿cuánto tiempo?", opts:["1 año","2 años","5 años","10 años"], re:"Si dos pruebas consecutivas de sensibilidad están dentro del rango listado/marcado, NFPA 72 permite extender el intervalo de prueba a un máximo de 5 años. Fuente: prueba de sensibilidad del Cap. 14 de NFPA 72."},
  {id:472, q:"Una ALARMA de humo de estación única o múltiple debe reemplazarse a más tardar cuántos años desde su fecha de fabricación (a menos que el fabricante indique lo contrario)?", opts:["5 años","10 años","15 años","20 años"], re:"NFPA 72 requiere que las alarmas de humo se reemplacen dentro de los 10 años de la fecha de fabricación a menos que las instrucciones del fabricante especifiquen lo contrario. Fuente: reemplazo de alarmas de humo del Cap. 14 de NFPA 72."},
  {id:473, q:"Las baterías de reserva selladas de plomo-ácido (SLA) usadas en sistemas de alarma de incendios deben reemplazarse a intervalos que no excedan aproximadamente ¿cuánto tiempo?", opts:["1 año","4 años","10 años","15 años"], re:"NFPA 72 indica que las baterías selladas de plomo-ácido se reemplacen cuando estén a alrededor del 80% de la capacidad marcada, generalmente dentro de ~4 años; los fabricantes a menudo recomiendan ~5 años. Fuente: mantenimiento de baterías del Cap. 14 de NFPA 72."},
  {id:474, q:"NFPA 72 requiere una prueba de carga (descarga) de la batería secundaria con ¿qué frecuencia mínima?", opts:["Semanalmente","Mensualmente","Anualmente","Cada 5 años"], re:"El Cap. 14 de NFPA 72 requiere que la batería se someta a una prueba de carga/descarga al menos anualmente para confirmar que puede soportar la operación del sistema. Fuente: NFPA 72 Tabla 14.4.3.2 (baterías de almacenamiento)."},
  {id:475, q:"Los dispositivos iniciadores y dispositivos de notificación generalmente requieren inspección VISUAL con ¿qué frecuencia mínima según NFPA 72?", opts:["Semanalmente","Mensualmente","Semestralmente","Cada 5 años"], re:"La Tabla 14.3.1 de NFPA 72 lista la inspección visual semestral para la mayoría de los dispositivos iniciadores y dispositivos de notificación (condición física/montaje). Fuente: NFPA 72 Tabla 14.3.1."},
  {id:476, q:"Los dispositivos de flujo de agua (p. ej., interruptores de flujo de agua) deben probarse funcionalmente con ¿qué frecuencia mínima según NFPA 72?", opts:["Anualmente","Semestralmente","Trimestralmente","Cada 5 años"], re:"NFPA 72 requiere la prueba funcional de los dispositivos de flujo de agua semestralmente (y los dispositivos de supervisión/manipulación de válvulas semestralmente también). Fuente: Cap. 14 de NFPA 72 (prueba de dispositivos de flujo de agua y de supervisión)."},
  {id:477, q:"Un detector de calor que es restaurable (tipo no destructivo) se prueba funcionalmente con ¿qué frecuencia mínima?", opts:["Mensualmente","Trimestralmente","Anualmente","Cada 10 años"], re:"Los detectores de calor restaurables se prueban funcionalmente con calor al menos anualmente; los tipos no restaurables no se prueban con calor pero se revisan/reemplazan según el programa. Fuente: NFPA 72 Tabla 14.4.3.2 (detectores de calor)."},
  {id:478, q:"¿Qué tipo de detector de calor NO debe probarse aplicando calor (para evitar destruirlo)?", opts:["Neumático de tasa de aumento","Electrónico restaurable de temperatura fija","Tipo no restaurable de temperatura fija (fusible/eutéctico)","Detector electrónico combinado"], re:"Los detectores no restaurables de temperatura fija (p. ej., de enlace fusible/eutéctico) se destruyen si se operan, por lo que no se prueban con calor; se usan métodos alternativos o el reemplazo programado. Fuente: prueba de detectores de calor del Cap. 14 de NFPA 72."},
  {id:479, q:"Las señales de problema de la unidad de control deben probarse con ¿qué frecuencia mínima según NFPA 72?", opts:["Anualmente","Cada 5 años","Solo en la aceptación","Cada 10 años"], re:"NFPA 72 requiere que las funciones de la unidad de control, incluyendo las señales de problema, se prueben al menos anualmente. Fuente: NFPA 72 Tabla 14.4.3.2 (equipo de control)."},
  {id:480, q:"Los detectores de humo de ducto deben probarse para verificar ¿qué además de la respuesta de alarma?", opts:["El muestreo de aire/flujo de aire es adecuado para que el humo pueda alcanzar la cámara de detección","El ducto está pintado","El ventilador es de la marca correcta","El filtro es nuevo"], re:"La prueba de detectores de ducto verifica que el tubo de muestreo/flujo de aire permita que el humo entre en la cámara de detección y que la unidad se active y realice su función de control (p. ej., apagado del ventilador). Fuente: prueba de detectores de ducto del Cap. 14 de NFPA 72."},
  {id:481, q:"Los registros de inspección, prueba y mantenimiento deben conservarse durante al menos ¿cuánto tiempo según NFPA 72?", opts:["6 meses","1 año (hasta la próxima prueba) o según lo requiera la AHJ","Indefinidamente sin un mínimo","Solo hasta el día siguiente"], re:"NFPA 72 requiere que los registros de ITM se conserven al menos hasta la próxima prueba/inspección y durante un periodo aceptable para la AHJ (comúnmente un ciclo de prueba o más). Fuente: retención de registros del Cap. 14 de NFPA 72."},
  {id:482, q:"Antes de deshabilitar parte de un sistema de alarma de incendios para servicio (un 'deterioro'), la mejor práctica de NFPA 72 requiere ¿qué?", opts:["Notificar a la AHJ/propietario y proporcionar una vigilancia contra incendios u otras medidas aprobadas según sea necesario","Nada; simplemente deshabilitarlo","Quitar todas las baterías","Cortar la energía al edificio"], re:"Los procedimientos de fuera de servicio/deterioro requieren notificar al propietario/AHJ y monitoreo/vigilancia contra incendios u otras medidas aprobadas mientras la protección está deteriorada. Fuente: disposiciones de deterioro del Cap. 10/14 de NFPA 72."},
  {id:483, q:"Las cajas manuales de alarma de incendios (estaciones manuales) deben probarse funcionalmente con ¿qué frecuencia mínima?", opts:["Semanalmente","Mensualmente","Anualmente","Cada 10 años"], re:"La Tabla 14.4.3.2 de NFPA 72 requiere que las estaciones manuales se prueben funcionalmente al menos anualmente. Fuente: prueba de estaciones manuales del Cap. 14 de NFPA 72."},
  {id:484, q:"Los dispositivos de notificación audibles y visibles deben probarse funcionalmente con ¿qué frecuencia mínima?", opts:["Anualmente","Cada 5 años","Solo en la aceptación","Cada 10 años"], re:"NFPA 72 requiere que los dispositivos de notificación (bocinas, luces estroboscópicas, altavoces) se prueben funcionalmente al menos anualmente. Fuente: NFPA 72 Tabla 14.4.3.2 (dispositivos de notificación)."},
  {id:485, q:"Un propósito principal del mantenimiento de rutina (p. ej., la limpieza) de los detectores de humo es ¿hacer qué?", opts:["Cambiar el color del dispositivo","Mantener el detector dentro de su rango de sensibilidad listado y reducir las alarmas no deseadas","Aumentar la salida de candelas","Alargar el conducto"], re:"La limpieza/mantenimiento mantiene los detectores operando dentro de su rango de sensibilidad listado, preservando la respuesta y minimizando las alarmas molestas por contaminación de polvo. Fuente: disposiciones de mantenimiento del Cap. 14 de NFPA 72."},
  {id:486, q:"¿Cuál artículo del NEC cubre específicamente la instalación del cableado del sistema de alarma de incendios?", opts:["Artículo 250","Artículo 700","Artículo 760","Artículo 800"], re:"El Artículo 760 del NEC cubre la instalación del cableado y equipo de los sistemas de alarma de incendios, incluyendo los circuitos de potencia limitada (PLFA) y de potencia no limitada (NPLFA). Fuente: alcance del Artículo 760 del NEC (760.1)."},
  {id:487, q:"En el Artículo 760 del NEC, la designación de cable 'FPL' se refiere a ¿qué?", opts:["Cable de alarma de incendios de potencia limitada, de uso general","Cable de potencia limitada apto para montante","Cable de potencia limitada apto para plenum","Cable de alarma de incendios de potencia no limitada"], re:"FPL es el cable de alarma de incendios de potencia limitada de uso general; la familia es FPLP (plenum), FPLR (montante) y FPL (general). Fuente: tipos de cable de NEC 760.179 / Tabla 760.154."},
  {id:488, q:"¿Cuál cable de alarma de incendios de potencia limitada se requiere para la instalación en ductos, plenums y otros espacios usados para aire ambiental?", opts:["FPL","FPLR","FPLP","CL2"], re:"El tipo FPLP (plenum) se requiere en ductos, plenums y espacios de manejo de aire ambiental porque cumple con la prueba estricta de propagación de llama/bajo humo (plenum). Fuente: cable para plenum de NEC 760.154 / 760.179."},
  {id:489, q:"¿Cuál cable de alarma de incendios de potencia limitada se requiere para tendidos verticales en un hueco o de piso a piso (montante)?", opts:["FPL","FPLR","CL2X","NPLF"], re:"El tipo FPLR (montante) se requiere para tendidos que penetran más de un piso o en huecos verticales; el FPLP puede sustituirse. Fuente: cable para montante de NEC 760.154 / 760.179."},
  {id:490, q:"En la jerarquía de sustitución de cable de potencia limitada del NEC 760, ¿cuál sustitución está PERMITIDA?", opts:["FPL usado en lugar de FPLP","FPLR usado en lugar de FPLP en un plenum","FPLP usado en lugar de FPLR o FPL","FPL usado en lugar de FPLR en un montante"], re:"El cable de mayor clasificación puede sustituir al de menor: FPLP puede reemplazar a FPLR y FPL; FPLR puede reemplazar a FPL; lo contrario no está permitido. Fuente: sustituciones de cable de NEC Tabla 760.154."},
  {id:491, q:"¿Qué designa 'NPLFA' en el Artículo 760 del NEC?", opts:["Circuito de alarma de incendios de potencia no limitada","Circuito de alarma de incendios de potencia limitada","Cable de comunicaciones para plenum","Un conductor del electrodo de puesta a tierra"], re:"NPLFA es un circuito de alarma de incendios de potencia no limitada; su salida de potencia no está limitada inherentemente y puede operar a mayor tensión (hasta 600 V). Fuente: NEC Artículo 760 Parte III (NPLFA)."},
  {id:492, q:"Un circuito de alarma de incendios de potencia limitada (PLFA) deriva su característica de potencia limitada de ¿qué?", opts:["El color del conductor","Una fuente de energía listada que limita la tensión y la corriente según el Código","El material del conducto","El número de detectores"], re:"Los circuitos PLFA son alimentados por una fuente de energía listada que limita la tensión y la corriente (p. ej., según las tablas de fuente de energía), permitiendo métodos de cableado reducidos. Fuente: fuente de energía PLFA de NEC 760.121 / Parte III."},
  {id:493, q:"Donde no estén en una canalización o de otro modo separados, los conductores de alarma de incendios de potencia limitada deben separarse de los conductores de iluminación eléctrica, potencia y Clase 1 por al menos ¿qué distancia?", opts:["1/2 in.","1 in.","2 in.","6 in."], re:"NEC 760.136 generalmente requiere al menos 2 in. (50 mm) de separación entre los conductores PLFA y los conductores de circuitos de iluminación, potencia, Clase 1 o NPLFA, a menos que estén separados por una barrera o en una canalización. Fuente: NEC 760.136."},
  {id:494, q:"NEC 760.124 requiere que los circuitos y equipos de alarma de incendios se identifiquen ¿cómo, para evitar interferencia accidental durante el servicio?", opts:["Sin ninguna marca","Marcados/identificados de forma duradera en las ubicaciones de terminales y cajas de empalme como circuitos de alarma de incendios","Solo por la memoria del instalador","Con un símbolo de extintor de incendios"], re:"NEC 760.124 requiere que los circuitos de alarma de incendios se identifiquen en las ubicaciones de terminales y cajas de empalme con una etiqueta/marca para evitar interferencia involuntaria durante las pruebas/servicio. Fuente: NEC 760.124."},
  {id:495, q:"El circuito ramal dedicado que alimenta una unidad de control de alarma de incendios debe tener su dispositivo de sobrecorriente identificado ¿cómo?", opts:["Pintado de azul y sin etiqueta","Marcado en rojo y etiquetado 'CIRCUITO DE ALARMA DE INCENDIOS', accesible solo para personal calificado","Dejado sin marcar","Etiquetado 'REPUESTO'"], re:"NEC 760.121(B) requiere que el dispositivo de sobrecorriente del circuito ramal de alarma de incendios esté marcado en rojo, etiquetado 'CIRCUITO DE ALARMA DE INCENDIOS' y accesible solo para personal calificado. Fuente: NEC 760.121(B)."},
  {id:496, q:"Se permite que los conductores del circuito de alarma de incendios de potencia limitada sean más pequeños que el mínimo típico solo bajo ¿qué condición del NEC?", opts:["Nunca bajo ninguna condición","Se permite 26 AWG donde se termine/empalme en equipo listado adecuado para ese tamaño","Solo si están pintados de rojo","Solo por encima de 600 V"], re:"NEC 760.142/760.179 permiten conductores PLFA de 26 AWG solo donde se empalmen/terminen con conectores o equipo listado como adecuado para 26 AWG (de lo contrario, 24 AWG mínimo). Fuente: dimensionamiento de conductores de NEC 760.179."},
  {id:497, q:"Dentro de un solo gabinete, se permite que los conductores PLFA estén en la misma canalización/gabinete con conductores de potencia solo si se cumple ¿cuál condición?", opts:["Son del mismo color","Una barrera los separa, o los conductores de potencia se conectan únicamente al mismo equipo de alarma de incendios","Usan cable más grande","La tensión es superior a 600 V"], re:"NEC 760.136 permite los PLFA con conductores de potencia en el mismo gabinete solo cuando están separados por una barrera, o donde los conductores de iluminación/potencia se introducen únicamente para conectarse al mismo equipo de alarma de incendios. Fuente: NEC 760.136(C)/(D)."},
  {id:498, q:"El cable de alarma de incendios abandonado (no terminado en el equipo y no identificado para uso futuro) debe manejarse ¿cómo según el NEC?", opts:["Dejarse en su lugar permanentemente","Retirarse (la porción accesible)","Pintarse encima","Energizarse continuamente"], re:"El NEC requiere que la porción accesible del cable de alarma de incendios abandonado se retire para reducir la carga de combustible de fuego/humo, a menos que esté etiquetado para uso futuro. Fuente: retiro de cable abandonado de NEC 760.25."},
  {id:499, q:"Los conductores del circuito de alarma de incendios de potencia no limitada (NPLFA) generalmente tienen ¿qué requisito de tamaño mínimo según el NEC?", opts:["26 AWG","18 AWG (con 16 AWG y mayores también permitidos)","10 AWG","4 AWG"], re:"NEC 760.49 especifica que se permiten conductores NPLFA de 18 AWG y 16 AWG para corrientes limitadas, con tamaños mayores según la ampacidad; el PLFA difiere. Fuente: dimensionamiento de conductores NPLFA de NEC 760.49."},
  {id:500, q:"¿Cuál afirmación sobre los listados de cable del NEC 760 es correcta?", opts:["Un cable FPL de uso general siempre puede usarse en un plenum","Las sustituciones solo van de mayor clasificación a menor clasificación de aplicación (plenum > montante > general)","El cable para montante (FPLR) puede usarse en un plenum","El tipo de cable no importa en interiores"], re:"La Tabla 760.154 del NEC permite sustituir solo un cable de mayor clasificación por un uso de menor clasificación (plenum FPLP por montante/general; montante FPLR por general); el cable de menor clasificación no puede usarse en una ubicación más exigente. Fuente: NEC Tabla 760.154."}
];
